		{
			foreach (IXRInteractor item in m_Interactors.registeredSnapshot)
			{
				if (m_Interactors.IsStillRegistered(item) && item.handedness == hand && item is IXRSelectInteractor { hasSelection: not false })
				{
					return true;
				}
			}
			return false;
		}

