				using (m_SelectEnterEventArgs.Get(out v))
				{
					v.manager = this;
					v.interactorObject = interactor;
					v.interactableObject = interactable;
					SelectEnter(interactor, interactable, v);
				}
				if (interactable is IXRFocusInteractable interactable2)
