	[AddComponentMenu("XR/Locomotion/Legacy/Character Controller Driver", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.CharacterControllerDriver.html")]
	[Obsolete("CharacterControllerDriver is deprecated in XRI 3.0.0 and will be removed in a future release. Instead set useCharacterControllerIfExists to true on the instance of XRBodyTransformer in the scene, and then, if at runtime, re-enable the Body Transformer to make the locomotion system drive the CharacterController.", false)]
	public class CharacterControllerDriver : MonoBehaviour
	{
		[SerializeField]
		[Tooltip("The Locomotion Provider object to listen to.")]
		private LocomotionProvider m_LocomotionProvider;

		[SerializeField]
		[Tooltip("The minimum height of the character's capsule that will be set by this behavior.")]
		private float m_MinHeight;

		[SerializeField]
		[Tooltip("The maximum height of the character's capsule that will be set by this behavior.")]
		private float m_MaxHeight = float.PositiveInfinity;

		private XROrigin m_XROrigin;

		private CharacterController m_CharacterController;

		public LocomotionProvider locomotionProvider
		{
			get
			{
				return m_LocomotionProvider;
			}
			set
			{
				Unsubscribe(m_LocomotionProvider);
				m_LocomotionProvider = value;
				Subscribe(m_LocomotionProvider);
				SetupCharacterController();
				UpdateCharacterController();
			}
		}

		public float minHeight
		{
			get
			{
				return m_MinHeight;
			}
			set
			{
				m_MinHeight = value;
			}
		}

		public float maxHeight
		{
			get
			{
				return m_MaxHeight;
			}
			set
			{
				m_MaxHeight = value;
			}
		}

		protected XROrigin xrOrigin => m_XROrigin;

		[Obsolete("xrRig has been deprecated. Use xrOrigin instead.", true)]
		protected XRRig xrRig => null;

		protected CharacterController characterController => m_CharacterController;

		protected void Awake()
		{
			if (!(m_LocomotionProvider == null))
			{
				return;
			}
			m_LocomotionProvider = GetComponent<ContinuousMoveProviderBase>();
			if (m_LocomotionProvider == null)
			{
				m_LocomotionProvider = ComponentLocatorUtility<ContinuousMoveProviderBase>.FindComponent();
				if (m_LocomotionProvider == null)
				{
					Debug.LogWarning("Unable to drive properties of the Character Controller without the locomotion events of a Locomotion Provider. Set Locomotion Provider or ensure a Continuous Move Provider component is in your scene.", this);
				}
			}
		}

		protected void OnEnable()
		{
			Subscribe(m_LocomotionProvider);
		}

		protected void OnDisable()
		{
			Unsubscribe(m_LocomotionProvider);
		}

		protected void Start()
		{
			SetupCharacterController();
			UpdateCharacterController();
		}

		protected virtual void UpdateCharacterController()
		{
			if (!(m_XROrigin == null) && !(m_CharacterController == null))
			{
				float num = Mathf.Clamp(m_XROrigin.CameraInOriginSpaceHeight, m_MinHeight, m_MaxHeight);
				Vector3 cameraInOriginSpacePos = m_XROrigin.CameraInOriginSpacePos;
				cameraInOriginSpacePos.y = num / 2f + m_CharacterController.skinWidth;
				m_CharacterController.height = num;
				m_CharacterController.center = cameraInOriginSpacePos;
			}
		}

		private void Subscribe(LocomotionProvider provider)
		{
			if (provider != null)
			{
				provider.beginLocomotion += OnBeginLocomotion;
				provider.endLocomotion += OnEndLocomotion;
			}
		}

		private void Unsubscribe(LocomotionProvider provider)
		{
			if (provider != null)
			{
				provider.beginLocomotion -= OnBeginLocomotion;
				provider.endLocomotion -= OnEndLocomotion;
			}
		}

		private void SetupCharacterController()
		{
			if (!(m_LocomotionProvider == null) && !(m_LocomotionProvider.system == null))
			{
				m_XROrigin = m_LocomotionProvider.system.xrOrigin;
				m_CharacterController = ((m_XROrigin != null) ? m_XROrigin.Origin.GetComponent<CharacterController>() : null);
				if (m_CharacterController == null && m_XROrigin != null)
				{
					Debug.LogError($"Could not get CharacterController on {m_XROrigin.Origin}, unable to drive properties." + $" Ensure there is a CharacterController on the \"Rig\" GameObject of {m_XROrigin}.", this);
				}
			}
		}

		private void OnBeginLocomotion(LocomotionSystem system)
		{
			UpdateCharacterController();
		}

		private void OnEndLocomotion(LocomotionSystem system)
		{
			UpdateCharacterController();
		}
	}
	[Obsolete("The ContinuousMoveProviderBase has been deprecated in XRI 3.0.0 and will be removed in a future version of XRI. Please use ContinuousMoveProvider instead.", false)]
	public abstract class ContinuousMoveProviderBase : LocomotionProvider
	{
		[Obsolete("GravityApplicationMode has been deprecated in XRI 3.0.0 and will be removed in a future version of XRI. Please use LocomotionMediator with a GravityProvider.", false)]
		public enum GravityApplicationMode
		{
			AttemptingMove,
			Immediately
		}

		[SerializeField]
		[Tooltip("The speed, in units per second, to move forward.")]
		private float m_MoveSpeed = 1f;

		[SerializeField]
		[Tooltip("Controls whether to enable strafing (sideways movement).")]
		private bool m_EnableStrafe = true;

		[SerializeField]
		[Tooltip("Controls whether to enable flying (unconstrained movement). This overrides the use of gravity.")]
		private bool m_EnableFly;

		[SerializeField]
		[Tooltip("Controls whether gravity affects this provider when a Character Controller is used and flying is disabled.")]
		private bool m_UseGravity = true;

		[SerializeField]
		[Tooltip("Controls when gravity begins to take effect.")]
		private GravityApplicationMode m_GravityApplicationMode;

		[SerializeField]
		[Tooltip("The source Transform to define the forward direction.")]
		private Transform m_ForwardSource;

		private CharacterController m_CharacterController;

		private bool m_AttemptedGetCharacterController;

		private bool m_IsMovingXROrigin;

		private Vector3 m_VerticalVelocity;

		public float moveSpeed
		{
			get
			{
				return m_MoveSpeed;
			}
			set
			{
				m_MoveSpeed = value;
			}
		}

		public bool enableStrafe
		{
			get
			{
				return m_EnableStrafe;
			}
			set
			{
				m_EnableStrafe = value;
			}
		}

		public bool enableFly
		{
			get
			{
				return m_EnableFly;
			}
			set
			{
				m_EnableFly = value;
			}
		}

		public bool useGravity
		{
			get
			{
				return m_UseGravity;
			}
			set
			{
				m_UseGravity = value;
			}
		}

		public GravityApplicationMode gravityApplicationMode
		{
			get
			{
				return m_GravityApplicationMode;
			}
			set
			{
				m_GravityApplicationMode = value;
			}
		}

		public Transform forwardSource
		{
			get
			{
				return m_ForwardSource;
			}
			set
			{
				m_ForwardSource = value;
			}
		}

		protected void Update()
		{
			m_IsMovingXROrigin = false;
			if (base.system.xrOrigin?.Origin == null)
			{
				return;
			}
			Vector2 vector = ReadInput();
			Vector3 translationInWorldSpace = ComputeDesiredMove(vector);
			switch (m_GravityApplicationMode)
			{
			case GravityApplicationMode.Immediately:
				MoveRig(translationInWorldSpace);
				break;
			case GravityApplicationMode.AttemptingMove:
				if (vector != Vector2.zero || m_VerticalVelocity != Vector3.zero)
				{
					MoveRig(translationInWorldSpace);
				}
				break;
			}
			switch (base.locomotionPhase)
			{
			case LocomotionPhase.Idle:
			case LocomotionPhase.Started:
				if (m_IsMovingXROrigin)
				{
					base.locomotionPhase = LocomotionPhase.Moving;
				}
				break;
			case LocomotionPhase.Moving:
				if (!m_IsMovingXROrigin)
				{
					base.locomotionPhase = LocomotionPhase.Done;
				}
				break;
			case LocomotionPhase.Done:
				base.locomotionPhase = (m_IsMovingXROrigin ? LocomotionPhase.Moving : LocomotionPhase.Idle);
				break;
			}
		}

		protected abstract Vector2 ReadInput();

		protected virtual Vector3 ComputeDesiredMove(Vector2 input)
		{
			if (input == Vector2.zero)
			{
				return Vector3.zero;
			}
			XROrigin xrOrigin = base.system.xrOrigin;
			if (xrOrigin == null)
			{
				return Vector3.zero;
			}
			Vector3 vector = Vector3.ClampMagnitude(new Vector3(m_EnableStrafe ? input.x : 0f, 0f, input.y), 1f);
			Transform transform = ((m_ForwardSource == null) ? xrOrigin.Camera.transform : m_ForwardSource);
			Vector3 vector2 = transform.forward;
			Transform transform2 = xrOrigin.Origin.transform;
			float num = m_MoveSpeed * Time.deltaTime * transform2.localScale.x;
			if (m_EnableFly)
			{
				Vector3 right = transform.right;
				return (vector.x * right + vector.z * vector2) * num;
			}
			Vector3 up = transform2.up;
			if (Mathf.Approximately(Mathf.Abs(Vector3.Dot(vector2, up)), 1f))
			{
				vector2 = -transform.up;
			}
			Vector3 toDirection = Vector3.ProjectOnPlane(vector2, up);
			Vector3 direction = Quaternion.FromToRotation(transform2.forward, toDirection) * vector * num;
			return transform2.TransformDirection(direction);
		}

		protected virtual void MoveRig(Vector3 translationInWorldSpace)
		{
			GameObject gameObject = base.system.xrOrigin?.Origin;
			if (gameObject == null)
			{
				return;
			}
			FindCharacterController();
			Vector3 vector = translationInWorldSpace;
			if (m_CharacterController != null && m_CharacterController.enabled)
			{
				if (m_CharacterController.isGrounded || !m_UseGravity || m_EnableFly)
				{
					m_VerticalVelocity = Vector3.zero;
				}
				else
				{
					m_VerticalVelocity += Physics.gravity * Time.deltaTime;
				}
				vector += m_VerticalVelocity * Time.deltaTime;
				if (CanBeginLocomotion() && BeginLocomotion())
				{
					m_IsMovingXROrigin = true;
					m_CharacterController.Move(vector);
					EndLocomotion();
				}
			}
			else if (CanBeginLocomotion() && BeginLocomotion())
			{
				m_IsMovingXROrigin = true;
				gameObject.transform.position += vector;
				EndLocomotion();
			}
		}

		private void FindCharacterController()
		{
			GameObject gameObject = base.system.xrOrigin?.Origin;
			if (!(gameObject == null) && m_CharacterController == null && !m_AttemptedGetCharacterController)
			{
				if (!gameObject.TryGetComponent<CharacterController>(out m_CharacterController) && gameObject != base.system.xrOrigin.gameObject)
				{
					base.system.xrOrigin.TryGetComponent<CharacterController>(out m_CharacterController);
				}
				m_AttemptedGetCharacterController = true;
			}
		}
	}
	[Obsolete("The ContinuousMoveProviderBase has been deprecated in XRI 3.0.0 and will be removed in a future version of XRI. Please use ContinuousTurnProvider instead.", false)]
	public abstract class ContinuousTurnProviderBase : LocomotionProvider
	{
		[SerializeField]
		[Tooltip("The number of degrees/second clockwise to rotate when turning clockwise.")]
		private float m_TurnSpeed = 60f;

		private bool m_IsTurningXROrigin;

		public float turnSpeed
		{
			get
			{
				return m_TurnSpeed;
			}
			set
			{
				m_TurnSpeed = value;
			}
		}

		protected void Update()
		{
			m_IsTurningXROrigin = false;
			Vector2 input = ReadInput();
			float turnAmount = GetTurnAmount(input);
			TurnRig(turnAmount);
			switch (base.locomotionPhase)
			{
			case LocomotionPhase.Idle:
			case LocomotionPhase.Started:
				if (m_IsTurningXROrigin)
				{
					base.locomotionPhase = LocomotionPhase.Moving;
				}
				break;
			case LocomotionPhase.Moving:
				if (!m_IsTurningXROrigin)
				{
					base.locomotionPhase = LocomotionPhase.Done;
				}
				break;
			case LocomotionPhase.Done:
				base.locomotionPhase = (m_IsTurningXROrigin ? LocomotionPhase.Moving : LocomotionPhase.Idle);
				break;
			}
		}

		protected abstract Vector2 ReadInput();

		protected virtual float GetTurnAmount(Vector2 input)
		{
			if (input == Vector2.zero)
			{
				return 0f;
			}
			Cardinal nearestCardinal = CardinalUtility.GetNearestCardinal(input);
			if ((uint)nearestCardinal > 1u && (uint)(nearestCardinal - 2) <= 1u)
			{
				return input.magnitude * (Mathf.Sign(input.x) * m_TurnSpeed * Time.deltaTime);
			}
			return 0f;
		}

		protected void TurnRig(float turnAmount)
		{
			if (!Mathf.Approximately(turnAmount, 0f) && CanBeginLocomotion() && BeginLocomotion())
			{
				XROrigin xrOrigin = base.system.xrOrigin;
				if (xrOrigin != null)
				{
					m_IsTurningXROrigin = true;
					xrOrigin.RotateAroundCameraUsingOriginUp(turnAmount);
				}
				EndLocomotion();
			}
		}
	}
	[AddComponentMenu("XR/Locomotion/Legacy/Continuous Move Provider (Device-based)", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.DeviceBasedContinuousMoveProvider.html")]
	[Obsolete("DeviceBasedContinuousMoveProvider has been deprecated in version 3.0.0. Use ContinuousMoveProvider instead.")]
	public class DeviceBasedContinuousMoveProvider : ContinuousMoveProviderBase
	{
		public enum InputAxes
		{
			Primary2DAxis,
			Secondary2DAxis
		}

		[SerializeField]
		[Tooltip("The 2D Input Axis on the controller devices that will be used to trigger a move.")]
		private InputAxes m_InputBinding;

		[SerializeField]
		[Tooltip("A list of controllers that allow move.  If an XRController is not enabled, or does not have input actions enabled, move will not work.")]
		private List<XRBaseController> m_Controllers = new List<XRBaseController>();

		[SerializeField]
		[Tooltip("Value below which input values will be clamped. After clamping, values will be renormalized to [0, 1] between min and max.")]
		private float m_DeadzoneMin = 0.125f;

		[SerializeField]
		[Tooltip("Value above which input values will be clamped. After clamping, values will be renormalized to [0, 1] between min and max.")]
		private float m_DeadzoneMax = 0.925f;

		private static readonly InputFeatureUsage<Vector2>[] k_Vec2UsageList = new InputFeatureUsage<Vector2>[2]
		{
			CommonUsages.primary2DAxis,
			CommonUsages.secondary2DAxis
		};

		public InputAxes inputBinding
		{
			get
			{
				return m_InputBinding;
			}
			set
			{
				m_InputBinding = value;
			}
		}

		public List<XRBaseController> controllers
		{
			get
			{
				return m_Controllers;
			}
			set
			{
				m_Controllers = value;
			}
		}

		public float deadzoneMin
		{
			get
			{
				return m_DeadzoneMin;
			}
			set
			{
				m_DeadzoneMin = value;
			}
		}

		public float deadzoneMax
		{
			get
			{
				return m_DeadzoneMax;
			}
			set
			{
				m_DeadzoneMax = value;
			}
		}

		protected override Vector2 ReadInput()
		{
			if (m_Controllers.Count == 0)
			{
				return Vector2.zero;
			}
			Vector2 zero = Vector2.zero;
			InputFeatureUsage<Vector2> usage = k_Vec2UsageList[(int)m_InputBinding];
			for (int i = 0; i < m_Controllers.Count; i++)
			{
				XRController xRController = m_Controllers[i] as XRController;
				if (xRController != null && xRController.enableInputActions && xRController.inputDevice.TryGetFeatureValue(usage, out var value))
				{
					zero += GetDeadzoneAdjustedValue(value);
				}
			}
			return zero;
		}

		protected Vector2 GetDeadzoneAdjustedValue(Vector2 value)
		{
			float magnitude = value.magnitude;
			float deadzoneAdjustedValue = GetDeadzoneAdjustedValue(magnitude);
			if (Mathf.Approximately(deadzoneAdjustedValue, 0f))
			{
				value = Vector2.zero;
			}
			else
			{
				value *= deadzoneAdjustedValue / magnitude;
			}
			return value;
		}

		protected float GetDeadzoneAdjustedValue(float value)
		{
			float num = m_DeadzoneMin;
			float num2 = m_DeadzoneMax;
			float num3 = Mathf.Abs(value);
			if (num3 < num)
			{
				return 0f;
			}
			if (num3 > num2)
			{
				return Mathf.Sign(value);
			}
			return Mathf.Sign(value) * ((num3 - num) / (num2 - num));
		}
	}
	[AddComponentMenu("XR/Locomotion/Legacy/Continuous Turn Provider (Device-based)", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.DeviceBasedContinuousTurnProvider.html")]
	[Obsolete("DeviceBasedContinuousTurnProvider has been deprecated in version 3.0.0. Use ContinuousTurnProvider instead.")]
	public class DeviceBasedContinuousTurnProvider : ContinuousTurnProviderBase
	{
		public enum InputAxes
		{
			Primary2DAxis,
			Secondary2DAxis
		}

		[SerializeField]
		[Tooltip("The 2D Input Axis on the controller devices that will be used to trigger a turn.")]
		private InputAxes m_InputBinding;

		[SerializeField]
		[Tooltip("A list of controllers that allow Turn.  If an XRController is not enabled, or does not have input actions enabled, turn will not work.")]
		private List<XRBaseController> m_Controllers = new List<XRBaseController>();

		[SerializeField]
		[Tooltip("Value below which input values will be clamped. After clamping, values will be renormalized to [0, 1] between min and max.")]
		private float m_DeadzoneMin = 0.125f;

		[SerializeField]
		[Tooltip("Value above which input values will be clamped. After clamping, values will be renormalized to [0, 1] between min and max.")]
		private float m_DeadzoneMax = 0.925f;

		private static readonly InputFeatureUsage<Vector2>[] k_Vec2UsageList = new InputFeatureUsage<Vector2>[2]
		{
			CommonUsages.primary2DAxis,
			CommonUsages.secondary2DAxis
		};

		public InputAxes inputBinding
		{
			get
			{
				return m_InputBinding;
			}
			set
			{
				m_InputBinding = value;
			}
		}

		public List<XRBaseController> controllers
		{
			get
			{
				return m_Controllers;
			}
			set
			{
				m_Controllers = value;
			}
		}

		public float deadzoneMin
		{
			get
			{
				return m_DeadzoneMin;
			}
			set
			{
				m_DeadzoneMin = value;
			}
		}

		public float deadzoneMax
		{
			get
			{
				return m_DeadzoneMax;
			}
			set
			{
				m_DeadzoneMax = value;
			}
		}

		protected override Vector2 ReadInput()
		{
			if (m_Controllers.Count == 0)
			{
				return Vector2.zero;
			}
			Vector2 zero = Vector2.zero;
			InputFeatureUsage<Vector2> usage = k_Vec2UsageList[(int)m_InputBinding];
			for (int i = 0; i < m_Controllers.Count; i++)
			{
				XRController xRController = m_Controllers[i] as XRController;
				if (xRController != null && xRController.enableInputActions && xRController.inputDevice.TryGetFeatureValue(usage, out var value))
				{
					zero += GetDeadzoneAdjustedValue(value);
				}
			}
			return zero;
		}

		protected Vector2 GetDeadzoneAdjustedValue(Vector2 value)
		{
			float magnitude = value.magnitude;
			float deadzoneAdjustedValue = GetDeadzoneAdjustedValue(magnitude);
			if (Mathf.Approximately(deadzoneAdjustedValue, 0f))
			{
				value = Vector2.zero;
			}
			else
			{
				value *= deadzoneAdjustedValue / magnitude;
			}
			return value;
		}

		protected float GetDeadzoneAdjustedValue(float value)
		{
			float num = m_DeadzoneMin;
			float num2 = m_DeadzoneMax;
			float num3 = Mathf.Abs(value);
			if (num3 < num)
			{
				return 0f;
			}
			if (num3 > num2)
			{
				return Mathf.Sign(value);
			}
			return Mathf.Sign(value) * ((num3 - num) / (num2 - num));
		}
	}
