			{
				result = math.cross(input, new float3(1f, 0f, 0f));
			}
			else if (math.abs(input.y) < math.abs(input.z))
			{
				result = math.cross(input, new float3(0f, 1f, 0f));
			}
			else
			{
				result = math.cross(input, new float3(0f, 0f, 1f));
			}
		}
