		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[BurstCompile]
		internal static void GetSphereOverlapParameters$BurstManaged(in Vector3 overlapStart, in Vector3 overlapEnd, out Vector3 normalizedOverlapVector, out float overlapSqrMagnitude, out float overlapDistance)
		{
			Vector3 vector = overlapEnd - overlapStart;
			overlapSqrMagnitude = math.distancesq(overlapStart, overlapEnd);
			overlapDistance = math.sqrt(overlapSqrMagnitude);
			normalizedOverlapVector = vector / overlapDistance;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[BurstCompile]
		internal static void GetConecastParameters$BurstManaged(float angleRadius, float offset, float maxOffset, in Vector3 direction, out Vector3 originOffset, out float radius, out float castMax)
		{
			castMax = math.clamp(offset, 0.125f, maxOffset);
			radius = angleRadius * (offset + castMax);
			originOffset = direction * (offset - radius);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[BurstCompile]
		internal static void GetMultiSegmentConecastParameters$BurstManaged(float angleRadius, float segmentOffset, float offsetFromOrigin, float maxOffset, in Vector3 direction, out Vector3 originOffset, out float radius, out float castMax)
		{
			castMax = math.clamp(segmentOffset, 0.125f, maxOffset);
			if (segmentOffset + castMax > maxOffset)
			{
				castMax = math.clamp(maxOffset - segmentOffset, 0.125f, castMax);
			}
			radius = angleRadius * (offsetFromOrigin + castMax);
			originOffset = direction * (segmentOffset - radius);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		[BurstCompile]
		internal static void GetConecastOffset$BurstManaged(in float3 origin, in float3 conePoint, in float3 direction, out float coneOffset)
		{
			float3 obj = conePoint - origin;
			float num = math.dot(obj, direction);
			float3 x = obj - direction * num;
			coneOffset = math.length(x);
		}
	}
	internal static class ComponentLocatorUtility<T> where T : Component
	{
		private static T s_ComponentCache;

		private static int s_LastTryFindFrame = -1;

		internal static T componentCache => s_ComponentCache;

		private static bool FindWasPerformedThisFrame()
		{
			return s_LastTryFindFrame == Time.frameCount;
		}

		public static T FindOrCreateComponent()
		{
			if (s_ComponentCache == null)
			{
				s_ComponentCache = Find();
				if (s_ComponentCache == null)
				{
					s_ComponentCache = new GameObject(typeof(T).Name, typeof(T)).GetComponent<T>();
				}
			}
			return s_ComponentCache;
		}

		public static T FindComponent()
		{
			TryFindComponent(out var component);
			return component;
		}

		public static bool TryFindComponent(out T component)
		{
			if (s_ComponentCache != null)
			{
				component = s_ComponentCache;
				return true;
			}
			s_ComponentCache = Find();
			component = s_ComponentCache;
			return component != null;
		}

		internal static bool TryFindComponent(out T component, bool limitTryFindPerFrame)
		{
			if (limitTryFindPerFrame && FindWasPerformedThisFrame() && s_ComponentCache == null)
			{
				component = null;
				return false;
			}
			return TryFindComponent(out component);
		}

		private static T Find()
		{
			s_LastTryFindFrame = Time.frameCount;
			return Object.FindFirstObjectByType<T>();
		}
	}
	internal static class DisplayUtility
	{
		private static float s_ScreenDpi = 100f;

		private static float s_OneOverScreenDpi = 1f / s_ScreenDpi;

		private static bool s_ScreenDpiChecked;

		public static float screenDpi
		{
			get
			{
				CacheScreenDpi();
				return s_ScreenDpi;
			}
		}

		public static float screenDpiRatio
		{
			get
			{
				CacheScreenDpi();
				return s_OneOverScreenDpi;
			}
		}

		private static void CacheScreenDpi()
		{
			if (!s_ScreenDpiChecked)
			{
				if (Screen.dpi > 0f)
				{
					s_ScreenDpi = Screen.dpi;
				}
				else
				{
					Debug.LogWarning("Platform has reported a screen DPI of 0. Using default value of 100.");
				}
				s_OneOverScreenDpi = 1f / s_ScreenDpi;
				s_ScreenDpiChecked = true;
			}
		}

		public static float PixelsToInches(float pixels)
		{
			return pixels * screenDpiRatio;
		}

		public static float InchesToPixels(float inches)
		{
			return inches * screenDpi;
		}
	}
	[AddComponentMenu("")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Utilities.DisposableManagerSingleton.html")]
	internal sealed class DisposableManagerSingleton : MonoBehaviour
	{
		private static DisposableManagerSingleton s_DisposableManagerSingleton;

		private readonly HashSetList<IDisposable> m_Disposables = new HashSetList<IDisposable>();

		private static DisposableManagerSingleton instance => Initialize();

		private static DisposableManagerSingleton Initialize()
		{
			if (s_DisposableManagerSingleton == null)
			{
				GameObject obj = new GameObject("[DisposableManagerSingleton]");
				Object.DontDestroyOnLoad(obj);
				s_DisposableManagerSingleton = obj.AddComponent<DisposableManagerSingleton>();
			}
			return s_DisposableManagerSingleton;
		}

		private void Awake()
		{
			if (s_DisposableManagerSingleton != null && s_DisposableManagerSingleton != this)
			{
				Object.Destroy(this);
			}
			else if (s_DisposableManagerSingleton == null)
			{
				s_DisposableManagerSingleton = this;
			}
		}

		private void OnDestroy()
		{
			DisposeAll();
		}

		private void OnApplicationQuit()
		{
			DisposeAll();
		}

		private void DisposeAll()
		{
			IReadOnlyList<IDisposable> readOnlyList = m_Disposables.AsList();
			for (int i = 0; i < readOnlyList.Count; i++)
			{
				readOnlyList[i].Dispose();
			}
			m_Disposables.Clear();
		}

		public static void RegisterDisposable(IDisposable disposableToRegister)
		{
			instance.m_Disposables.Add(disposableToRegister);
		}
	}
	internal class ExposedRegistrationList<T> : SmallRegistrationList<T>, IXRFilterList<T> where T : class
	{
		public int count => base.flushedCount;

		public void Add(T item)
		{
			if (item == null || (item is Object obj && obj == null))
			{
				throw new ArgumentNullException("item");
			}
			Register(item);
		}

		public bool Remove(T item)
		{
			return Unregister(item);
		}

		public void MoveTo(T item, int newIndex)
		{
			MoveItemImmediately(item, newIndex);
		}

		public void Clear()
		{
			UnregisterAll();
		}

		public void GetAll(List<T> results)
		{
			GetRegisteredItems(results);
		}

		public T GetAt(int index)
		{
			return GetRegisteredItemAt(index);
		}

		public void RegisterReferences<TObject>(List<TObject> references, Object context = null) where TObject : Object
		{
			foreach (TObject reference in references)
			{
				if (reference != null && reference is T item)
				{
					Add(item);
				}
				else if (context != null)
				{
					Debug.LogError($"Trying to add the invalid item {reference} into {typeof(IXRFilterList<T>).Name}, in {context}. {reference} does not implement {typeof(T).Name}.", context);
				}
				else
				{
					Debug.LogError($"Trying to add the invalid item {reference} into {typeof(IXRFilterList<T>).Name}. {reference} does not implement {typeof(T).Name}.");
				}
			}
		}
	}
	public class GradientUtility
	{
		private const int k_MaxGradientColorKeys = 8;

		private const int k_Precision = 100;

		private static readonly List<float> s_ColorKeyTimes;

		private static readonly HashSet<int> s_TruncatedColorKeyTimes;

		private static readonly List<float> s_AlphaKeyTimes;

		private static readonly HashSet<int> s_TruncatedAlphaKeyTimes;

		private static readonly GradientColorKey[][] s_ColorKeyArrays;

		private static readonly GradientAlphaKey[][] s_AlphaKeyArrays;

		static GradientUtility()
		{
			s_ColorKeyTimes = new List<float>();
			s_TruncatedColorKeyTimes = new HashSet<int>();
			s_AlphaKeyTimes = new List<float>();
			s_TruncatedAlphaKeyTimes = new HashSet<int>();
			s_ColorKeyArrays = new GradientColorKey[7][];
			s_AlphaKeyArrays = new GradientAlphaKey[7][];
			for (int i = 2; i <= 8; i++)
			{
				s_ColorKeyArrays[i - 2] = new GradientColorKey[i];
				s_AlphaKeyArrays[i - 2] = new GradientAlphaKey[i];
			}
		}

		public static Gradient Lerp(Gradient a, Gradient b, float t, bool lerpColors = true, bool lerpAlphas = true)
		{
			Gradient gradient = new Gradient();
			Lerp(a, b, gradient, t, lerpColors, lerpAlphas);
			return gradient;
		}

		public static void Lerp(Gradient a, Gradient b, Gradient output, float t, bool lerpColors = true, bool lerpAlphas = true)
		{
			s_ColorKeyTimes.Clear();
			s_TruncatedColorKeyTimes.Clear();
			s_AlphaKeyTimes.Clear();
			s_TruncatedAlphaKeyTimes.Clear();
			if (lerpColors)
			{
				AddUniqueColorKeys(a.colorKeys);
				AddUniqueColorKeys(b.colorKeys);
			}
			if (lerpAlphas)
			{
				AddUniqueAlphaKeys(a.alphaKeys);
				AddUniqueAlphaKeys(b.alphaKeys);
			}
			ReduceKeysIfNeeded(s_ColorKeyTimes, 8);
			ReduceKeysIfNeeded(s_AlphaKeyTimes, 8);
			GradientColorKey[] colorKeys = (lerpColors ? PrepareColorKeys(s_ColorKeyTimes, a, b, t) : b.colorKeys);
			GradientAlphaKey[] alphaKeys = (lerpAlphas ? PrepareAlphaKeys(s_AlphaKeyTimes, a, b, t) : b.alphaKeys);
			output.SetKeys(colorKeys, alphaKeys);
		}

		public static void CopyGradient(Gradient source, Gradient destination)
		{
			destination.SetKeys(source.colorKeys, source.alphaKeys);
		}

		private static void AddUniqueColorKeys(GradientColorKey[] keys)
		{
			for (int i = 0; i < keys.Length; i++)
			{
				AddColorKeyIfUnique(keys[i].time);
			}
		}

		private static void AddUniqueAlphaKeys(GradientAlphaKey[] keys)
		{
			for (int i = 0; i < keys.Length; i++)
			{
				AddAlphaKeyIfUnique(keys[i].time);
			}
		}

		private static void AddColorKeyIfUnique(float keyTime)
		{
			int item = TruncatePrecision(keyTime);
			if (s_TruncatedColorKeyTimes.Add(item))
			{
				s_ColorKeyTimes.Add(keyTime);
			}
		}

		private static void AddAlphaKeyIfUnique(float keyTime)
		{
			int item = TruncatePrecision(keyTime);
			if (s_TruncatedAlphaKeyTimes.Add(item))
			{
				s_AlphaKeyTimes.Add(keyTime);
			}
		}

		private static GradientColorKey[] PrepareColorKeys(List<float> keyTimes, Gradient a, Gradient b, float t)
		{
			int count = keyTimes.Count;
			GradientColorKey[] colorKeyArray = GetColorKeyArray(count);
			for (int i = 0; i < count; i++)
			{
				float time = keyTimes[i];
				Color col = Color.Lerp(a.Evaluate(time), b.Evaluate(time), t);
				colorKeyArray[i] = new GradientColorKey(col, time);
			}
			return colorKeyArray;
		}

		private static GradientAlphaKey[] PrepareAlphaKeys(List<float> keyTimes, Gradient a, Gradient b, float t)
		{
			int count = keyTimes.Count;
			GradientAlphaKey[] alphaKeyArray = GetAlphaKeyArray(count);
			for (int i = 0; i < count; i++)
			{
				float time = keyTimes[i];
				float alpha = Mathf.Lerp(a.Evaluate(time).a, b.Evaluate(time).a, t);
				alphaKeyArray[i] = new GradientAlphaKey(alpha, time);
			}
			return alphaKeyArray;
		}

		private static int TruncatePrecision(float value)
		{
			return (int)(value * 100f);
		}

		private static void ReduceKeysIfNeeded(List<float> keyTimes, int maxKeys)
		{
			while (keyTimes.Count > maxKeys)
			{
				int index = keyTimes.Count / 2;
				keyTimes.RemoveAt(index);
			}
		}

		private static GradientColorKey[] GetColorKeyArray(int size)
		{
			if (size < 2 || size > 8)
			{
				return new GradientColorKey[size];
			}
			return s_ColorKeyArrays[size - 2];
		}

		private static GradientAlphaKey[] GetAlphaKeyArray(int size)
		{
			if (size < 2 || size > 8)
			{
				return new GradientAlphaKey[size];
			}
			return s_AlphaKeyArrays[size - 2];
		}
	}
	internal static class XRFilterUtility
	{
		public static bool Process(SmallRegistrationList<IXRHoverFilter> filters, IXRHoverInteractor interactor, IXRHoverInteractable interactable)
		{
			if (filters.registeredSnapshot.Count == 0)
			{
				return true;
			}
			bool bufferChanges = filters.bufferChanges;
			filters.bufferChanges = true;
			bool result = true;
			try
			{
				foreach (IXRHoverFilter item in filters.registeredSnapshot)
				{
					if (item.canProcess && !item.Process(interactor, interactable))
					{
						result = false;
						break;
					}
				}
			}
			finally
			{
				if (!bufferChanges)
				{
					filters.bufferChanges = false;
				}
			}
			return result;
		}

		public static bool Process(SmallRegistrationList<IXRSelectFilter> filters, IXRSelectInteractor interactor, IXRSelectInteractable interactable)
		{
			if (filters.registeredSnapshot.Count == 0)
			{
				return true;
			}
			bool bufferChanges = filters.bufferChanges;
			filters.bufferChanges = true;
			bool result = true;
			try
			{
				foreach (IXRSelectFilter item in filters.registeredSnapshot)
				{
					if (item.canProcess && !item.Process(interactor, interactable))
					{
						result = false;
						break;
					}
				}
			}
			finally
			{
				if (!bufferChanges)
				{
					filters.bufferChanges = false;
				}
			}
			return result;
		}

		public static float Process(SmallRegistrationList<IXRInteractionStrengthFilter> filters, IXRInteractor interactor, IXRInteractable interactable, float interactionStrength)
		{
			if (filters.registeredSnapshot.Count == 0)
			{
				return interactionStrength;
			}
			bool bufferChanges = filters.bufferChanges;
			filters.bufferChanges = true;
			try
			{
				foreach (IXRInteractionStrengthFilter item in filters.registeredSnapshot)
				{
					if (item.canProcess)
					{
						interactionStrength = item.Process(interactor, interactable, interactionStrength);
					}
				}
				return interactionStrength;
			}
			finally
			{
				if (!bufferChanges)
				{
					filters.bufferChanges = false;
				}
			}
		}
	}
	public static class XRInteractableUtility
	{
		internal struct AllowTriggerCollidersScope(bool newAllowTriggerColliders) : IDisposable
		{
			private bool m_Disposed = false;

			private readonly bool m_OldValue = allowTriggerColliders;

			public void Dispose()
			{
				if (!m_Disposed)
				{
					m_Disposed = true;
					allowTriggerColliders = m_OldValue;
				}
			}
		}

		private static bool allowTriggerColliders { get; set; }

		public static bool TryGetClosestCollider(IXRInteractable interactable, Vector3 position, out DistanceInfo distanceInfo)
		{
			Vector3 point = default(Vector3);
			float num = float.MaxValue;
			Collider collider = null;
			bool result = false;
			foreach (Collider collider2 in interactable.colliders)
			{
				if (!(collider2 == null) && collider2.gameObject.activeInHierarchy && collider2.enabled && (!collider2.isTrigger || allowTriggerColliders))
				{
					Vector3 position2 = collider2.transform.position;
					float sqrMagnitude = (position - position2).sqrMagnitude;
					if (!(sqrMagnitude >= num))
					{
						result = true;
						num = sqrMagnitude;
						point = position2;
						collider = collider2;
					}
				}
			}
			distanceInfo = new DistanceInfo
			{
				point = point,
				distanceSqr = num,
				collider = collider
			};
			return result;
		}

		public static bool TryGetClosestPointOnCollider(IXRInteractable interactable, Vector3 position, out DistanceInfo distanceInfo)
		{
			Vector3 point = default(Vector3);
			Collider collider = null;
			float num = float.MaxValue;
			bool result = false;
			foreach (Collider collider2 in interactable.colliders)
			{
				if (!(collider2 == null) && collider2.gameObject.activeInHierarchy && collider2.enabled && (!collider2.isTrigger || allowTriggerColliders))
				{
					Vector3 vector = collider2.ClosestPoint(position);
					float sqrMagnitude = (position - vector).sqrMagnitude;
					if (!(sqrMagnitude >= num))
					{
						result = true;
						num = sqrMagnitude;
						point = vector;
						collider = collider2;
					}
				}
			}
			distanceInfo = new DistanceInfo
			{
				point = point,
				distanceSqr = num,
				collider = collider
			};
			return result;
		}
	}
