	internal abstract class BaseRegistrationList<T>
	{
		private static readonly UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<List<T>> s_BufferedListPool = new UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<List<T>>(() => new List<T>(), null, delegate(List<T> list)
		{
			list.Clear();
		}, null, collectionCheck: false);

		protected List<T> m_BufferedAdd;

		protected List<T> m_BufferedRemove;

		public List<T> registeredSnapshot { get; } = new List<T>();

		public int flushedCount => registeredSnapshot.Count - bufferedRemoveCount + bufferedAddCount;

		protected int bufferedAddCount => m_BufferedAdd?.Count ?? 0;

		protected int bufferedRemoveCount => m_BufferedRemove?.Count ?? 0;

		protected void AddToBufferedAdd(T item)
		{
			if (m_BufferedAdd == null)
			{
				m_BufferedAdd = s_BufferedListPool.Get();
			}
			m_BufferedAdd.Add(item);
		}

		protected bool RemoveFromBufferedAdd(T item)
		{
			if (m_BufferedAdd != null)
			{
				return m_BufferedAdd.Remove(item);
			}
			return false;
		}

		protected void ClearBufferedAdd()
		{
			if (m_BufferedAdd != null)
			{
				s_BufferedListPool.Release(m_BufferedAdd);
				m_BufferedAdd = null;
			}
		}

		protected void AddToBufferedRemove(T item)
		{
			if (m_BufferedRemove == null)
			{
				m_BufferedRemove = s_BufferedListPool.Get();
			}
			m_BufferedRemove.Add(item);
		}

		protected bool RemoveFromBufferedRemove(T item)
		{
			if (m_BufferedRemove != null)
			{
				return m_BufferedRemove.Remove(item);
			}
			return false;
		}

		protected void ClearBufferedRemove()
		{
			if (m_BufferedRemove != null)
			{
				s_BufferedListPool.Release(m_BufferedRemove);
				m_BufferedRemove = null;
			}
		}

		public abstract bool IsRegistered(T item);

		public abstract bool IsStillRegistered(T item);

		public abstract bool Register(T item);

		public abstract bool Unregister(T item);

		public abstract void Flush();

		public abstract void GetRegisteredItems(List<T> results);

		public abstract T GetRegisteredItemAt(int index);

		public bool MoveItemImmediately(T item, int newIndex)
		{
			if (bufferedRemoveCount != 0 || bufferedAddCount != 0)
			{
				throw new InvalidOperationException("Cannot move item when there are pending registration changes that have not been flushed.");
			}
			int num = registeredSnapshot.IndexOf(item);
			if (num == newIndex)
			{
				return false;
			}
			if (num >= 0)
			{
				registeredSnapshot.RemoveAt(num);
			}
			registeredSnapshot.Insert(newIndex, item);
			OnItemMovedImmediately(item, newIndex);
			return num < 0;
		}

		protected virtual void OnItemMovedImmediately(T item, int newIndex)
		{
		}

		public void UnregisterAll()
		{
			List<T> v;
			using (s_BufferedListPool.Get(out v))
			{
				GetRegisteredItems(v);
				for (int num = v.Count - 1; num >= 0; num--)
				{
					Unregister(v[num]);
				}
			}
		}

		protected static void EnsureCapacity(List<T> list, int capacity)
		{
			if (list.Capacity < capacity)
			{
				list.Capacity = capacity;
			}
		}
	}
	internal sealed class RegistrationList<T> : BaseRegistrationList<T>
	{
		private readonly HashSet<T> m_UnorderedBufferedAdd = new HashSet<T>();

		private readonly HashSet<T> m_UnorderedBufferedRemove = new HashSet<T>();

		private readonly HashSet<T> m_UnorderedRegisteredSnapshot = new HashSet<T>();

		private readonly HashSet<T> m_UnorderedRegisteredItems = new HashSet<T>();

		private bool m_BufferedRemoveEmpty = true;

		public override bool IsRegistered(T item)
		{
			return m_UnorderedRegisteredItems.Contains(item);
		}

		public override bool IsStillRegistered(T item)
		{
			if (!m_BufferedRemoveEmpty)
			{
				return !m_UnorderedBufferedRemove.Contains(item);
			}
			return true;
		}

		public override bool Register(T item)
		{
			if (m_UnorderedBufferedAdd.Count > 0 && m_UnorderedBufferedAdd.Contains(item))
			{
				return false;
			}
			bool flag = m_UnorderedRegisteredSnapshot.Contains(item);
			if ((!m_BufferedRemoveEmpty && m_UnorderedBufferedRemove.Remove(item)) || !flag)
			{
				RemoveFromBufferedRemove(item);
				m_BufferedRemoveEmpty = m_UnorderedBufferedRemove.Count == 0;
				m_UnorderedRegisteredItems.Add(item);
				if (!flag)
				{
					AddToBufferedAdd(item);
					m_UnorderedBufferedAdd.Add(item);
				}
				return true;
			}
			return false;
		}

		public override bool Unregister(T item)
		{
			if (!m_BufferedRemoveEmpty && m_UnorderedBufferedRemove.Contains(item))
			{
				return false;
			}
			if (m_UnorderedBufferedAdd.Count > 0 && m_UnorderedBufferedAdd.Remove(item))
			{
				RemoveFromBufferedAdd(item);
				m_UnorderedRegisteredItems.Remove(item);
				return true;
			}
			if (m_UnorderedRegisteredSnapshot.Contains(item))
			{
				AddToBufferedRemove(item);
				m_UnorderedBufferedRemove.Add(item);
				m_BufferedRemoveEmpty = false;
				m_UnorderedRegisteredItems.Remove(item);
				return true;
			}
			return false;
		}

		public override void Flush()
		{
			if (!m_BufferedRemoveEmpty)
			{
				foreach (T item in m_BufferedRemove)
				{
					base.registeredSnapshot.Remove(item);
					m_UnorderedRegisteredSnapshot.Remove(item);
				}
				ClearBufferedRemove();
				m_UnorderedBufferedRemove.Clear();
				m_BufferedRemoveEmpty = true;
			}
			if (base.bufferedAddCount <= 0)
			{
				return;
			}
			foreach (T item2 in m_BufferedAdd)
			{
				if (!m_UnorderedRegisteredSnapshot.Contains(item2))
				{
					base.registeredSnapshot.Add(item2);
					m_UnorderedRegisteredSnapshot.Add(item2);
				}
			}
			ClearBufferedAdd();
			m_UnorderedBufferedAdd.Clear();
		}

		public override void GetRegisteredItems(List<T> results)
		{
			if (results == null)
			{
				throw new ArgumentNullException("results");
			}
			results.Clear();
			BaseRegistrationList<T>.EnsureCapacity(results, base.flushedCount);
			foreach (T item in base.registeredSnapshot)
			{
				if (m_BufferedRemoveEmpty || !m_UnorderedBufferedRemove.Contains(item))
				{
					results.Add(item);
				}
			}
			if (base.bufferedAddCount > 0)
			{
				results.AddRange(m_BufferedAdd);
			}
		}

		public override T GetRegisteredItemAt(int index)
		{
			if (index < 0 || index >= base.flushedCount)
			{
				throw new ArgumentOutOfRangeException("index", "Index was out of range. Must be non-negative and less than the size of the registration collection.");
			}
			if (base.bufferedRemoveCount == 0 && base.bufferedAddCount == 0)
			{
				return base.registeredSnapshot[index];
			}
			if (index >= base.registeredSnapshot.Count - base.bufferedRemoveCount)
			{
				return m_BufferedAdd[index - (base.registeredSnapshot.Count - base.bufferedRemoveCount)];
			}
			int num = 0;
			foreach (T item in base.registeredSnapshot)
			{
				if (!m_UnorderedBufferedRemove.Contains(item))
				{
					if (num == index)
					{
						return base.registeredSnapshot[index];
					}
					num++;
				}
			}
			throw new ArgumentOutOfRangeException("index", "Index was out of range. Must be non-negative and less than the size of the registration collection.");
		}

		protected override void OnItemMovedImmediately(T item, int newIndex)
		{
			base.OnItemMovedImmediately(item, newIndex);
			m_UnorderedRegisteredItems.Add(item);
			m_UnorderedRegisteredSnapshot.Add(item);
		}
	}
	internal static class ScriptableSingletonCache<T> where T : ScriptableObject
	{
		private static T s_Instance;

		private static readonly Dictionary<ScriptableObject, HashSet<object>> s_UsersPerInstance = new Dictionary<ScriptableObject, HashSet<object>>();

		public static T GetInstance(object user)
		{
			if (s_Instance == null)
			{
				s_Instance = ScriptableObject.CreateInstance<T>();
			}
			if (!s_UsersPerInstance.TryGetValue(s_Instance, out var value))
			{
				value = new HashSet<object>();
				s_UsersPerInstance.Add(s_Instance, value);
			}
			value.Add(user);
			return s_Instance;
		}

		public static void ReleaseInstance(object user)
		{
			if (s_Instance == null)
			{
				return;
			}
			if (!s_UsersPerInstance.TryGetValue(s_Instance, out var value))
			{
				Object.Destroy(s_Instance);
				return;
			}
			value.Remove(user);
			if (value.Count == 0)
			{
				s_UsersPerInstance.Remove(s_Instance);
				Object.Destroy(s_Instance);
			}
		}
	}
	internal class SmallRegistrationList<T> : BaseRegistrationList<T>
	{
		private bool m_BufferChanges = true;

		public bool bufferChanges
		{
			get
			{
				return m_BufferChanges;
			}
			set
			{
				if (m_BufferChanges && !value)
				{
					m_BufferChanges = false;
					Flush();
				}
				else
				{
					m_BufferChanges = value;
				}
			}
		}

		public override bool IsRegistered(T item)
		{
			if (base.bufferedAddCount <= 0 || !m_BufferedAdd.Contains(item))
			{
				if (base.registeredSnapshot.Count > 0 && base.registeredSnapshot.Contains(item))
				{
					return IsStillRegistered(item);
				}
				return false;
			}
			return true;
		}

		public override bool IsStillRegistered(T item)
		{
			if (base.bufferedRemoveCount != 0)
			{
				return !m_BufferedRemove.Contains(item);
			}
			return true;
		}

		public override bool Register(T item)
		{
			if (!bufferChanges)
			{
				if (base.registeredSnapshot.Contains(item))
				{
					return false;
				}
				base.registeredSnapshot.Add(item);
				return true;
			}
			if (base.bufferedAddCount > 0 && m_BufferedAdd.Contains(item))
			{
				return false;
			}
			bool flag = base.registeredSnapshot.Contains(item);
			if ((base.bufferedRemoveCount > 0 && RemoveFromBufferedRemove(item)) || !flag)
			{
				if (!flag)
				{
					AddToBufferedAdd(item);
				}
				return true;
			}
			return false;
		}

		public override bool Unregister(T item)
		{
			if (!bufferChanges)
			{
				return base.registeredSnapshot.Remove(item);
			}
			if (base.bufferedRemoveCount > 0 && m_BufferedRemove.Contains(item))
			{
				return false;
			}
			if (base.bufferedAddCount > 0 && RemoveFromBufferedAdd(item))
			{
				return true;
			}
			if (base.registeredSnapshot.Contains(item))
			{
				AddToBufferedRemove(item);
				return true;
			}
			return false;
		}

		public override void Flush()
		{
			if (base.bufferedRemoveCount > 0)
			{
				foreach (T item in m_BufferedRemove)
				{
					base.registeredSnapshot.Remove(item);
				}
				ClearBufferedRemove();
			}
			if (base.bufferedAddCount <= 0)
			{
				return;
			}
			foreach (T item2 in m_BufferedAdd)
			{
				if (!base.registeredSnapshot.Contains(item2))
				{
					base.registeredSnapshot.Add(item2);
				}
			}
			ClearBufferedAdd();
		}

		public override void GetRegisteredItems(List<T> results)
		{
			if (results == null)
			{
				throw new ArgumentNullException("results");
			}
			results.Clear();
			BaseRegistrationList<T>.EnsureCapacity(results, base.flushedCount);
			foreach (T item in base.registeredSnapshot)
			{
				if (base.bufferedRemoveCount <= 0 || !m_BufferedRemove.Contains(item))
				{
					results.Add(item);
				}
			}
			if (base.bufferedAddCount > 0)
			{
				results.AddRange(m_BufferedAdd);
			}
		}

		public override T GetRegisteredItemAt(int index)
		{
			if (index < 0 || index >= base.flushedCount)
			{
				throw new ArgumentOutOfRangeException("index", "Index was out of range. Must be non-negative and less than the size of the registration collection.");
			}
			if (base.bufferedRemoveCount == 0 && base.bufferedAddCount == 0)
			{
				return base.registeredSnapshot[index];
			}
			if (index >= base.registeredSnapshot.Count - base.bufferedRemoveCount)
			{
				return m_BufferedAdd[index - (base.registeredSnapshot.Count - base.bufferedRemoveCount)];
			}
			int num = 0;
			foreach (T item in base.registeredSnapshot)
			{
				if (base.bufferedRemoveCount <= 0 || !m_BufferedRemove.Contains(item))
				{
					if (num == index)
					{
						return base.registeredSnapshot[index];
					}
					num++;
				}
			}
			throw new ArgumentOutOfRangeException("index", "Index was out of range. Must be non-negative and less than the size of the registration collection.");
		}
	}
	internal class TeleportationMonitor
	{
		private class PoseContainer
		{
			public Pose beforePose;

			public Pose afterPose;

			public Pose deltaPose;

			private int m_BeforeFrame = -1;

			private int m_AfterFrame = -1;

			private int m_DeltaFrame = -1;

			public void CaptureBeforePose(XRBodyTransformer bodyTransformer)
			{
				int frameCount = Time.frameCount;
				if (m_BeforeFrame != frameCount && LocomotionUtility.TryGetOriginTransform(bodyTransformer, out var originTransform))
				{
					m_BeforeFrame = frameCount;
					beforePose = originTransform.GetWorldPose();
				}
			}

			public void CaptureAfterPose(XRBodyTransformer bodyTransformer)
			{
				int frameCount = Time.frameCount;
				if (m_AfterFrame != frameCount && LocomotionUtility.TryGetOriginTransform(bodyTransformer, out var originTransform))
				{
					m_AfterFrame = frameCount;
					afterPose = originTransform.GetWorldPose();
				}
			}

			public void CalculateDeltaPose()
			{
				int frameCount = Time.frameCount;
				if (m_DeltaFrame != frameCount)
				{
					Vector3 position = afterPose.position - beforePose.position;
					Quaternion rotation = afterPose.rotation * Quaternion.Inverse(beforePose.rotation);
					m_DeltaFrame = frameCount;
					deltaPose = new Pose(position, rotation);
				}
			}
		}

