		private class ProviderMonitor<T> : ProviderMonitor where T : LocomotionProvider
		{
			private Dictionary<T, List<IXRInteractor>> m_ProviderInteractors;

			private static List<T> s_Providers;

			private static readonly UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<Dictionary<T, List<IXRInteractor>>> s_ProviderInteractorsPool = new UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<Dictionary<T, List<IXRInteractor>>>(() => new Dictionary<T, List<IXRInteractor>>());

			public event Action<PoseContainer> providerStepped;

			public static void InitializeProvidersList()
			{
				if (s_Providers != null)
				{
					return;
				}
				s_Providers = new List<T>();
				foreach (LocomotionProvider locomotionProvider in LocomotionProvider.locomotionProviders)
				{
					if (!(locomotionProvider == null) && locomotionProvider is T item)
					{
						s_Providers.Add(item);
					}
				}
				LocomotionProvider.locomotionProvidersChanged += OnLocomotionProvidersChanged;
				static void OnLocomotionProvidersChanged(LocomotionProvider provider)
				{
					if (provider is T item2)
					{
						s_Providers.Add(item2);
					}
					s_Providers.RemoveAll((T p) => p == null);
				}
			}

			public override void AddInteractor(IXRInteractor interactor)
			{
				if (interactor == null)
				{
					throw new ArgumentNullException("interactor");
				}
				Transform transform = interactor.transform;
				if (transform == null)
				{
					return;
				}
				if (s_Providers == null)
				{
					InitializeProvidersList();
				}
				foreach (T s_Provider in s_Providers)
				{
					if (!(s_Provider == null) && LocomotionUtility.TryGetOriginTransform(s_Provider, out var originTransform) && transform.IsChildOf(originTransform))
					{
						if (m_ProviderInteractors == null)
						{
							m_ProviderInteractors = s_ProviderInteractorsPool.Get();
						}
						if (!m_ProviderInteractors.TryGetValue(s_Provider, out var value))
						{
							value = new List<IXRInteractor>();
							m_ProviderInteractors.Add(s_Provider, value);
						}
						value.Add(interactor);
						if (value.Count == 1)
						{
							s_Provider.beforeStepLocomotion += OnBeforeStepLocomotion;
							s_Provider.afterStepLocomotion += OnAfterStepLocomotion;
						}
					}
				}
			}

			public override void RemoveInteractor(IXRInteractor interactor)
			{
				if (interactor == null)
				{
					throw new ArgumentNullException("interactor");
				}
				int num = 0;
				if (m_ProviderInteractors != null)
				{
					foreach (KeyValuePair<T, List<IXRInteractor>> providerInteractor in m_ProviderInteractors)
					{
						T key = providerInteractor.Key;
						List<IXRInteractor> value = providerInteractor.Value;
						if (!(key == null))
						{
							if (value.Remove(interactor) && value.Count == 0)
							{
								key.beforeStepLocomotion -= OnBeforeStepLocomotion;
								key.afterStepLocomotion -= OnAfterStepLocomotion;
							}
							num += value.Count;
						}
					}
				}
				if (num == 0 && m_ProviderInteractors != null)
				{
					s_ProviderInteractorsPool.Release(m_ProviderInteractors);
					m_ProviderInteractors = null;
				}
			}

			private static void CaptureOriginPoseBefore(XRBodyTransformer bodyTransformer)
			{
				if (ProviderMonitor.s_OriginPoses == null)
				{
					ProviderMonitor.s_OriginPoses = new Dictionary<XRBodyTransformer, PoseContainer>();
				}
				if (!ProviderMonitor.s_OriginPoses.TryGetValue(bodyTransformer, out var value))
				{
					value = new PoseContainer();
					ProviderMonitor.s_OriginPoses[bodyTransformer] = value;
				}
				value.CaptureBeforePose(bodyTransformer);
			}

			private static PoseContainer CaptureOriginPoseAfter(XRBodyTransformer bodyTransformer)
			{
				if (ProviderMonitor.s_OriginPoses == null)
				{
					ProviderMonitor.s_OriginPoses = new Dictionary<XRBodyTransformer, PoseContainer>();
				}
				if (!ProviderMonitor.s_OriginPoses.TryGetValue(bodyTransformer, out var value))
				{
					value = new PoseContainer();
					ProviderMonitor.s_OriginPoses[bodyTransformer] = value;
				}
				value.CaptureAfterPose(bodyTransformer);
				return value;
			}

			private static void OnBeforeStepLocomotion(LocomotionProvider provider)
			{
				if (!(provider.mediator == null))
				{
					CaptureOriginPoseBefore(provider.mediator.bodyTransformer);
				}
			}

			private void OnAfterStepLocomotion(LocomotionProvider provider)
			{
				if (!(provider.mediator == null))
				{
					PoseContainer obj = CaptureOriginPoseAfter(provider.mediator.bodyTransformer);
					this.providerStepped?.Invoke(obj);
				}
			}
		}

		private int m_TeleportedFrame = -1;

		private ProviderMonitor[] m_Monitors;

		public event Action<Pose, Pose, Pose> teleported;

		private void Initialize()
		{
			ProviderMonitor<TeleportationProvider> providerMonitor = new ProviderMonitor<TeleportationProvider>();
			providerMonitor.providerStepped += OnTeleportedAlways;
			ProviderMonitor<SnapTurnProvider> providerMonitor2 = new ProviderMonitor<SnapTurnProvider>();
			providerMonitor2.providerStepped += OnTeleportedAlways;
			ProviderMonitor<ContinuousTurnProvider> providerMonitor3 = new ProviderMonitor<ContinuousTurnProvider>();
			providerMonitor3.providerStepped += OnTeleportedTurnAround;
			ProviderMonitor<TeleportationProvider>.InitializeProvidersList();
			ProviderMonitor<SnapTurnProvider>.InitializeProvidersList();
			ProviderMonitor<ContinuousTurnProvider>.InitializeProvidersList();
			m_Monitors = new ProviderMonitor[3] { providerMonitor, providerMonitor2, providerMonitor3 };
		}

		public void AddInteractor(IXRInteractor interactor)
		{
			if (m_Monitors == null)
			{
				Initialize();
			}
			ProviderMonitor[] monitors = m_Monitors;
			for (int i = 0; i < monitors.Length; i++)
			{
				monitors[i].AddInteractor(interactor);
			}
		}

		public void RemoveInteractor(IXRInteractor interactor)
		{
			ProviderMonitor[] monitors = m_Monitors;
			for (int i = 0; i < monitors.Length; i++)
			{
				monitors[i].RemoveInteractor(interactor);
			}
		}

		private void OnTeleportedAlways(PoseContainer poseContainer)
		{
			int frameCount = Time.frameCount;
			if (m_TeleportedFrame != frameCount)
			{
				m_TeleportedFrame = frameCount;
				poseContainer.CalculateDeltaPose();
				this.teleported?.Invoke(poseContainer.beforePose, poseContainer.afterPose, poseContainer.deltaPose);
			}
		}

		private void OnTeleportedTurnAround(PoseContainer poseContainer)
		{
			int frameCount = Time.frameCount;
			if (m_TeleportedFrame != frameCount && !(Vector3.Dot(poseContainer.beforePose.forward, poseContainer.afterPose.forward) >= 0f))
			{
				m_TeleportedFrame = frameCount;
				poseContainer.CalculateDeltaPose();
				this.teleported?.Invoke(poseContainer.beforePose, poseContainer.afterPose, poseContainer.deltaPose);
			}
		}
	}
	internal class TriggerContactMonitor
	{
		private readonly Dictionary<Collider, IXRInteractable> m_EnteredColliders = new Dictionary<Collider, IXRInteractable>();

		private readonly HashSet<IXRInteractable> m_UnorderedInteractables = new HashSet<IXRInteractable>();

		private readonly HashSet<Collider> m_EnteredUnassociatedColliders = new HashSet<Collider>();

		private static readonly List<Collider> s_ScratchColliders = new List<Collider>();

		private static readonly List<Collider> s_ExitedColliders = new List<Collider>();

		public XRInteractionManager interactionManager { get; set; }

		public event Action<IXRInteractable> contactAdded;

		public event Action<IXRInteractable> contactRemoved;

		public void AddCollider(Collider collider)
		{
			if (interactionManager == null)
			{
				return;
			}
			if (!interactionManager.TryGetInteractableForCollider(collider, out var interactable))
			{
				m_EnteredUnassociatedColliders.Add(collider);
				return;
			}
			m_EnteredColliders[collider] = interactable;
			if (m_UnorderedInteractables.Add(interactable))
			{
				this.contactAdded?.Invoke(interactable);
			}
		}

		public void RemoveCollider(Collider collider)
		{
			if (m_EnteredUnassociatedColliders.Remove(collider) || !m_EnteredColliders.TryGetValue(collider, out var value))
			{
				return;
			}
			m_EnteredColliders.Remove(collider);
			if (value == null)
			{
				return;
			}
			foreach (KeyValuePair<Collider, IXRInteractable> enteredCollider in m_EnteredColliders)
			{
				if (enteredCollider.Value == value && enteredCollider.Key != null)
				{
					return;
				}
			}
			if (m_UnorderedInteractables.Remove(value))
			{
				this.contactRemoved?.Invoke(value);
			}
		}

		public void ResolveUnassociatedColliders()
		{
			m_EnteredUnassociatedColliders.RemoveWhere(IsDestroyed);
			if (m_EnteredUnassociatedColliders.Count == 0 || interactionManager == null)
			{
				return;
			}
			s_ScratchColliders.Clear();
			foreach (Collider enteredUnassociatedCollider in m_EnteredUnassociatedColliders)
			{
				if (interactionManager.TryGetInteractableForCollider(enteredUnassociatedCollider, out var interactable))
				{
					s_ScratchColliders.Add(enteredUnassociatedCollider);
					m_EnteredColliders[enteredUnassociatedCollider] = interactable;
					if (m_UnorderedInteractables.Add(interactable))
					{
						this.contactAdded?.Invoke(interactable);
					}
				}
			}
			s_ScratchColliders.ForEach(RemoveFromUnassociatedColliders);
			s_ScratchColliders.Clear();
		}

		private void RemoveFromUnassociatedColliders(Collider col)
		{
			m_EnteredUnassociatedColliders.Remove(col);
		}

		public void ResolveUnassociatedColliders(IXRInteractable interactable)
		{
			m_EnteredUnassociatedColliders.RemoveWhere(IsDestroyed);
			if (m_EnteredUnassociatedColliders.Count == 0 || interactionManager == null)
			{
				return;
			}
			int i = 0;
			for (int count = interactable.colliders.Count; i < count; i++)
			{
				Collider collider = interactable.colliders[i];
				if (!(collider == null) && m_EnteredUnassociatedColliders.Contains(collider) && interactionManager.TryGetInteractableForCollider(collider, out var interactable2) && interactable2 == interactable)
				{
					m_EnteredUnassociatedColliders.Remove(collider);
					m_EnteredColliders[collider] = interactable;
					if (m_UnorderedInteractables.Add(interactable))
					{
						this.contactAdded?.Invoke(interactable);
					}
				}
			}
		}

		public void UpdateStayedColliders(HashSet<Collider> stayedColliders)
		{
			s_ExitedColliders.Clear();
			if (m_EnteredColliders.Count > 0)
			{
				foreach (Collider key in m_EnteredColliders.Keys)
				{
					if (!stayedColliders.Contains(key))
					{
						s_ExitedColliders.Add(key);
					}
					else
					{
						stayedColliders.Remove(key);
					}
				}
			}
			if (stayedColliders.Count > 0)
			{
				foreach (Collider stayedCollider in stayedColliders)
				{
					AddCollider(stayedCollider);
				}
			}
			if (s_ExitedColliders.Count > 0)
			{
				s_ExitedColliders.ForEach(RemoveCollider);
				s_ExitedColliders.Clear();
			}
		}

		public bool IsContacting(IXRInteractable interactable)
		{
			return m_UnorderedInteractables.Contains(interactable);
		}

		private static bool IsDestroyed(Collider col)
		{
			return col == null;
		}
	}
	internal class UnityObjectReferenceCache<T> where T : Object
	{
		private T m_CapturedField;

		private T m_FieldOrNull;

		public bool TryGet(T field, out T fieldOrNull)
		{
			if ((object)m_CapturedField == field)
			{
				fieldOrNull = m_FieldOrNull;
				return (object)m_FieldOrNull != null;
			}
			m_CapturedField = field;
			if (field != null)
			{
				m_FieldOrNull = field;
				fieldOrNull = field;
				return true;
			}
			m_FieldOrNull = null;
			fieldOrNull = null;
			return false;
		}
	}
	internal class UnityObjectReferenceCache<TInterface, TObject> where TInterface : class where TObject : Object
	{
		private TObject m_CapturedObject;

		private TInterface m_Interface;

		public TInterface Get(TObject field)
		{
			if ((object)m_CapturedObject == field)
			{
				return m_Interface;
			}
			m_CapturedObject = field;
			m_Interface = field as TInterface;
			return m_Interface;
		}

		public void Set(ref TObject field, TInterface value)
		{
			field = value as TObject;
			m_CapturedObject = field;
			m_Interface = value;
		}
	}
	[AddComponentMenu("")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Utilities.XRDebugLineVisualizer.html")]
	internal class XRDebugLineVisualizer : MonoBehaviour
	{
		[Serializable]
		private class DebugLine
		{
			public string name;

			public Color color;

			public LineRenderer lineRenderer;

			public float decayTime;
		}

		private List<DebugLine> m_DebugLines = new List<DebugLine>();

		private void Update()
		{
			for (int num = m_DebugLines.Count - 1; num >= 0; num--)
			{
				m_DebugLines[num].decayTime -= Time.deltaTime;
				if (m_DebugLines[num].decayTime <= 0f)
				{
					Object.Destroy(m_DebugLines[num].lineRenderer.gameObject);
					m_DebugLines.RemoveAt(num);
				}
			}
		}

		private void OnDestroy()
		{
			ClearLines();
		}

		public void UpdateOrCreateLine(string lineName, Vector3 start, Vector3 end, Color color, float decayTime = 0.2f)
		{
			DebugLine debugLine = m_DebugLines.Find((DebugLine l) => l.name == lineName);
			if (debugLine == null)
			{
				GameObject obj = new GameObject(lineName + "Line");
				obj.transform.SetParent(base.transform, worldPositionStays: false);
				LineRenderer lineRenderer = obj.AddComponent<LineRenderer>();
				lineRenderer.startWidth = 0.01f;
				lineRenderer.endWidth = 0.01f;
				lineRenderer.material = new Material(Shader.Find("Sprites/Default"));
				lineRenderer.startColor = color;
				lineRenderer.endColor = color;
				debugLine = new DebugLine
				{
					name = lineName,
					color = color,
					lineRenderer = lineRenderer
				};
				m_DebugLines.Add(debugLine);
			}
			debugLine.lineRenderer.SetPosition(0, start);
			debugLine.lineRenderer.SetPosition(1, end);
			debugLine.decayTime = decayTime;
		}

		public void ClearLines()
		{
			foreach (DebugLine debugLine in m_DebugLines)
			{
				Object.Destroy(debugLine.lineRenderer.gameObject);
			}
			m_DebugLines.Clear();
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Utilities.Tweenables
