		protected override void OnEnable()
		{
			base.OnEnable();
			m_ActiveInputMode = ActiveInputMode.InputSystemActions;
			m_PointerState = new PointerModel(0);
			m_NavigationState = default(NavigationModel);
			m_UseBuiltInInputSystemActions = m_EnableBuiltinActionsAsFallback && !InputActionReferencesAreSet();
			if (m_ActiveInputMode != ActiveInputMode.InputManagerBindings)
			{
				EnableAllActions();
			}
		}

		protected override void OnDisable()
		{
			RemovePointerEventData(m_PointerState.pointerId);
			if (m_ActiveInputMode != ActiveInputMode.InputManagerBindings)
			{
				DisableAllActions();
			}
			base.OnDisable();
		}

		public void RegisterInteractor(IUIInteractor interactor)
		{
			if (interactor == null)
			{
				return;
			}
			for (int i = 0; i < m_RegisteredInteractors.Count; i++)
			{
				RegisteredInteractor value = m_RegisteredInteractors[i];
				if (value.interactor == interactor)
				{
					if (!value.active)
					{
						value.active = true;
						value.deactivating = false;
						value.model.Reset();
						m_RegisteredInteractors[i] = value;
					}
					return;
				}
			}
			if (!m_DeletedPointerIds.TryPop(out var result))
			{
				result = m_RollingPointerId++;
			}
			m_RegisteredInteractors.Add(new RegisteredInteractor(interactor, result));
		}

		public void UnregisterInteractor(IUIInteractor interactor)
		{
			if (interactor == null)
			{
				return;
			}
			for (int i = 0; i < m_RegisteredInteractors.Count; i++)
			{
				RegisteredInteractor value = m_RegisteredInteractors[i];
				if (value.interactor == interactor)
				{
					if (value.active)
					{
						value.deactivating = true;
						value.active = false;
						m_RegisteredInteractors[i] = value;
					}
					break;
				}
			}
		}

		public IUIInteractor GetInteractor(int pointerId)
		{
			for (int i = 0; i < m_RegisteredInteractors.Count; i++)
			{
				if (m_RegisteredInteractors[i].model.pointerId == pointerId && m_RegisteredInteractors[i].active)
				{
					return m_RegisteredInteractors[i].interactor;
				}
			}
			return null;
		}

		public bool GetTrackedDeviceModel(IUIInteractor interactor, out TrackedDeviceModel model)
		{
			for (int i = 0; i < m_RegisteredInteractors.Count; i++)
			{
				if (m_RegisteredInteractors[i].interactor == interactor)
				{
					model = m_RegisteredInteractors[i].model;
					return true;
				}
			}
			model = new TrackedDeviceModel(-1);
			return false;
		}

		protected override void DoProcess()
		{
			if (m_EnableXRInput)
			{
				for (int i = 0; i < m_RegisteredInteractors.Count; i++)
				{
					RegisteredInteractor value = m_RegisteredInteractors[i];
					GameObject pointerTarget = value.model.implementationData.pointerTarget;
					bool flag = value.interactor is Object obj && obj == null;
					if (flag || value.deactivating)
					{
						value.model.Reset(resetImplementation: false);
						ProcessTrackedDevice(ref value.model, force: true);
						RemovePointerEventData(value.model.pointerId);
						if (flag)
						{
							m_DeletedPointerIds.Push(value.model.pointerId);
							m_RegisteredInteractors.RemoveAt(i--);
							continue;
						}
						value.deactivating = false;
						value.model.Reset();
						m_RegisteredInteractors[i] = value;
					}
					else
					{
						if (!value.active)
						{
							continue;
						}
						value.interactor.UpdateUIModel(ref value.model);
						ProcessTrackedDevice(ref value.model);
						value.model.UpdatePokeSelectState();
						m_RegisteredInteractors[i] = value;
					}
					GameObject pointerTarget2 = value.model.implementationData.pointerTarget;
					if (pointerTarget != pointerTarget2)
					{
						UIHoverEventArgs v;
						using (m_UIHoverEventArgs.Get(out v))
						{
							v.interactorObject = value.interactor;
							v.deviceModel = value.model;
							if (v.interactorObject != null && v.interactorObject is IUIHoverInteractor iUIHoverInteractor)
							{
								if (pointerTarget != null)
								{
									v.uiObject = pointerTarget;
									iUIHoverInteractor.OnUIHoverExited(v);
								}
								if (pointerTarget2 != null && pointerTarget2.activeInHierarchy)
								{
									v.uiObject = pointerTarget2;
									iUIHoverInteractor.OnUIHoverEntered(v);
								}
							}
						}
					}
					if ((!(pointerTarget != null) || pointerTarget.activeInHierarchy) && ((object)pointerTarget == null || !(pointerTarget == null)))
					{
						continue;
					}
					UIHoverEventArgs v2;
					using (m_UIHoverEventArgs.Get(out v2))
					{
						if (pointerTarget == pointerTarget2)
						{
							value.model.Reset();
							m_RegisteredInteractors[i] = value;
						}
						IUIInteractor interactor = value.interactor;
						if (interactor != null && interactor is IUIHoverInteractor iUIHoverInteractor2)
						{
							v2.interactorObject = interactor;
							v2.uiObject = pointerTarget;
							v2.deviceModel = value.model;
							iUIHoverInteractor2.OnUIHoverExited(v2);
						}
					}
				}
			}
			if (m_ActiveInputMode != ActiveInputMode.InputManagerBindings)
			{
				GetPointerStates();
			}
			ProcessPointerState(ref m_PointerState);
			ProcessNavigationState(ref m_NavigationState);
		}

		private void GetPointerStates()
		{
			if (m_UseBuiltInInputSystemActions)
			{
				if (m_EnableTouchInput && Touchscreen.current != null)
				{
					m_PointerState.position = Touchscreen.current.position.ReadValue();
					m_PointerState.displayIndex = Touchscreen.current.displayIndex.ReadValue();
				}
				if (m_EnableMouseInput && Mouse.current != null)
				{
					m_PointerState.position = Mouse.current.position.ReadValue();
					m_PointerState.displayIndex = Mouse.current.displayIndex.ReadValue();
					m_PointerState.scrollDelta = Mouse.current.scroll.ReadValue() * 0.05f;
					m_PointerState.leftButtonPressed = Mouse.current.leftButton.isPressed;
					m_PointerState.rightButtonPressed = Mouse.current.rightButton.isPressed;
					m_PointerState.middleButtonPressed = Mouse.current.middleButton.isPressed;
				}
				if (m_EnableGamepadInput && Gamepad.current != null)
				{
					m_NavigationState.move = Gamepad.current.leftStick.ReadValue() + Gamepad.current.dpad.ReadValue();
					m_NavigationState.submitButtonDown = Gamepad.current.buttonSouth.isPressed;
					m_NavigationState.cancelButtonDown = Gamepad.current.buttonEast.isPressed;
				}
				if (m_EnableJoystickInput && Joystick.current != null)
				{
					m_NavigationState.move = Joystick.current.stick.ReadValue() + ((Joystick.current.hatswitch != null) ? Joystick.current.hatswitch.ReadValue() : Vector2.zero);
					m_NavigationState.submitButtonDown = Joystick.current.trigger.isPressed;
					m_NavigationState.cancelButtonDown = false;
				}
				return;
			}
			if (IsActionEnabled(m_PointAction))
			{
				m_PointerState.position = m_PointAction.action.ReadValue<Vector2>();
				m_PointerState.displayIndex = GetDisplayIndexFor(m_PointAction.action.activeControl);
			}
			if (IsActionEnabled(m_ScrollWheelAction))
			{
				m_PointerState.scrollDelta = m_ScrollWheelAction.action.ReadValue<Vector2>() * 0.05f;
			}
			if (IsActionEnabled(m_LeftClickAction))
			{
				m_PointerState.leftButtonPressed = m_LeftClickAction.action.IsPressed();
			}
			if (IsActionEnabled(m_RightClickAction))
			{
				m_PointerState.rightButtonPressed = m_RightClickAction.action.IsPressed();
			}
			if (IsActionEnabled(m_MiddleClickAction))
			{
				m_PointerState.middleButtonPressed = m_MiddleClickAction.action.IsPressed();
			}
			if (IsActionEnabled(m_NavigateAction))
			{
				m_NavigationState.move = m_NavigateAction.action.ReadValue<Vector2>();
			}
			if (IsActionEnabled(m_SubmitAction))
			{
				m_NavigationState.submitButtonDown = m_SubmitAction.action.WasPerformedThisFrame();
			}
			if (IsActionEnabled(m_CancelAction))
			{
				m_NavigationState.cancelButtonDown = m_CancelAction.action.WasPerformedThisFrame();
			}
		}

		private bool InputActionReferencesAreSet()
		{
			if (!(m_PointAction != null) && !(m_LeftClickAction != null) && !(m_RightClickAction != null) && !(m_MiddleClickAction != null) && !(m_NavigateAction != null) && !(m_SubmitAction != null) && !(m_CancelAction != null))
			{
				return m_ScrollWheelAction != null;
			}
			return true;
		}

		private void EnableAllActions()
		{
			EnableInputAction(m_PointAction);
			EnableInputAction(m_LeftClickAction);
			EnableInputAction(m_RightClickAction);
			EnableInputAction(m_MiddleClickAction);
			EnableInputAction(m_NavigateAction);
			EnableInputAction(m_SubmitAction);
			EnableInputAction(m_CancelAction);
			EnableInputAction(m_ScrollWheelAction);
		}

		private void DisableAllActions()
		{
			DisableInputAction(m_PointAction);
			DisableInputAction(m_LeftClickAction);
			DisableInputAction(m_RightClickAction);
			DisableInputAction(m_MiddleClickAction);
			DisableInputAction(m_NavigateAction);
			DisableInputAction(m_SubmitAction);
			DisableInputAction(m_CancelAction);
			DisableInputAction(m_ScrollWheelAction);
		}

		private static bool IsActionEnabled(InputActionReference inputAction)
		{
			if (inputAction != null && inputAction.action != null)
			{
				return inputAction.action.enabled;
			}
			return false;
		}

		private static void EnableInputAction(InputActionReference inputAction)
		{
			if (!(inputAction == null) && inputAction.action != null)
			{
				inputAction.action.Enable();
			}
		}

		private static void DisableInputAction(InputActionReference inputAction)
		{
			if (!(inputAction == null) && inputAction.action != null)
			{
				inputAction.action.Disable();
			}
		}

		private void SetInputAction(ref InputActionReference inputAction, InputActionReference value)
		{
			if (Application.isPlaying && inputAction != null)
			{
				inputAction.action?.Disable();
			}
			inputAction = value;
			if (Application.isPlaying && base.isActiveAndEnabled && inputAction != null)
			{
				inputAction.action?.Enable();
			}
		}

		private int GetDisplayIndexFor(InputControl control)
		{
			int result = 0;
			if (control != null && control.device is UnityEngine.InputSystem.Pointer pointer && pointer != null)
			{
				result = pointer.displayIndex.ReadValue();
			}
			return result;
		}
	}
	internal struct PointerHitData
	{
		public Vector3 worldPosition;

		public Quaternion worldOrientation;

		public float hitDistance;

		public Collider hitCollider;

		public UIDocument hitDocument;

		public VisualElement hitElement;
	}
	internal struct InteractorHitData
	{
		public Vector3 closestPoint;

		public Vector3 interactorOrigin;

		public Vector3 interactorDirection;

		public UIDocument hitDocument;
	}
	internal static class XRUIToolkitHandler
	{
		private class InteractorInfo
		{
			public IXRInteractor interactor;

			public int index;
		}

		private const int k_MaxInteractors = 8;

		private const int k_InvalidIndex = -1;

		private static readonly Vector3 k_ResetPos = new Vector3(0f, -1000f, 0f);

		private static readonly Dictionary<IXRInteractor, InteractorInfo> s_RegisteredInteractors = new Dictionary<IXRInteractor, InteractorInfo>();

		private static readonly Dictionary<IXRInteractor, InteractorHitData> s_InteractorHitData = new Dictionary<IXRInteractor, InteractorHitData>();

		private static readonly bool[] s_UsedIndices = new bool[8];

		private static readonly Dictionary<int, bool> s_LastWasDown = new Dictionary<int, bool>();

		private static readonly Dictionary<int, bool> s_WasReset = new Dictionary<int, bool>();

		private static PanelInputConfiguration s_PanelInputConfigurationRef;

		private static bool s_EventSystemValidated;

		private static bool s_PanelInputConfigurationValidated;

		private static bool s_DidCheckPanelInputConfiguration;

		private static readonly Dictionary<IXRInteractor, VisualElement> s_InteractorElements = new Dictionary<IXRInteractor, VisualElement>();

		private static readonly Dictionary<uint, float> s_InitialZDepth = new Dictionary<uint, float>();

		public static bool uiToolkitSupportEnabled { get; set; }

		public static int count => s_RegisteredInteractors.Count;

		public static int Register(IXRInteractor interactor)
		{
			if (s_RegisteredInteractors.TryGetValue(interactor, out var value))
			{
				Debug.LogWarning($"interactor {interactor} is already registered with XR UI Toolkit Handler.");
				return value.index;
			}
			int num = -1;
			for (int i = 0; i < 8; i++)
			{
				if (!s_UsedIndices[i])
				{
					num = i;
					s_UsedIndices[i] = true;
					break;
				}
			}
			if (num == -1)
			{
				Debug.LogError("No available indices for pointer registration.");
				return -1;
			}
			InteractorInfo value2 = new InteractorInfo
			{
				interactor = interactor,
				index = num
			};
			s_RegisteredInteractors.Add(interactor, value2);
			return num;
		}

		public static void Unregister(IXRInteractor interactor)
		{
			if (s_RegisteredInteractors.TryGetValue(interactor, out var value))
			{
				s_LastWasDown.Remove(value.index);
				s_WasReset.Remove(value.index);
				s_UsedIndices[value.index] = false;
				s_RegisteredInteractors.Remove(interactor);
				s_InteractorHitData.Remove(interactor);
				ClearZDepthForInteractor(interactor);
			}
		}

		public static bool TryGetPointerIndex(IXRInteractor interactor, out int index)
		{
			if (s_RegisteredInteractors.TryGetValue(interactor, out var value))
			{
				index = value.index;
				return true;
			}
			index = -1;
			return false;
		}

		public static void UpdateInteractorHitData(IXRInteractor interactor, InteractorHitData hitData)
		{
			s_InteractorHitData[interactor] = hitData;
		}

		public static bool TryGetInteractorHitData(IXRInteractor interactor, out InteractorHitData hitData)
		{
			return s_InteractorHitData.TryGetValue(interactor, out hitData);
		}

		public static void ClearInteractorHitData(IXRInteractor interactor)
		{
			ClearZDepthForInteractor(interactor);
			s_InteractorHitData.Remove(interactor);
		}

		public static void Clear()
		{
			s_RegisteredInteractors.Clear();
			s_LastWasDown.Clear();
			s_WasReset.Clear();
			s_InteractorHitData.Clear();
			s_InteractorElements.Clear();
			for (int i = 0; i < 8; i++)
			{
				s_UsedIndices[i] = false;
			}
		}

		public static bool IsRegistered(IXRInteractor interactor)
		{
			return s_RegisteredInteractors.ContainsKey(interactor);
		}

		public static void HandlePointerUpdate(IXRInteractor interactor, Vector3 pos, Quaternion rot, bool isUiSelectInputActive, bool shouldReset)
		{
			if (!TryGetPointerIndex(interactor, out var index))
			{
				return;
			}
			s_LastWasDown.TryAdd(index, value: false);
			s_WasReset.TryAdd(index, shouldReset);
			if (!shouldReset || !s_WasReset[index])
			{
				if (ShouldCheckPanelInputConfigurationValidation())
				{
					ValidatePanelInputConfiguration();
				}
				Vector3 worldPosition = (shouldReset ? k_ResetPos : pos);
				Quaternion worldOrientation = (shouldReset ? Quaternion.identity : rot);
				EventProvider.Dispatch(Event.From(new PointerEvent
				{
					pointerIndex = index,
					type = PointerEvent.Type.PointerMoved,
					worldPosition = worldPosition,
					worldOrientation = worldOrientation,
					eventSource = EventSource.TrackedDevice,
					maxDistance = 10f
				}));
				bool flag = !shouldReset && isUiSelectInputActive;
				if (flag != s_LastWasDown[index])
				{
					s_LastWasDown[index] = flag;
					PointerEvent.Type type = (flag ? PointerEvent.Type.ButtonPressed : PointerEvent.Type.ButtonReleased);
					EventProvider.Dispatch(Event.From(new PointerEvent
					{
						pointerIndex = index,
						type = type,
						button = PointerEvent.Button.Primary,
						clickCount = 1,
						worldPosition = worldPosition,
						worldOrientation = worldOrientation,
						eventSource = EventSource.TrackedDevice,
						maxDistance = 10f
					}));
				}
				s_WasReset[index] = shouldReset;
				if (shouldReset)
				{
					ClearInteractorHitData(interactor);
				}
			}
		}

		public static bool TryGetPointerHitData(IXRInteractor interactor, out PointerHitData hitData)
		{
			hitData = default(PointerHitData);
			if (!TryGetPointerIndex(interactor, out var index))
			{
				return false;
			}
			PointerDeviceState.TrackedPointerState trackedState = PointerDeviceState.GetTrackedState(PointerId.trackedPointerIdBase + index);
			if (trackedState == null)
			{
				return false;
			}
			hitData = new PointerHitData
			{
				worldPosition = trackedState.worldPosition,
				worldOrientation = trackedState.worldOrientation,
				hitDistance = trackedState.hit.distance,
				hitCollider = trackedState.hit.collider,
				hitDocument = trackedState.hit.document,
				hitElement = trackedState.hit.element
			};
			return true;
		}

		public static float SetZDepthForInteractor(VisualElement ve, IXRInteractor interactor, float z)
		{
			s_InteractorElements[interactor] = ve;
			Translate value = ve.style.translate.value;
			if (!s_InitialZDepth.TryAdd(ve.controlid, value.z))
			{
				s_InitialZDepth[ve.controlid] = value.z;
			}
			ve.style.translate = new Translate(value.x.value, value.y.value, z);
			return z;
		}

		private static float ResetDepth(VisualElement ve)
		{
			Translate value = ve.style.translate.value;
			if (s_InitialZDepth.TryGetValue(ve.controlid, out var value2))
			{
				ve.style.translate = new Translate(value.x.value, value.y.value, value2);
			}
			else
			{
				ve.style.translate = new Translate(value.x.value, value.y.value, 0f);
			}
			return value2;
		}

		public static void ClearZDepthForInteractor(IXRInteractor interactor)
		{
			if (s_InteractorElements.TryGetValue(interactor, out var value) && value != null)
			{
				ResetDepth(value);
				s_InteractorElements.Remove(interactor);
			}
		}

		public static void UpdateEventSystem()
		{
			if (count > 0)
			{
				UIElementsRuntimeUtility.UpdateEventSystem();
			}
		}

		public static bool IsValidUIToolkitInteraction(List<Collider> colliders)
		{
			if (colliders.Count > 0)
			{
				return HasUIDocument(colliders[0]);
			}
			return false;
		}

		public static bool HasUIDocument(Collider collider)
		{
			UIDocument component;
			return collider.TryGetComponent<UIDocument>(out component);
		}

		private static bool ShouldCheckPanelInputConfigurationValidation()
		{
			if (s_PanelInputConfigurationRef != PanelInputConfiguration.current)
			{
				s_EventSystemValidated = false;
				s_PanelInputConfigurationValidated = false;
				s_DidCheckPanelInputConfiguration = false;
				return true;
			}
			return !s_DidCheckPanelInputConfiguration && (!s_EventSystemValidated || !s_PanelInputConfigurationValidated);
		}

		private static void ValidatePanelInputConfiguration()
		{
			s_DidCheckPanelInputConfiguration = true;
			s_PanelInputConfigurationValidated = false;
			if (s_EventSystemValidated || !(EventSystem.current == null))
			{
				s_EventSystemValidated = true;
				PanelInputConfiguration panelInputConfiguration = (s_PanelInputConfigurationRef = PanelInputConfiguration.current);
				if (panelInputConfiguration == null)
				{
					Debug.LogWarning("Detected an Event System component that could interfere with UI Toolkit input. Create a Panel Input Configuration component and configured it by setting Panel Input Redirection to No input redirection to prevent interactions with the Event System.");
				}
				else if (panelInputConfiguration.panelInputRedirection != PanelInputConfiguration.PanelInputRedirection.Never)
				{
					Debug.LogWarning("Detected an Event System component that could interfere with UI Toolkit input. Configure your Panel Input Configuration component to set Panel Input Redirection to No input redirection to prevent interactions with the Event System.");
				}
				else
				{
					s_PanelInputConfigurationValidated = true;
				}
			}
		}
	}
	[AddComponentMenu("XR/XR UI Toolkit Manager", 11)]
	[DisallowMultipleComponent]
	[DefaultExecutionOrder(-200)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.UI.XRUIToolkitManager.html")]
	public class XRUIToolkitManager : MonoBehaviour
	{
		protected void OnEnable()
		{
			XRUIToolkitHandler.uiToolkitSupportEnabled = true;
		}

		protected void OnDisable()
		{
			XRUIToolkitHandler.uiToolkitSupportEnabled = false;
		}
	}
	internal class XRUIToolkitPokeHandler
	{
		private GameObject m_VisualizersRoot;

		private Transform m_PokePointVisualizer;

		private Transform m_ClosestPointVisualizer;

		private Transform m_RayOriginVisualizer;

		private Transform m_NormalVisualizer;

		private bool m_VisualizersCreated;

		private readonly XRPokeInteractor m_Interactor;

		private bool m_UpdateDepth;

		public bool updateDepth
		{
			get
			{
				return m_UpdateDepth;
			}
			set
			{
				m_UpdateDepth = value;
			}
		}

		public XRUIToolkitPokeHandler(XRPokeInteractor interactor)
		{
			m_Interactor = interactor;
		}

		public void Dispose()
		{
			DestroyVisualizers();
		}

		public void ProcessPokeInteraction(Collider hitCollider, Transform interactableTransform, IXRInteractable interactable, bool useMultiPick, IXRPokeFilter pokeFilter = null)
		{
			if (!interactableTransform.TryGetComponent<UIDocument>(out var component))
			{
				return;
			}
			Transform transform = component.transform;
			Vector3 position = m_Interactor.GetAttachTransform(null).position;
			Vector3 vector = -transform.forward;
			new Plane(vector, transform.position).Raycast(new Ray(position, -vector), out var enter);
			Vector3 vector2 = position - vector * enter;
			Vector3 vector3 = vector2 + vector;
			UpdateVisualizers(position, vector2, vector3, vector, transform);
			VisualElement visualElement = PerformPick(component, vector3, -vector, m_Interactor.pokeWidth, useMultiPick);
			if (visualElement != null)
			{
				XRUIToolkitHandler.UpdateInteractorHitData(m_Interactor, new InteractorHitData
				{
					closestPoint = vector2,
					interactorOrigin = position,
					interactorDirection = vector,
					hitDocument = component
				});
				float num = 1f;
				if (pokeFilter != null && interactable is IXRSelectInteractable interactable2)
				{
					num = pokeFilter.Process(m_Interactor, interactable2, 0f);
				}
				bool isUiSelectInputActive = num > 0.99f;
				if (m_UpdateDepth)
				{
					XRUIToolkitHandler.SetZDepthForInteractor(visualElement, m_Interactor, 20f * (1f - num));
				}
				XRUIToolkitHandler.HandlePointerUpdate(m_Interactor, vector3, Quaternion.LookRotation((vector2 - vector3).normalized), isUiSelectInputActive, shouldReset: false);
			}
			else
			{
				ResetPointerState();
			}
		}

		public void ResetPointerState()
		{
			XRUIToolkitHandler.HandlePointerUpdate(m_Interactor, Vector3.zero, Quaternion.identity, isUiSelectInputActive: false, shouldReset: true);
			if (m_UpdateDepth)
			{
				XRUIToolkitHandler.ClearZDepthForInteractor(m_Interactor);
			}
		}

		private VisualElement PerformPick(UIDocument document, Vector3 center, Vector3 direction, float radius, bool useMultiPick)
		{
			VisualElement visualElement = WorldSpaceInput.Pick3D(document, new Ray(center, direction));
			if (visualElement != null)
			{
				return visualElement;
			}
			if (useMultiPick)
			{
				return PerformMultiPick(document, center, direction, radius);
			}
			return null;
		}

		private VisualElement PerformMultiPick(UIDocument document, Vector3 center, Vector3 direction, float radius)
		{
			Dictionary<VisualElement, float> dictionary = new Dictionary<VisualElement, float>();
			Matrix4x4 localToWorldMatrix = document.transform.localToWorldMatrix;
			Vector3 vector = localToWorldMatrix.GetColumn(0);
			Vector3 vector2 = localToWorldMatrix.GetColumn(1);
			for (int i = 0; i < 4; i++)
			{
				float f = (float)i * (MathF.PI / 2f);
				Vector3 vector3 = vector * (Mathf.Cos(f) * radius) + vector2 * (Mathf.Sin(f) * radius);
				Vector3 origin = center + vector3;
				VisualElement visualElement = WorldSpaceInput.Pick3D(document, new Ray(origin, direction));
				if (visualElement != null)
				{
					float sqrMagnitude = vector3.sqrMagnitude;
					if (!dictionary.TryGetValue(visualElement, out var value) || sqrMagnitude < value)
					{
						dictionary[visualElement] = sqrMagnitude;
					}
				}
			}
			VisualElement result = null;
			float num = float.MaxValue;
			foreach (KeyValuePair<VisualElement, float> item in dictionary)
			{
				if (item.Value < num)
				{
					num = item.Value;
					result = item.Key;
				}
			}
			return result;
		}

		public void UpdateVisualizersState()
		{
			if (m_Interactor.debugVisualizationsEnabled && m_Interactor.isActiveAndEnabled)
			{
				CreateVisualizers();
			}
			else
			{
				DestroyVisualizers();
			}
		}

		private void UpdateVisualizers(Vector3 pokePoint, Vector3 closestPoint, Vector3 rayOrigin, Vector3 normal, Transform parentTransform)
		{
			if (m_Interactor.debugVisualizationsEnabled && m_VisualizersCreated)
			{
				m_PokePointVisualizer.position = pokePoint;
				m_ClosestPointVisualizer.position = closestPoint;
				m_RayOriginVisualizer.position = rayOrigin;
				m_NormalVisualizer.position = closestPoint + normal * 0.025f;
				m_NormalVisualizer.up = normal;
				if (m_VisualizersRoot.transform.parent != parentTransform)
				{
					m_VisualizersRoot.transform.SetParent(parentTransform, worldPositionStays: false);
				}
			}
		}

		private void CreateVisualizers()
		{
			if (!m_VisualizersCreated)
			{
				m_VisualizersRoot = new GameObject("UIPokeVisualizers");
				GameObject gameObject = GameObject.CreatePrimitive(PrimitiveType.Sphere);
				gameObject.name = "PokePoint";
				gameObject.transform.SetParent(m_VisualizersRoot.transform);
				gameObject.transform.localScale = new Vector3(0.01f, 0.01f, 0.01f);
				if (gameObject.TryGetComponent<Collider>(out var component))
				{
					Object.Destroy(component);
				}
				gameObject.GetComponent<Renderer>().material.color = Color.blue;
				m_PokePointVisualizer = gameObject.transform;
				GameObject gameObject2 = GameObject.CreatePrimitive(PrimitiveType.Sphere);
				gameObject2.name = "ClosestPoint";
				gameObject2.transform.SetParent(m_VisualizersRoot.transform);
				gameObject2.transform.localScale = new Vector3(0.01f, 0.01f, 0.01f);
				if (gameObject2.TryGetComponent<Collider>(out var component2))
				{
					Object.Destroy(component2);
				}
				gameObject2.GetComponent<Renderer>().material.color = Color.green;
				m_ClosestPointVisualizer = gameObject2.transform;
				GameObject gameObject3 = GameObject.CreatePrimitive(PrimitiveType.Sphere);
				gameObject3.name = "RayOrigin";
				gameObject3.transform.SetParent(m_VisualizersRoot.transform);
				gameObject3.transform.localScale = new Vector3(0.01f, 0.01f, 0.01f);
				if (gameObject3.TryGetComponent<Collider>(out var component3))
				{
					Object.Destroy(component3);
				}
				gameObject3.GetComponent<Renderer>().material.color = Color.yellow;
				m_RayOriginVisualizer = gameObject3.transform;
				GameObject gameObject4 = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
				gameObject4.name = "DocumentNormal";
				gameObject4.transform.SetParent(m_VisualizersRoot.transform);
				gameObject4.transform.localScale = new Vector3(0.005f, 0.05f, 0.005f);
				if (gameObject4.TryGetComponent<Collider>(out var component4))
				{
					Object.Destroy(component4);
				}
				gameObject4.GetComponent<Renderer>().material.color = Color.red;
				m_NormalVisualizer = gameObject4.transform;
				m_VisualizersCreated = true;
			}
		}

		private void DestroyVisualizers()
		{
			if (m_VisualizersRoot != null)
			{
				Object.Destroy(m_VisualizersRoot);
				m_VisualizersCreated = false;
				m_PokePointVisualizer = null;
				m_ClosestPointVisualizer = null;
				m_RayOriginVisualizer = null;
				m_NormalVisualizer = null;
			}
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.UI.BodyUI
{
	public enum FollowReferenceAxis
	{
		Right,
		Up,
		Forward,
		Left,
		Down,
		Back
	}
	[Serializable]
	public class FollowPreset
	{
		[Header("Local Space Anchor Transform")]
		[Tooltip("Local space anchor position for the right hand.")]
		public Vector3 rightHandLocalPosition;

		[Tooltip("Local space anchor position for the left hand.")]
		public Vector3 leftHandLocalPosition;

		[Tooltip("Local space anchor rotation for the right hand.")]
		public Vector3 rightHandLocalRotation;

		[Tooltip("Local space anchor rotation for the left hand.")]
		public Vector3 leftHandLocalRotation;

		[Header("Hand anchor angle constraints")]
		[Tooltip("Reference axis equivalent used for comparisons with the user's gaze direction and the world up direction.")]
		public FollowReferenceAxis palmReferenceAxis = FollowReferenceAxis.Down;

		[Tooltip("Given that the default reference hand for menus is the left hand, it may be required to mirror the reference axis for the right hand.")]
		public bool invertAxisForRightHand;

		[Tooltip("Whether or not check if the palm reference axis is facing the user.")]
		public bool requirePalmFacingUser;

		[Tooltip("The angle threshold in degrees to check if the palm reference axis is facing the user.")]
		public float palmFacingUserDegreeAngleThreshold;

		private float m_PalmFacingUserDotThreshold;

		[Tooltip("Whether or not check if the palm reference axis is facing up.")]
		public bool requirePalmFacingUp;

		[Tooltip("The angle threshold in degrees to check if the palm reference axis is facing up.")]
		public float palmFacingUpDegreeAngleThreshold;

		private float m_PalmFacingUpDotThreshold;

		[Header("Snap To gaze config")]
		[Tooltip("Whether to snap the following element to the gaze direction.")]
		public bool snapToGaze;

		[Tooltip("The angle threshold in degrees to snap the following element to the gaze direction.")]
		public float snapToGazeAngleThreshold;

		private float m_SnapToGazeDotThreshold;

		[Header("Hide delay config")]
		[Tooltip("The amount of time in seconds to wait before hiding the following element after the hand is no longer tracked.")]
		public float hideDelaySeconds = 0.25f;

		[Header("Smoothing Config")]
		[Tooltip("Whether to allow smoothing of the following element position and rotation.")]
		public bool allowSmoothing = true;

		[Tooltip("The lower bound of smoothing to apply.")]
		public float followLowerSmoothingValue = 10f;

		[Tooltip("The upper bound of smoothing to apply.")]
		public float followUpperSmoothingValue = 16f;

		public float palmFacingUserDotThreshold => m_PalmFacingUserDotThreshold;

		public float palmFacingUpDotThreshold => m_PalmFacingUpDotThreshold;

		public float snapToGazeDotThreshold => m_SnapToGazeDotThreshold;

		public void ApplyPreset(Transform leftTrackingOffset, Transform rightTrackingOffset)
		{
			leftTrackingOffset.SetLocalPose(new Pose(leftHandLocalPosition, Quaternion.Euler(leftHandLocalRotation)));
			rightTrackingOffset.SetLocalPose(new Pose(rightHandLocalPosition, Quaternion.Euler(rightHandLocalRotation)));
			ComputeDotProductThresholds();
		}

		public void ComputeDotProductThresholds()
		{
			m_PalmFacingUserDotThreshold = AngleToDot(palmFacingUserDegreeAngleThreshold);
			m_PalmFacingUpDotThreshold = AngleToDot(palmFacingUpDegreeAngleThreshold);
			m_SnapToGazeDotThreshold = AngleToDot(snapToGazeAngleThreshold);
		}

		private static float AngleToDot(float angleDeg)
		{
			return Mathf.Cos(MathF.PI / 180f * angleDeg);
		}

		public Vector3 GetReferenceAxisForTrackingAnchor(Transform trackingRoot, bool isRightHand)
		{
			return trackingRoot.TransformDirection(GetLocalAxis(isRightHand));
		}

		private Vector3 GetLocalAxis(bool isRightHand)
		{
			Vector3 result = Vector3.zero;
			bool flag = isRightHand && invertAxisForRightHand;
			switch (palmReferenceAxis)
			{
			case FollowReferenceAxis.Right:
				result = (flag ? Vector3.left : Vector3.right);
				break;
			case FollowReferenceAxis.Up:
				result = (flag ? Vector3.down : Vector3.up);
				break;
			case FollowReferenceAxis.Forward:
				result = (flag ? Vector3.back : Vector3.forward);
				break;
			case FollowReferenceAxis.Left:
				result = (flag ? Vector3.right : Vector3.left);
				break;
			case FollowReferenceAxis.Down:
				result = (flag ? Vector3.up : Vector3.down);
				break;
			case FollowReferenceAxis.Back:
				result = (flag ? Vector3.forward : Vector3.back);
				break;
			}
			return result;
		}
	}
	[Serializable]
	public class FollowPresetDatumProperty : DatumProperty<FollowPreset, FollowPresetDatum>
	{
		public FollowPresetDatumProperty(FollowPreset value)
			: base(value)
		{
		}

		public FollowPresetDatumProperty(FollowPresetDatum datum)
			: base(datum)
		{
		}
	}
