		protected void Awake()
		{
			m_HandAnchorSmartFollow.minDistanceAllowed = m_MinFollowDistance;
			m_HandAnchorSmartFollow.maxDistanceAllowed = m_MaxFollowDistance;
			m_HandAnchorSmartFollow.minToMaxDelaySeconds = m_MinToMaxDelaySeconds;
			m_RightOffsetRoot = new GameObject("Right Offset Root").transform;
			m_RightOffsetRoot.transform.SetParent(m_RightPalmAnchor);
			m_LeftOffsetRoot = new GameObject("Left Offset Root").transform;
			m_LeftOffsetRoot.transform.SetParent(m_LeftPalmAnchor);
		}

		protected void OnEnable()
		{
			if (m_LeftPalmAnchor == null || m_RightPalmAnchor == null)
			{
				Debug.LogError($"Missing palm anchor transform reference. Disabling {this} component.", this);
				base.enabled = false;
				return;
			}
			if (m_HandMenuUIGameObject == null)
			{
				Debug.LogError($"Missing Hand Menu UI GameObject reference. Disabling {this} component.", this);
				base.enabled = false;
				return;
			}
			if (m_ControllerFollowPreset == null || m_HandTrackingFollowPreset == null)
			{
				Debug.LogError($"Missing Follow Preset reference. Disabling {this} component.", this);
				base.enabled = false;
				return;
			}
			m_HandAnchorSmartFollow.Value = m_HandMenuUIGameObject.transform.position;
			m_BindingsGroup.AddBinding(m_HandAnchorSmartFollow.Subscribe(delegate(float3 newPosition)
			{
				m_HandMenuUIGameObject.transform.position = newPosition;
			}));
			m_RotTweenFollow.Value = m_HandMenuUIGameObject.transform.rotation;
			m_BindingsGroup.AddBinding(m_RotTweenFollow.Subscribe(delegate(Quaternion newRot)
			{
				m_HandMenuUIGameObject.transform.rotation = newRot;
			}));
			m_InitialMenuLocalScale = m_HandMenuUIGameObject.transform.localScale;
			m_MenuScaleTweenable.Value = m_InitialMenuLocalScale;
			m_BindingsGroup.AddBinding(m_MenuScaleTweenable.Subscribe(delegate(float3 value)
			{
				m_HandMenuUIGameObject.transform.localScale = value;
			}));
			m_BindingsGroup.AddBinding(XRInputModalityManager.currentInputMode.SubscribeAndUpdate(OnInputModeChanged));
			m_MenuVisibleBindableVariable.Value = false;
			m_BindingsGroup.AddBinding(m_MenuVisibleBindableVariable.SubscribeAndUpdate(delegate(bool value)
			{
				if (value)
				{
					ShowMenu();
				}
				else
				{
					HideMenu();
				}
			}));
		}

		protected void OnDisable()
		{
			if (m_ShowCoroutine != null)
			{
				StopCoroutine(m_ShowCoroutine);
				m_ShowCoroutine = null;
			}
			if (m_HideCoroutine != null)
			{
				StopCoroutine(m_HideCoroutine);
				m_HideCoroutine = null;
			}
			m_BindingsGroup.Clear();
			m_HandMenuUIGameObject.transform.localScale = m_InitialMenuLocalScale;
			m_HandMenuUIGameObject.SetActive(value: true);
			OnMenuVisible();
		}

		protected void OnDestroy()
		{
			m_HandAnchorSmartFollow.Dispose();
		}

		protected void OnValidate()
		{
			m_HandAnchorSmartFollow.minDistanceAllowed = m_MinFollowDistance;
			m_HandAnchorSmartFollow.maxDistanceAllowed = m_MaxFollowDistance;
			m_HandAnchorSmartFollow.minToMaxDelaySeconds = m_MinToMaxDelaySeconds;
			m_MenuVisibilityDotThreshold = AngleToDot(m_MenuVisibleGazeAngleDivergenceThreshold);
		}

		private void OnInputModeChanged(XRInputModalityManager.InputMode newInputMode)
		{
			m_CurrentInputMode = newInputMode;
			GetCurrentPreset()?.ApplyPreset(m_LeftOffsetRoot, m_RightOffsetRoot);
		}

		private FollowPreset GetCurrentPreset()
		{
			if (m_CurrentInputMode == XRInputModalityManager.InputMode.MotionController)
			{
				return m_ControllerFollowPreset.Value;
			}
			return m_HandTrackingFollowPreset.Value;
		}

		private void ShowMenu()
		{
			if (m_HideCoroutine != null)
			{
				StopCoroutine(m_HideCoroutine);
				m_HideCoroutine = null;
			}
			m_HandMenuUIGameObject.SetActive(value: true);
			if (m_AnimateMenuHideAndReveal && m_ShowCoroutine == null)
			{
				m_ShowCoroutine = StartCoroutine(m_MenuScaleTweenable.PlaySequence(m_MenuScaleTweenable.Value, m_InitialMenuLocalScale, m_RevealHideAnimationDuration, OnMenuVisible));
			}
			else
			{
				OnMenuVisible();
			}
		}

		private void OnMenuVisible()
		{
			m_ShowCoroutine = null;
			m_WasMenuHiddenLastFrame = false;
		}

		private void HideMenu()
		{
			if (m_ShowCoroutine != null)
			{
				StopCoroutine(m_ShowCoroutine);
				m_ShowCoroutine = null;
			}
			if (m_AnimateMenuHideAndReveal && m_HideCoroutine == null)
			{
				m_HideCoroutine = StartCoroutine(m_MenuScaleTweenable.PlaySequence(m_MenuScaleTweenable.Value, Vector3.zero, m_RevealHideAnimationDuration, OnMenuHidden));
			}
			else
			{
				OnMenuHidden();
			}
		}

		private void OnMenuHidden()
		{
			m_HandMenuUIGameObject.SetActive(value: false);
			m_WasMenuHiddenLastFrame = true;
			m_HideCoroutine = null;
		}

		protected void LateUpdate()
		{
			if (m_CurrentInputMode == XRInputModalityManager.InputMode.None)
			{
				m_MenuVisibleBindableVariable.Value = false;
				return;
			}
			bool flag = false;
			FollowPreset currentPreset = GetCurrentPreset();
			if (TryGetTrackedAnchors(m_MenuHandedness, in currentPreset, out var targetHandedness, out var cameraTransform, out var palmAnchor, out var palmAnchorOffset))
			{
				m_LastValidCameraTransform = cameraTransform;
				m_LastValidPalmAnchor = palmAnchor;
				m_LastValidPalmAnchorOffset = palmAnchorOffset;
				m_LastValidTrackingTime = Time.unscaledTime;
				flag = true;
			}
			if (!flag)
			{
				if (Time.unscaledTime - m_LastValidTrackingTime > currentPreset.hideDelaySeconds)
				{
					m_MenuVisibleBindableVariable.Value = false;
				}
				if (m_LastValidCameraTransform == null || m_LastValidPalmAnchor == null || m_LastValidPalmAnchorOffset == null)
				{
					return;
				}
			}
			Vector3 forward = (m_LastValidPalmAnchorOffset.position - m_LastValidCameraTransform.position).normalized;
			if (flag)
			{
				if (m_HideMenuWhenGazeDiverges)
				{
					Vector3 forward2 = m_LastValidCameraTransform.forward;
					flag = Vector3.Dot(forward, forward2) > m_MenuVisibilityDotThreshold;
				}
				m_MenuVisibleBindableVariable.Value = flag;
			}
			if (!m_HandMenuUIGameObject.activeSelf)
			{
				return;
			}
			Pose worldPose = m_LastValidPalmAnchorOffset.GetWorldPose();
			Vector3 position = worldPose.position;
			Quaternion lookRotation = worldPose.rotation;
			if (targetHandedness == MenuHandedness.Left || targetHandedness == MenuHandedness.Right)
			{
				Vector3 referenceAxisForTrackingAnchor = currentPreset.GetReferenceAxisForTrackingAnchor(m_LastValidPalmAnchor, targetHandedness == MenuHandedness.Right);
				Vector3 rhs = -forward;
				if (currentPreset.snapToGaze && Vector3.Dot(referenceAxisForTrackingAnchor, rhs) > currentPreset.snapToGazeDotThreshold)
				{
					BurstMathUtility.OrthogonalLookRotation(in forward, GetReferenceUpDirection(m_LastValidCameraTransform), out lookRotation);
				}
			}
			m_HandAnchorSmartFollow.target = position;
			m_RotTweenFollow.target = lookRotation;
			if (m_WasMenuHiddenLastFrame || !currentPreset.allowSmoothing)
			{
				m_HandAnchorSmartFollow.HandleTween(1f);
				if (currentPreset.allowSmoothing)
				{
					m_RotTweenFollow.HandleTween(Time.deltaTime * currentPreset.followLowerSmoothingValue);
				}
				else
				{
					m_RotTweenFollow.HandleTween(1f);
				}
			}
			else
			{
				m_HandAnchorSmartFollow.HandleSmartTween(Time.deltaTime, currentPreset.followLowerSmoothingValue, currentPreset.followUpperSmoothingValue);
				m_RotTweenFollow.HandleTween(Time.deltaTime * currentPreset.followLowerSmoothingValue);
			}
		}

		private bool TryGetTrackedAnchors(MenuHandedness desiredHandedness, in FollowPreset currentPreset, out MenuHandedness targetHandedness, out Transform cameraTransform, out Transform palmAnchor, out Transform palmAnchorOffset)
		{
			palmAnchor = null;
			palmAnchorOffset = null;
			targetHandedness = MenuHandedness.None;
			if (!TryGetCamera(out cameraTransform) || desiredHandedness == MenuHandedness.None)
			{
				return false;
			}
			bool flag = false;
			bool flag2 = false;
			if (m_HideMenuOnSelect && TryGetInteractionManager(out var manager))
			{
				flag = manager.IsHandSelecting(InteractorHandedness.Left);
				flag2 = manager.IsHandSelecting(InteractorHandedness.Right);
			}
			bool flag3 = !flag && PalmMeetsRequirements(cameraTransform, m_LeftPalmAnchor, isRightHand: false, in currentPreset);
			bool flag4 = !flag2 && PalmMeetsRequirements(cameraTransform, m_RightPalmAnchor, isRightHand: true, in currentPreset);
			if (!flag3 && !flag4)
			{
				return false;
			}
			switch (desiredHandedness)
			{
			case MenuHandedness.Either:
				if (flag3 && flag4)
				{
					MenuHandedness menuHandedness = ((m_LastHandThatMetRequirements != MenuHandedness.Right) ? MenuHandedness.Left : MenuHandedness.Right);
					GetTransformAnchorsForHandedness(menuHandedness, out palmAnchor, out palmAnchorOffset);
					targetHandedness = menuHandedness;
					return true;
				}
				if (flag3)
				{
					GetTransformAnchorsForHandedness(MenuHandedness.Left, out palmAnchor, out palmAnchorOffset);
					m_LastHandThatMetRequirements = MenuHandedness.Left;
					targetHandedness = MenuHandedness.Left;
					return true;
				}
				GetTransformAnchorsForHandedness(MenuHandedness.Right, out palmAnchor, out palmAnchorOffset);
				m_LastHandThatMetRequirements = MenuHandedness.Right;
				targetHandedness = MenuHandedness.Right;
				return true;
			case MenuHandedness.Left:
				if (flag3)
				{
					GetTransformAnchorsForHandedness(MenuHandedness.Left, out palmAnchor, out palmAnchorOffset);
					m_LastHandThatMetRequirements = MenuHandedness.Left;
					targetHandedness = MenuHandedness.Left;
					return true;
				}
				palmAnchor = null;
				palmAnchorOffset = null;
				return false;
			case MenuHandedness.Right:
				if (flag4)
				{
					GetTransformAnchorsForHandedness(MenuHandedness.Right, out palmAnchor, out palmAnchorOffset);
					m_LastHandThatMetRequirements = MenuHandedness.Right;
					targetHandedness = MenuHandedness.Right;
					return true;
				}
				palmAnchor = null;
				palmAnchorOffset = null;
				return false;
			default:
				return false;
			}
		}

		private bool TryGetInteractionManager(out XRInteractionManager manager)
		{
			if (m_InteractionManager != null)
			{
				manager = m_InteractionManager;
				return true;
			}
			if (ComponentLocatorUtility<XRInteractionManager>.TryFindComponent(out m_InteractionManager))
			{
				manager = m_InteractionManager;
				return true;
			}
			manager = null;
			return false;
		}

		private void GetTransformAnchorsForHandedness(MenuHandedness handedness, out Transform palmAnchor, out Transform palmAnchorOffset)
		{
			switch (handedness)
			{
			case MenuHandedness.Left:
				palmAnchor = m_LeftPalmAnchor;
				palmAnchorOffset = m_LeftOffsetRoot;
				break;
			case MenuHandedness.Right:
				palmAnchor = m_RightPalmAnchor;
				palmAnchorOffset = m_RightOffsetRoot;
				break;
			default:
				palmAnchor = null;
				palmAnchorOffset = null;
				break;
			}
		}

		private Vector3 GetReferenceUpDirection(Transform cameraTransform)
		{
			return m_HandMenuUpDirection switch
			{
				UpDirection.WorldUp => Vector3.up, 
				UpDirection.CameraUp => cameraTransform.up, 
				_ => base.transform.up, 
			};
		}

		private bool PalmMeetsRequirements(Transform cameraTransform, Transform palmAnchor, bool isRightHand, in FollowPreset currentPresent)
		{
			if (currentPresent == null)
			{
				return false;
			}
			Vector3 referenceAxisForTrackingAnchor = currentPresent.GetReferenceAxisForTrackingAnchor(palmAnchor, isRightHand);
			Vector3 referenceUpDirection = GetReferenceUpDirection(cameraTransform);
			bool num = !currentPresent.requirePalmFacingUser || Vector3.Dot(referenceAxisForTrackingAnchor, -cameraTransform.forward) > currentPresent.palmFacingUserDotThreshold;
			bool flag = !currentPresent.requirePalmFacingUp || Vector3.Dot(referenceAxisForTrackingAnchor, referenceUpDirection) > currentPresent.palmFacingUpDotThreshold;
			return num && flag;
		}

		private bool TryGetCamera(out Transform cameraTransform)
		{
			if (m_CameraTransform == null)
			{
				Camera main = Camera.main;
				if (main == null)
				{
					cameraTransform = null;
					return false;
				}
				m_CameraTransform = main.transform;
			}
			cameraTransform = m_CameraTransform;
			return true;
		}

		private static float AngleToDot(float angleDeg)
		{
			return Mathf.Cos(MathF.PI / 180f * angleDeg);
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Locomotion
{
	[CreateAssetMenu(fileName = "CharacterControllerBodyManipulator", menuName = "XR/Locomotion/Character Controller Body Manipulator")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.CharacterControllerBodyManipulator.html")]
	public class CharacterControllerBodyManipulator : ScriptableConstrainedBodyManipulator
	{
		public override CollisionFlags lastCollisionFlags
		{
			get
			{
				if (!(characterController != null))
				{
					return CollisionFlags.None;
				}
				return characterController.collisionFlags;
			}
		}

		public override bool isGrounded
		{
			get
			{
				if (!(characterController == null))
				{
					return characterController.isGrounded;
				}
				return true;
			}
		}

		public CharacterController characterController { get; private set; }

		public override void OnLinkedToBody(XRMovableBody body)
		{
			base.OnLinkedToBody(body);
			XROrigin xrOrigin = body.xrOrigin;
			GameObject origin = xrOrigin.Origin;
			if (!origin.TryGetComponent<CharacterController>(out var component) && origin != xrOrigin.gameObject)
			{
				xrOrigin.TryGetComponent<CharacterController>(out component);
			}
			if (component != null)
			{
				characterController = component;
				return;
			}
			Debug.LogWarning("No CharacterController found. Adding one to Origin GameObject '" + origin.name + "'.", this);
			characterController = origin.AddComponent<CharacterController>();
		}

		public override void OnUnlinkedFromBody()
		{
			base.OnUnlinkedFromBody();
			characterController = null;
		}

		public override CollisionFlags MoveBody(Vector3 motion)
		{
			if (base.linkedBody == null || characterController == null)
			{
				return CollisionFlags.None;
			}
			XROrigin xrOrigin = base.linkedBody.xrOrigin;
			Vector3 bodyGroundLocalPosition = base.linkedBody.GetBodyGroundLocalPosition();
			float num = xrOrigin.CameraInOriginSpaceHeight - bodyGroundLocalPosition.y;
			characterController.height = num;
			characterController.center = new Vector3(bodyGroundLocalPosition.x, bodyGroundLocalPosition.y + num * 0.5f + characterController.skinWidth, bodyGroundLocalPosition.z);
			return characterController.Move(motion);
		}
	}
	public interface IConstrainedXRBodyManipulator
	{
		XRMovableBody linkedBody { get; }

		CollisionFlags lastCollisionFlags { get; }

		bool isGrounded { get; }

		void OnLinkedToBody(XRMovableBody body);

		void OnUnlinkedFromBody();

		CollisionFlags MoveBody(Vector3 motion);
	}
	public interface IXRBodyPositionEvaluator
	{
		Vector3 GetBodyGroundLocalPosition(XROrigin xrOrigin);
	}
	public static class XRBodyPositionEvaluatorExtensions
	{
		public static Vector3 GetBodyGroundWorldPosition(this IXRBodyPositionEvaluator evaluator, XROrigin xrOrigin)
		{
			return xrOrigin.Origin.transform.TransformPoint(evaluator.GetBodyGroundLocalPosition(xrOrigin));
		}
	}
	public interface IXRBodyTransformation
	{
		void Apply(XRMovableBody body);
	}
	[AddComponentMenu("XR/Locomotion/Locomotion Mediator", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.LocomotionMediator.html")]
	[RequireComponent(typeof(XRBodyTransformer))]
	public class LocomotionMediator : MonoBehaviour
	{
		private class LocomotionProviderData
		{
			public LocomotionState state;

			public int locomotionEndFrame;
		}

		private XRBodyTransformer m_XRBodyTransformer;

		private readonly Dictionary<LocomotionProvider, LocomotionProviderData> m_ProviderDataMap = new Dictionary<LocomotionProvider, LocomotionProviderData>();

		private static readonly List<LocomotionProvider> s_ProvidersToRemove = new List<LocomotionProvider>();

		public XROrigin xrOrigin
		{
			get
			{
				return m_XRBodyTransformer.xrOrigin;
			}
			set
			{
				m_XRBodyTransformer.xrOrigin = value;
			}
		}

		public XRBodyTransformer bodyTransformer => m_XRBodyTransformer;

		protected void Awake()
		{
			m_XRBodyTransformer = GetComponent<XRBodyTransformer>();
		}

		protected void Update()
		{
			s_ProvidersToRemove.Clear();
			foreach (KeyValuePair<LocomotionProvider, LocomotionProviderData> item in m_ProviderDataMap)
			{
				LocomotionProvider key = item.Key;
				if (key == null)
				{
					s_ProvidersToRemove.Add(key);
					continue;
				}
				LocomotionProviderData value = item.Value;
				if (value.state == LocomotionState.Preparing && key.canStartMoving)
				{
					ChangeState(key, value, LocomotionState.Moving);
				}
				else if (value.state == LocomotionState.Ended && Time.frameCount > value.locomotionEndFrame)
				{
					ChangeState(key, value, LocomotionState.Idle);
				}
			}
			if (s_ProvidersToRemove.Count <= 0)
			{
				return;
			}
			foreach (LocomotionProvider item2 in s_ProvidersToRemove)
			{
				m_ProviderDataMap.Remove(item2);
			}
		}

		internal bool TryPrepareLocomotion(LocomotionProvider provider)
		{
			if (!m_ProviderDataMap.TryGetValue(provider, out var value))
			{
				value = new LocomotionProviderData();
				m_ProviderDataMap[provider] = value;
			}
			else if (GetProviderLocomotionState(provider).IsActive())
			{
				return false;
			}
			ChangeState(provider, value, LocomotionState.Preparing);
			return true;
		}

		internal bool TryStartLocomotion(LocomotionProvider provider)
		{
			if (!m_ProviderDataMap.TryGetValue(provider, out var value))
			{
				value = new LocomotionProviderData();
				m_ProviderDataMap[provider] = value;
			}
			else if (GetProviderLocomotionState(provider) == LocomotionState.Moving)
			{
				return false;
			}
			ChangeState(provider, value, LocomotionState.Moving);
			return true;
		}

		internal bool TryEndLocomotion(LocomotionProvider provider)
		{
			if (!m_ProviderDataMap.TryGetValue(provider, out var value))
			{
				return false;
			}
			if (!value.state.IsActive())
			{
				return false;
			}
			ChangeState(provider, value, LocomotionState.Ended);
			return true;
		}

		private void ChangeState(LocomotionProvider provider, LocomotionProviderData providerData, LocomotionState state)
		{
			if (providerData.state != state)
			{
				LocomotionState state2 = providerData.state;
				providerData.state = state;
				if (state == LocomotionState.Ended)
				{
					providerData.locomotionEndFrame = Time.frameCount;
				}
				provider.OnLocomotionStateChanging(state2, state, m_XRBodyTransformer);
			}
		}

		public LocomotionState GetProviderLocomotionState(LocomotionProvider provider)
		{
			if (!m_ProviderDataMap.TryGetValue(provider, out var value))
			{
				return LocomotionState.Idle;
			}
			return value.state;
		}
	}
	[DefaultExecutionOrder(-210)]
	[MovedFrom("UnityEngine.XR.Interaction.Toolkit")]
	public abstract class LocomotionProvider : MonoBehaviour
	{
		[SerializeField]
		[Tooltip("The behavior that this provider communicates with for access to the mediator's XR Body Transformer. If one is not provided, this provider will attempt to locate one during its Awake call.")]
		private LocomotionMediator m_Mediator;

		[SerializeField]
		[Tooltip("The queue order of this provider's transformations of the XR Origin. The lower the value, the earlier the transformations are applied.")]
		private int m_TransformationPriority;

		private XRBodyTransformer m_ActiveBodyTransformer;

		private XRBodyTransformer m_SubscribedTransformer;

		private bool m_AnyTransformationsQueued;

		[Tooltip("(Deprecated) The Locomotion System that this locomotion provider communicates with for exclusive access to an XR Origin. If one is not provided, the behavior will attempt to locate one during its Awake call.")]
		[Obsolete("LocomotionSystem is deprecated in XRI 3.0.0 and will be removed in a future release. Use mediator instead.", false)]
		private LocomotionSystem m_System;

		public LocomotionMediator mediator
		{
			get
			{
				return m_Mediator;
			}
			set
			{
				m_Mediator = value;
			}
		}

		public int transformationPriority
		{
			get
			{
				return m_TransformationPriority;
			}
			set
			{
				m_TransformationPriority = value;
			}
		}

		public LocomotionState locomotionState
		{
			get
			{
				if (!(m_Mediator != null))
				{
					return LocomotionState.Idle;
				}
				return m_Mediator.GetProviderLocomotionState(this);
			}
		}

		public bool isLocomotionActive => locomotionState.IsActive();

		public virtual bool canStartMoving => true;

		internal static List<LocomotionProvider> locomotionProviders { get; } = new List<LocomotionProvider>();

		[Obsolete("LocomotionSystem is deprecated in XRI 3.0.0 and will be removed in a future release. Use mediator instead.", false)]
		public LocomotionSystem system
		{
			get
			{
				return m_System;
			}
			set
			{
				m_System = value;
			}
		}

		[Obsolete("locomotionPhase is deprecated in XRI 3.0.0 and will be removed in a future release. Use locomotionState instead.", false)]
		public LocomotionPhase locomotionPhase { get; protected set; }

		public event Action<LocomotionProvider, LocomotionState> locomotionStateChanged;

		public event Action<LocomotionProvider> locomotionStarted;

		public event Action<LocomotionProvider> locomotionEnded;

		public event Action<LocomotionProvider> beforeStepLocomotion;

		public event Action<LocomotionProvider> afterStepLocomotion;

		internal static event Action<LocomotionProvider> locomotionProvidersChanged;

		[Obsolete("startLocomotion has been deprecated in XRI 3.0.0. Use beginLocomotion instead. (UnityUpgradable) -> beginLocomotion", true)]
		public event Action<LocomotionSystem> startLocomotion;

		[Obsolete("beginLocomotion is deprecated in XRI 3.0.0 and will be removed in a future release. Use locomotionStarted instead.", false)]
		public event Action<LocomotionSystem> beginLocomotion;

		[Obsolete("endLocomotion is deprecated in XRI 3.0.0 and will be removed in a future release. Use locomotionEnded instead.", false)]
		public event Action<LocomotionSystem> endLocomotion;

		protected virtual void Awake()
		{
			if (m_System == null)
			{
				m_System = GetComponentInParent<LocomotionSystem>();
				if (m_System == null)
				{
					ComponentLocatorUtility<LocomotionSystem>.TryFindComponent(out m_System);
				}
			}
			if (m_Mediator == null)
			{
				m_Mediator = GetComponentInParent<LocomotionMediator>();
				if (m_Mediator == null)
				{
					ComponentLocatorUtility<LocomotionMediator>.TryFindComponent(out m_Mediator);
				}
			}
			if (m_Mediator == null && m_System == null)
			{
				Debug.LogError("Locomotion Provider requires a Locomotion Mediator or Locomotion System (legacy) in the scene.", this);
				base.enabled = false;
			}
			locomotionProviders.Add(this);
			LocomotionProvider.locomotionProvidersChanged?.Invoke(this);
		}

		protected bool TryPrepareLocomotion()
		{
			if (m_Mediator != null)
			{
				return m_Mediator.TryPrepareLocomotion(this);
			}
			return false;
		}

		protected bool TryStartLocomotionImmediately()
		{
			if (m_Mediator != null)
			{
				return m_Mediator.TryStartLocomotion(this);
			}
			return false;
		}

		protected bool TryEndLocomotion()
		{
			if (m_Mediator != null)
			{
				return m_Mediator.TryEndLocomotion(this);
			}
			return false;
		}

		protected virtual void OnLocomotionStarting()
		{
		}

		protected virtual void OnLocomotionEnding()
		{
		}

		protected virtual void OnLocomotionStateChanging(LocomotionState state)
		{
		}

		internal void OnLocomotionStateChanging(LocomotionState oldState, LocomotionState state, XRBodyTransformer transformer)
		{
			switch (state)
			{
			case LocomotionState.Moving:
				if (oldState == LocomotionState.Ended && m_AnyTransformationsQueued)
				{
					Debug.LogWarning("LocomotionProvider (" + GetType().Name + ") changed state from LocomotionState.Ended to LocomotionState.Moving before its queued transformations have been applied. The deferred OnLocomotionEnding method call and locomotionEnded event will not be invoked.", this);
				}
				m_ActiveBodyTransformer = transformer;
				Subscribe(transformer);
				break;
			case LocomotionState.Ended:
				m_ActiveBodyTransformer = null;
				break;
			}
			OnLocomotionStateChanging(state);
			this.locomotionStateChanged?.Invoke(this, state);
			switch (state)
			{
			case LocomotionState.Moving:
				OnLocomotionStarting();
				this.locomotionStarted?.Invoke(this);
				break;
			case LocomotionState.Ended:
				if (!m_AnyTransformationsQueued)
				{
					Unsubscribe();
					OnLocomotionEnding();
					this.locomotionEnded?.Invoke(this);
				}
				break;
			}
		}

		protected bool TryQueueTransformation(IXRBodyTransformation bodyTransformation)
		{
			if (!CanQueueTransformation())
			{
				return false;
			}
			m_ActiveBodyTransformer.QueueTransformation(bodyTransformation, m_TransformationPriority);
			m_AnyTransformationsQueued = true;
			return true;
		}

		protected bool TryQueueTransformation(IXRBodyTransformation bodyTransformation, int priority)
		{
			if (!CanQueueTransformation())
			{
				return false;
			}
			m_ActiveBodyTransformer.QueueTransformation(bodyTransformation, priority);
			m_AnyTransformationsQueued = true;
			return true;
		}

		private bool CanQueueTransformation()
		{
			if (m_ActiveBodyTransformer == null)
			{
				if (locomotionState == LocomotionState.Moving)
				{
					Debug.LogError("Cannot queue transformation because reference to active XR Body Transformer is null, even though Locomotion Provider is in Moving state. This should not happen.", this);
				}
				return false;
			}
			return true;
		}

		private void Subscribe(XRBodyTransformer transformer)
		{
			if (!(m_SubscribedTransformer == transformer))
			{
				Unsubscribe();
				transformer.beforeApplyTransformations += OnBeforeApplyTransformations;
				transformer.afterApplyTransformations += OnAfterApplyTransformations;
				m_SubscribedTransformer = transformer;
			}
		}

		private void Unsubscribe()
		{
			if (!(m_SubscribedTransformer == null))
			{
				m_SubscribedTransformer.beforeApplyTransformations -= OnBeforeApplyTransformations;
				m_SubscribedTransformer.afterApplyTransformations -= OnAfterApplyTransformations;
				m_SubscribedTransformer = null;
			}
		}

		private void OnBeforeApplyTransformations(XRBodyTransformer transformer)
		{
			if (m_AnyTransformationsQueued)
			{
				this.beforeStepLocomotion?.Invoke(this);
			}
		}

		private void OnAfterApplyTransformations(ApplyBodyTransformationsEventArgs args)
		{
			if (m_AnyTransformationsQueued)
			{
				this.afterStepLocomotion?.Invoke(this);
			}
			m_AnyTransformationsQueued = false;
			if ((object)m_ActiveBodyTransformer == null)
			{
				Unsubscribe();
				OnLocomotionEnding();
				this.locomotionEnded?.Invoke(this);
			}
		}

		[Obsolete("CanBeginLocomotion is deprecated in XRI 3.0.0 and will be removed in a future release. Instead, query isLocomotionActive to check if locomotion can start.", false)]
		protected bool CanBeginLocomotion()
		{
			if (m_System == null)
			{
				return false;
			}
			return !m_System.busy;
		}

		[Obsolete("BeginLocomotion is deprecated in XRI 3.0.0 and will be removed in a future release. Instead, call TryPrepareLocomotion when locomotion start input occurs.", false)]
		protected bool BeginLocomotion()
		{
			if (m_System == null)
			{
				return false;
			}
			bool num = m_System.RequestExclusiveOperation(this) == RequestResult.Success;
			if (num)
			{
				Action<LocomotionSystem> action = this.beginLocomotion;
				if (action == null)
				{
					return num;
				}
				action(m_System);
			}
			return num;
		}

		[Obsolete("EndLocomotion is deprecated in XRI 3.0.0 and will be removed in a future release. Instead, call TryEndLocomotion when locomotion end input has completed.", false)]
		protected bool EndLocomotion()
		{
			if (m_System == null)
			{
				return false;
			}
			bool num = m_System.FinishExclusiveOperation(this) == RequestResult.Success;
			if (num)
			{
				Action<LocomotionSystem> action = this.endLocomotion;
				if (action == null)
				{
					return num;
				}
				action(m_System);
			}
			return num;
		}
	}
	public enum LocomotionState
	{
		Idle,
		Preparing,
		Moving,
		Ended
	}
	public static class LocomotionStateExtensions
	{
		public static bool IsActive(this LocomotionState state)
		{
			if (state != LocomotionState.Preparing)
			{
				return state == LocomotionState.Moving;
			}
			return true;
		}
	}
	public abstract class ScriptableConstrainedBodyManipulator : ScriptableObject, IConstrainedXRBodyManipulator
	{
		public XRMovableBody linkedBody { get; private set; }

		public abstract CollisionFlags lastCollisionFlags { get; }

		public abstract bool isGrounded { get; }

		public virtual void OnLinkedToBody(XRMovableBody body)
		{
			linkedBody = body;
		}

		public virtual void OnUnlinkedFromBody()
		{
			linkedBody = null;
		}

		public abstract CollisionFlags MoveBody(Vector3 motion);
	}
	[CreateAssetMenu(fileName = "UnderCameraBodyPositionEvaluator", menuName = "XR/Locomotion/Under Camera Body Position Evaluator")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.UnderCameraBodyPositionEvaluator.html")]
	public class UnderCameraBodyPositionEvaluator : ScriptableObject, IXRBodyPositionEvaluator
	{
		public Vector3 GetBodyGroundLocalPosition(XROrigin xrOrigin)
		{
			Vector3 cameraInOriginSpacePos = xrOrigin.CameraInOriginSpacePos;
			cameraInOriginSpacePos.y = 0f;
			return cameraInOriginSpacePos;
		}
	}
	public class DelegateXRBodyTransformation : IXRBodyTransformation
	{
		public event Action<XRMovableBody> transformation;

		public DelegateXRBodyTransformation()
		{
		}

		public DelegateXRBodyTransformation(Action<XRMovableBody> transformation)
		{
			this.transformation = transformation;
		}

		public void Apply(XRMovableBody body)
		{
			this.transformation?.Invoke(body);
		}
	}
	public class XROriginMovement : IXRBodyTransformation
	{
		public Vector3 motion { get; set; }

		public bool forceUnconstrained { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			if (body.constrainedManipulator != null && !forceUnconstrained)
			{
				body.constrainedManipulator.MoveBody(motion);
			}
			else
			{
				body.originTransform.position += motion;
			}
		}
	}
	public class XRBodyGroundPosition : IXRBodyTransformation
	{
		public Vector3 targetPosition { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			Transform originTransform = body.originTransform;
			originTransform.position = targetPosition + originTransform.position - body.GetBodyGroundWorldPosition();
		}
	}
	public class XROriginUpAlignment : IXRBodyTransformation
	{
		public Vector3 targetUp { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			body.xrOrigin.MatchOriginUp(targetUp);
		}
	}
	public class XRBodyYawRotation : IXRBodyTransformation
	{
		public float angleDelta { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			Transform originTransform = body.originTransform;
			originTransform.RotateAround(body.GetBodyGroundWorldPosition(), originTransform.up, angleDelta);
		}
	}
	public class XRCameraForwardXZAlignment : IXRBodyTransformation
	{
		public Vector3 targetDirection { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			XROrigin xrOrigin = body.xrOrigin;
			Vector3 up = body.originTransform.up;
			Vector3 normalized = Vector3.ProjectOnPlane(xrOrigin.Camera.transform.forward, up).normalized;
			Vector3 normalized2 = Vector3.ProjectOnPlane(targetDirection, up).normalized;
			float angleDegrees = Vector3.SignedAngle(normalized, normalized2, up);
			xrOrigin.RotateAroundCameraPosition(up, angleDegrees);
		}
	}
	public class XRBodyScale : IXRBodyTransformation
	{
		public float uniformScale { get; set; }

		public virtual void Apply(XRMovableBody body)
		{
			Vector3 bodyGroundWorldPosition = body.GetBodyGroundWorldPosition();
			Transform originTransform = body.originTransform;
			originTransform.localScale = Vector3.one * uniformScale;
			Vector3 bodyGroundWorldPosition2 = body.GetBodyGroundWorldPosition();
			originTransform.position = bodyGroundWorldPosition + originTransform.position - bodyGroundWorldPosition2;
		}
	}
	public sealed class ApplyBodyTransformationsEventArgs
	{
		public XRBodyTransformer bodyTransformer { get; set; }
	}
	[AddComponentMenu("XR/Locomotion/XR Body Transformer", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.XRBodyTransformer.html")]
	[DefaultExecutionOrder(-205)]
	public class XRBodyTransformer : MonoBehaviour
	{
		private struct OrderedTransformation
		{
			public IXRBodyTransformation transformation;

			public int priority;
		}

		[SerializeField]
		[Tooltip("The XR Origin to transform (will find one if None).")]
		private XROrigin m_XROrigin;

		[SerializeField]
		[RequireInterface(typeof(IXRBodyPositionEvaluator))]
		[Tooltip("Object that determines the position of the user's body. If set to None, this behavior will estimate the position to be the camera position projected onto the XZ plane of the XR Origin.")]
		private Object m_BodyPositionEvaluatorObject;

		private IXRBodyPositionEvaluator m_BodyPositionEvaluator;

		[SerializeField]
		[RequireInterface(typeof(IConstrainedXRBodyManipulator))]
		[Tooltip("Object used to perform movement that is constrained by collision (optional, may be None).")]
		private Object m_ConstrainedBodyManipulatorObject;

		private IConstrainedXRBodyManipulator m_ConstrainedBodyManipulator;

		[SerializeField]
		[Tooltip("When enabled and if a Constrained Manipulator is not already assigned, this behavior will use the XR Origin's Character Controller to perform constrained movement, if one exists on the XR Origin's base GameObject.")]
		private bool m_UseCharacterControllerIfExists = true;

		private bool m_UsingDynamicBodyPositionEvaluator;

		private bool m_UsingDynamicConstrainedBodyManipulator;

		private XRMovableBody m_MovableBody;

		private readonly LinkedList<OrderedTransformation> m_TransformationsQueue = new LinkedList<OrderedTransformation>();

		private readonly ApplyBodyTransformationsEventArgs m_ApplyTransformationsEventArgs = new ApplyBodyTransformationsEventArgs();

		public XROrigin xrOrigin
		{
			get
			{
				return m_XROrigin;
			}
			set
			{
				m_XROrigin = value;
				if (Application.isPlaying)
				{
					InitializeMovableBody();
				}
			}
		}

		public IXRBodyPositionEvaluator bodyPositionEvaluator
		{
			get
			{
				return m_BodyPositionEvaluator;
			}
			set
			{
				m_BodyPositionEvaluator = value;
				if (Application.isPlaying)
				{
					InitializeMovableBody();
				}
			}
		}

		public IConstrainedXRBodyManipulator constrainedBodyManipulator
		{
			get
			{
				return m_ConstrainedBodyManipulator;
			}
			set
			{
				m_ConstrainedBodyManipulator = value;
				if (m_MovableBody != null)
				{
					m_MovableBody.UnlinkConstrainedManipulator();
					if (m_ConstrainedBodyManipulator != null)
					{
						m_MovableBody.LinkConstrainedManipulator(m_ConstrainedBodyManipulator);
					}
				}
			}
		}

		public bool useCharacterControllerIfExists
		{
			get
			{
				return m_UseCharacterControllerIfExists;
			}
			set
			{
				m_UseCharacterControllerIfExists = value;
			}
		}

		public event Action<XRBodyTransformer> beforeApplyTransformations;

		public event Action<ApplyBodyTransformationsEventArgs> afterApplyTransformations;

		protected virtual void Reset()
		{
			m_XROrigin = ComponentLocatorUtility<XROrigin>.FindComponent();
		}

		protected virtual void OnEnable()
		{
			if (m_XROrigin == null && !ComponentLocatorUtility<XROrigin>.TryFindComponent(out m_XROrigin))
			{
				Debug.LogError("XR Body Transformer requires an XR Origin in the scene.", this);
				base.enabled = false;
				return;
			}
			m_BodyPositionEvaluator = m_BodyPositionEvaluatorObject as IXRBodyPositionEvaluator;
			if (m_BodyPositionEvaluator == null)
			{
				m_UsingDynamicBodyPositionEvaluator = true;
				m_BodyPositionEvaluator = ScriptableSingletonCache<UnderCameraBodyPositionEvaluator>.GetInstance(this);
			}
			m_ConstrainedBodyManipulator = m_ConstrainedBodyManipulatorObject as IConstrainedXRBodyManipulator;
			if (m_ConstrainedBodyManipulator == null && m_UseCharacterControllerIfExists && m_XROrigin.Origin.TryGetComponent<CharacterController>(out var _))
			{
				m_UsingDynamicConstrainedBodyManipulator = true;
				m_ConstrainedBodyManipulator = ScriptableSingletonCache<CharacterControllerBodyManipulator>.GetInstance(this);
			}
			InitializeMovableBody();
		}

		protected virtual void OnDisable()
		{
			m_MovableBody?.UnlinkConstrainedManipulator();
			m_MovableBody = null;
			if (m_UsingDynamicBodyPositionEvaluator)
			{
				ScriptableSingletonCache<UnderCameraBodyPositionEvaluator>.ReleaseInstance(this);
				m_UsingDynamicBodyPositionEvaluator = false;
			}
			if (m_UsingDynamicConstrainedBodyManipulator)
			{
				ScriptableSingletonCache<CharacterControllerBodyManipulator>.ReleaseInstance(this);
				m_UsingDynamicConstrainedBodyManipulator = false;
			}
		}

		protected virtual void Update()
		{
			if (m_TransformationsQueue.Count != 0)
			{
				this.beforeApplyTransformations?.Invoke(this);
				while (m_TransformationsQueue.Count > 0)
				{
					m_TransformationsQueue.First.Value.transformation.Apply(m_MovableBody);
					m_TransformationsQueue.RemoveFirst();
				}
				m_ApplyTransformationsEventArgs.bodyTransformer = this;
				this.afterApplyTransformations?.Invoke(m_ApplyTransformationsEventArgs);
			}
		}

		private void InitializeMovableBody()
		{
			m_MovableBody = new XRMovableBody(m_XROrigin, m_BodyPositionEvaluator);
			if (m_ConstrainedBodyManipulator != null)
			{
				m_MovableBody.LinkConstrainedManipulator(m_ConstrainedBodyManipulator);
			}
		}

		public void QueueTransformation(IXRBodyTransformation transformation, int priority = 0)
		{
			OrderedTransformation value = new OrderedTransformation
			{
				transformation = transformation,
				priority = priority
			};
			LinkedListNode<OrderedTransformation> linkedListNode = m_TransformationsQueue.First;
			if (linkedListNode == null || linkedListNode.Value.priority > priority)
			{
				m_TransformationsQueue.AddFirst(value);
				return;
			}
			while (linkedListNode.Next != null && linkedListNode.Next.Value.priority <= priority)
			{
				linkedListNode = linkedListNode.Next;
			}
			m_TransformationsQueue.AddAfter(linkedListNode, value);
		}

		protected virtual void OnDrawGizmosSelected()
		{
			if (m_UseCharacterControllerIfExists && m_ConstrainedBodyManipulator != null && m_ConstrainedBodyManipulator is CharacterControllerBodyManipulator characterControllerBodyManipulator && characterControllerBodyManipulator.characterController != null)
			{
				CharacterController characterController = characterControllerBodyManipulator.characterController;
				Vector3 center = characterController.center + characterController.transform.position + Vector3.up * ((characterController.stepOffset - characterController.skinWidth) * 0.5f);
				float height = characterController.height + characterController.stepOffset + characterController.skinWidth;
				float radius = characterController.radius + characterController.skinWidth;
				GizmoHelpers.DrawCapsule(center, height, radius, Vector3.up, new Color(1f, 0.92f, 0.016f, 0.5f));
			}
		}
	}
	public class XRMovableBody
	{
		public XROrigin xrOrigin { get; private set; }

		public Transform originTransform => xrOrigin.Origin.transform;

		public IXRBodyPositionEvaluator bodyPositionEvaluator { get; private set; }

		public IConstrainedXRBodyManipulator constrainedManipulator { get; private set; }

		public XRMovableBody(XROrigin xrOrigin, IXRBodyPositionEvaluator bodyPositionEvaluator)
		{
			this.xrOrigin = xrOrigin;
			this.bodyPositionEvaluator = bodyPositionEvaluator;
		}

		public Vector3 GetBodyGroundLocalPosition()
		{
			return bodyPositionEvaluator.GetBodyGroundLocalPosition(xrOrigin);
		}

		public Vector3 GetBodyGroundWorldPosition()
		{
			return bodyPositionEvaluator.GetBodyGroundWorldPosition(xrOrigin);
		}

		public void LinkConstrainedManipulator(IConstrainedXRBodyManipulator manipulator)
		{
			constrainedManipulator?.OnUnlinkedFromBody();
			manipulator.linkedBody?.UnlinkConstrainedManipulator();
			constrainedManipulator = manipulator;
			constrainedManipulator.OnLinkedToBody(this);
		}

		public void UnlinkConstrainedManipulator()
		{
			constrainedManipulator?.OnUnlinkedFromBody();
			constrainedManipulator = null;
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Locomotion.Turning
{
	[AddComponentMenu("XR/Locomotion/Continuous Turn Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Turning.ContinuousTurnProvider.html")]
	public class ContinuousTurnProvider : LocomotionProvider
	{
		[SerializeField]
		[Tooltip("The number of degrees/second clockwise to rotate when turning clockwise.")]
		private float m_TurnSpeed = 60f;

		[SerializeField]
		[Tooltip("Controls whether to enable left & right continuous turns.")]
		private bool m_EnableTurnLeftRight = true;

		[SerializeField]
		[Tooltip("Controls whether to enable 180° snap turns on the South direction.")]
		private bool m_EnableTurnAround;

		[SerializeField]
		[Tooltip("Reads input data from the left hand controller. Input Action must be a Value action type (Vector 2).")]
		private XRInputValueReader<Vector2> m_LeftHandTurnInput = new XRInputValueReader<Vector2>("Left Hand Turn");

		[SerializeField]
		[Tooltip("Reads input data from the right hand controller. Input Action must be a Value action type (Vector 2).")]
		private XRInputValueReader<Vector2> m_RightHandTurnInput = new XRInputValueReader<Vector2>("Right Hand Turn");

		private bool m_IsTurningXROrigin;

		private bool m_TurnAroundActivated;

		public float turnSpeed
		{
			get
			{
				return m_TurnSpeed;
			}
			set
			{
				m_TurnSpeed = value;
			}
		}

		public bool enableTurnLeftRight
		{
			get
			{
				return m_EnableTurnLeftRight;
			}
			set
			{
				m_EnableTurnLeftRight = value;
			}
		}

		public bool enableTurnAround
		{
			get
			{
				return m_EnableTurnAround;
			}
			set
			{
				m_EnableTurnAround = value;
			}
		}

		public XRInputValueReader<Vector2> leftHandTurnInput
		{
			get
			{
				return m_LeftHandTurnInput;
			}
			set
			{
				XRInputReaderUtility.SetInputProperty(ref m_LeftHandTurnInput, value, this);
			}
		}

		public XRInputValueReader<Vector2> rightHandTurnInput
		{
			get
			{
				return m_RightHandTurnInput;
			}
			set
			{
				XRInputReaderUtility.SetInputProperty(ref m_RightHandTurnInput, value, this);
			}
		}

		public XRBodyYawRotation transformation { get; set; } = new XRBodyYawRotation();

		protected void OnEnable()
		{
			m_LeftHandTurnInput.EnableDirectActionIfModeUsed();
			m_RightHandTurnInput.EnableDirectActionIfModeUsed();
		}

		protected void OnDisable()
		{
			m_LeftHandTurnInput.DisableDirectActionIfModeUsed();
			m_RightHandTurnInput.DisableDirectActionIfModeUsed();
		}

		protected void Update()
		{
			m_IsTurningXROrigin = false;
			Vector2 vector = ReadInput();
			float turnAmount = GetTurnAmount(vector);
			TurnRig(turnAmount);
			if (!m_IsTurningXROrigin)
			{
				TryEndLocomotion();
			}
			if (vector == Vector2.zero)
			{
				m_TurnAroundActivated = false;
			}
		}

		private Vector2 ReadInput()
		{
			Vector2 vector = m_LeftHandTurnInput.ReadValue();
			Vector2 vector2 = m_RightHandTurnInput.ReadValue();
			return vector + vector2;
		}

		protected virtual float GetTurnAmount(Vector2 input)
		{
			switch (CardinalUtility.GetNearestCardinal(input))
			{
			case Cardinal.South:
				if (m_EnableTurnAround && !m_TurnAroundActivated)
				{
					return 180f;
				}
				break;
			case Cardinal.East:
			case Cardinal.West:
				if (m_EnableTurnLeftRight)
				{
					return input.magnitude * (Mathf.Sign(input.x) * m_TurnSpeed * Time.deltaTime);
				}
				break;
			}
			return 0f;
		}

		protected void TurnRig(float turnAmount)
		{
			if (!Mathf.Approximately(turnAmount, 0f))
			{
				if (Mathf.Approximately(turnAmount, 180f))
				{
					m_TurnAroundActivated = true;
				}
				TryStartLocomotionImmediately();
				if (base.locomotionState == LocomotionState.Moving)
				{
					m_IsTurningXROrigin = true;
					transformation.angleDelta = turnAmount;
					TryQueueTransformation(transformation);
				}
			}
		}
	}
	[AddComponentMenu("XR/Locomotion/Snap Turn Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Turning.SnapTurnProvider.html")]
	public class SnapTurnProvider : LocomotionProvider
	{
		[SerializeField]
		[Tooltip("The number of degrees clockwise to rotate when snap turning clockwise.")]
		private float m_TurnAmount = 45f;

		[SerializeField]
		[Tooltip("The amount of time that the system will wait before starting another snap turn.")]
		private float m_DebounceTime = 0.5f;

		[SerializeField]
		[Tooltip("Controls whether to enable left & right snap turns.")]
		private bool m_EnableTurnLeftRight = true;

		[SerializeField]
		[Tooltip("Controls whether to enable 180° snap turns.")]
		private bool m_EnableTurnAround = true;

		[SerializeField]
		[Tooltip("The time (in seconds) to delay the first turn after receiving initial input for the turn.")]
		private float m_DelayTime;

		[SerializeField]
		[Tooltip("Reads input data from the left hand controller. Input Action must be a Value action type (Vector 2).")]
		private XRInputValueReader<Vector2> m_LeftHandTurnInput = new XRInputValueReader<Vector2>("Left Hand Snap Turn");

		[SerializeField]
		[Tooltip("Reads input data from the right hand controller. Input Action must be a Value action type (Vector 2).")]
		private XRInputValueReader<Vector2> m_RightHandTurnInput = new XRInputValueReader<Vector2>("Right Hand Snap Turn");

		private float m_CurrentTurnAmount;

		private float m_TimeStarted;

		private float m_DelayStartTime;

		private bool m_TurnAroundActivated;

		public float turnAmount
		{
			get
			{
				return m_TurnAmount;
			}
			set
			{
				m_TurnAmount = value;
			}
		}

		public float debounceTime
		{
			get
			{
				return m_DebounceTime;
			}
			set
			{
				m_DebounceTime = value;
			}
		}

		public bool enableTurnLeftRight
		{
			get
			{
				return m_EnableTurnLeftRight;
			}
			set
			{
				m_EnableTurnLeftRight = value;
			}
		}

		public bool enableTurnAround
		{
			get
			{
				return m_EnableTurnAround;
			}
			set
			{
				m_EnableTurnAround = value;
			}
		}

		public float delayTime
		{
			get
			{
				return m_DelayTime;
			}
			set
			{
				m_DelayTime = value;
			}
		}

		public override bool canStartMoving
		{
			get
			{
				if (!(m_DelayTime <= 0f))
				{
					return Time.time - m_DelayStartTime >= m_DelayTime;
				}
				return true;
			}
		}

		public XRBodyYawRotation transformation { get; set; } = new XRBodyYawRotation();

		public XRInputValueReader<Vector2> leftHandTurnInput
		{
			get
			{
				return m_LeftHandTurnInput;
			}
			set
			{
				XRInputReaderUtility.SetInputProperty(ref m_LeftHandTurnInput, value, this);
			}
		}

		public XRInputValueReader<Vector2> rightHandTurnInput
		{
			get
			{
				return m_RightHandTurnInput;
			}
			set
			{
				XRInputReaderUtility.SetInputProperty(ref m_RightHandTurnInput, value, this);
			}
		}

		protected void OnEnable()
		{
			m_LeftHandTurnInput.EnableDirectActionIfModeUsed();
			m_RightHandTurnInput.EnableDirectActionIfModeUsed();
		}

		protected void OnDisable()
		{
			m_LeftHandTurnInput.DisableDirectActionIfModeUsed();
			m_RightHandTurnInput.DisableDirectActionIfModeUsed();
		}

		protected void Update()
		{
			if (m_TimeStarted > 0f && m_TimeStarted + m_DebounceTime < Time.time)
			{
				m_TimeStarted = 0f;
				return;
			}
			Vector2 vector = ReadInput();
			float num = GetTurnAmount(vector);
			if (Mathf.Abs(num) > 0f)
			{
				StartTurn(num);
			}
			else if (Mathf.Approximately(m_CurrentTurnAmount, 0f) && base.locomotionState == LocomotionState.Moving)
			{
				TryEndLocomotion();
			}
			if (base.locomotionState == LocomotionState.Moving && math.abs(m_CurrentTurnAmount) > 0f)
			{
				m_TimeStarted = Time.time;
				transformation.angleDelta = m_CurrentTurnAmount;
				TryQueueTransformation(transformation);
				m_CurrentTurnAmount = 0f;
				if (Mathf.Approximately(num, 0f))
				{
					TryEndLocomotion();
				}
			}
			if (vector == Vector2.zero)
			{
				m_TurnAroundActivated = false;
			}
		}

		private Vector2 ReadInput()
		{
			Vector2 vector = m_LeftHandTurnInput.ReadValue();
			Vector2 vector2 = m_RightHandTurnInput.ReadValue();
			return vector + vector2;
		}

		protected virtual float GetTurnAmount(Vector2 input)
		{
			if (input == Vector2.zero)
			{
				return 0f;
			}
			switch (CardinalUtility.GetNearestCardinal(input))
			{
			case Cardinal.South:
				if (m_EnableTurnAround && !m_TurnAroundActivated)
				{
					return 180f;
				}
				break;
			case Cardinal.East:
				if (m_EnableTurnLeftRight)
				{
					return m_TurnAmount;
				}
				break;
			case Cardinal.West:
				if (m_EnableTurnLeftRight)
				{
					return 0f - m_TurnAmount;
				}
				break;
			}
			return 0f;
		}

		protected void StartTurn(float amount)
		{
			if (m_TimeStarted > 0f)
			{
				return;
			}
			if (Mathf.Approximately(amount, 180f))
			{
				m_TurnAroundActivated = true;
			}
			if (base.locomotionState == LocomotionState.Idle)
			{
				if (m_DelayTime > 0f)
				{
					if (TryPrepareLocomotion())
					{
						m_DelayStartTime = Time.time;
					}
				}
				else
				{
					TryStartLocomotionImmediately();
				}
			}
			if (math.abs(amount) > 0f)
			{
				m_CurrentTurnAmount = amount;
			}
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Locomotion.Teleportation
