				return m_InAirJumpCount;
			}
			set
			{
				m_InAirJumpCount = Mathf.Max(0, value);
				m_CurrentInAirJumpCount = m_InAirJumpCount;
			}
		}

		public float jumpForgivenessWindow
		{
			get
			{
				return m_JumpForgivenessWindow;
			}
			set
