			}
		}

		public XROriginMovement transformation { get; set; } = new XROriginMovement();

		public bool isJumping => m_IsJumping;

		public bool canProcess => base.isActiveAndEnabled;

		public bool gravityPaused { get; protected set; }

		protected virtual void OnValidate()
		{
			m_InAirJumpCount = Mathf.Max(0, m_InAirJumpCount);
		}

		protected override void Awake()
		{
			base.Awake();
			m_HasGravityProvider = ComponentLocatorUtility<GravityProvider>.TryFindComponent(out m_GravityProvider);
			if (!m_HasGravityProvider)
			{
				Debug.LogError("Could not find Gravity Provider component which is required by the Jump Provider component. Disabling component.", this);
				base.enabled = false;
			}
		}

		protected virtual void OnEnable()
		{
			m_JumpInput.EnableDirectActionIfModeUsed();
			m_CurrentInAirJumpCount = m_InAirJumpCount;
		}

		protected virtual void OnDisable()
		{
			m_JumpInput.DisableDirectActionIfModeUsed();
		}

		protected virtual void Update()
		{
			CheckJump();
		}

		private void CheckJump()
		{
			if (m_HasGravityProvider)
			{
				if (m_CurrentJumpForgivenessWindowTime > 0f)
				{
					m_CurrentJumpForgivenessWindowTime -= Time.deltaTime;
				}
				if (m_HasJumped && m_JumpInput.ReadWasCompletedThisFrame())
				{
					m_HasJumped = false;
				}
				if (!m_HasJumped && m_JumpInput.ReadIsPerformed())
				{
					Jump();
				}
				if (m_IsJumping)
				{
					UpdateJump();
				}
			}
		}

		public void Jump()
		{
			if (CanJump())
			{
				if (!m_GravityProvider.isGrounded)
				{
					m_CurrentInAirJumpCount--;
				}
				m_HasJumped = true;
				m_IsJumping = true;
				m_CurrentJumpTimer = 0f;
				m_StoppingJumpTime = m_MaxJumpHoldTime;
				m_CurrentJumpForgivenessWindowTime = 0f;
				m_CurrentJumpForceThisFrame = m_JumpHeight;
				if (m_DisableGravityDuringJump)
				{
					TryLockGravity(GravityOverride.ForcedOff);
				}
				m_GravityProvider.ResetFallForce();
			}
		}

		public bool CanJump()
		{
			if (!m_UnlimitedInAirJumps && m_CurrentInAirJumpCount <= 0 && !m_GravityProvider.isGrounded)
			{
				return m_CurrentJumpForgivenessWindowTime > 0f;
			}
			return true;
		}

		private void UpdateJump()
		{
			float deltaTime = Time.deltaTime;
			ProcessJumpForce(deltaTime);
			if (m_GravityProvider.useLocalSpaceGravity)
			{
				m_JumpVector = m_CurrentJumpForceThisFrame * deltaTime * m_GravityProvider.GetCurrentUp();
			}
			else
			{
				m_JumpVector.y = m_CurrentJumpForceThisFrame * deltaTime;
			}
			TryStartLocomotionImmediately();
			if (base.locomotionState == LocomotionState.Moving)
			{
				transformation.motion = m_JumpVector;
				TryQueueTransformation(transformation);
			}
		}

		private void ProcessJumpForce(float dt)
		{
			m_CurrentJumpTimer += dt;
			if (m_StoppingJumpTime == m_MaxJumpHoldTime && (m_MaxJumpHoldTime <= 0f || (m_VariableHeightJump && m_CurrentJumpTimer > m_MinJumpHoldTime && !m_JumpInput.ReadIsPerformed())))
			{
				m_StoppingJumpTime = Mathf.Min(m_CurrentJumpTimer + m_EarlyOutDecelerationSpeed, m_MaxJumpHoldTime);
			}
			m_CurrentJumpForceThisFrame = CalculateJumpForceForFrame(Mathf.Clamp01(m_CurrentJumpTimer / m_StoppingJumpTime));
			if (m_CurrentJumpTimer >= m_StoppingJumpTime)
			{
				StopJump();
			}
		}

		private float CalculateJumpForceForFrame(float normalizedJumpTime)
		{
			float b = 5f;
			float num = 4f;
			float num2 = Mathf.Lerp(7f, b, Mathf.Clamp01(m_JumpHeight / num));
			if (m_DisableGravityDuringJump)
			{
				num2 /= 1.5f;
			}
			return (1f - normalizedJumpTime) * m_JumpHeight * num2;
		}

		private void StopJump()
		{
			m_IsJumping = false;
			if (m_DisableGravityDuringJump)
			{
				RemoveGravityLock();
			}
		}

		private void StartCoyoteTimer()
		{
			m_CurrentJumpForgivenessWindowTime = m_JumpForgivenessWindow;
		}

		public bool IsPausingGravity()
		{
			if (m_IsJumping)
			{
				return m_DisableGravityDuringJump;
			}
			return false;
		}

		public bool TryLockGravity(GravityOverride gravityOverride)
		{
			if (m_GravityProvider != null)
			{
				return m_GravityProvider.TryLockGravity(this, gravityOverride);
			}
			return false;
		}

		public void RemoveGravityLock()
		{
			if (m_GravityProvider != null)
			{
				m_GravityProvider.UnlockGravity(this);
			}
		}

		void IGravityController.OnGroundedChanged(bool isGrounded)
		{
			OnGroundedChanged(isGrounded);
		}

		void IGravityController.OnGravityLockChanged(GravityOverride gravityOverride)
		{
			OnGravityLockChanged(gravityOverride);
		}

		protected virtual void OnGroundedChanged(bool isGrounded)
		{
			gravityPaused = false;
			if (!base.isActiveAndEnabled)
			{
				return;
			}
			if (!isGrounded)
			{
				if (!m_IsJumping)
				{
					StartCoyoteTimer();
				}
				return;
			}
			m_CurrentJumpForgivenessWindowTime = 0f;
			m_JumpVector = Vector3.zero;
			m_CurrentInAirJumpCount = m_InAirJumpCount;
			if (m_IsJumping)
			{
				StopJump();
			}
		}

		protected virtual void OnGravityLockChanged(GravityOverride gravityOverride)
		{
			if (gravityOverride == GravityOverride.ForcedOn)
			{
				gravityPaused = false;
			}
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Locomotion.Gravity
{
	public enum GravityOverride
	{
		ForcedOff,
		ForcedOn
	}
	[AddComponentMenu("XR/Locomotion/Gravity Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Gravity.GravityProvider.html")]
	[DefaultExecutionOrder(-207)]
	public class GravityProvider : LocomotionProvider
	{
		[SerializeField]
		[Tooltip("Apply gravity to the XR Origin.")]
		private bool m_UseGravity = true;

		[SerializeField]
		[Tooltip("Apply gravity based on the current Up vector of the XR Origin.")]
		private bool m_UseLocalSpaceGravity = true;

		[SerializeField]
		[Tooltip("Determines the maximum fall speed based on units per second.")]
		private float m_TerminalVelocity = 90f;

		[SerializeField]
		[Tooltip("Determines the speed at which a player reaches max gravity velocity.")]
		private float m_GravityAccelerationModifier = 1f;

		[SerializeField]
		[Tooltip("Sets the center of the character controller to match the local x and z positions of the player camera.")]
		private bool m_UpdateCharacterControllerCenterEachFrame = true;

		[SerializeField]
		[Tooltip("Buffer for the radius of the sphere cast used to check if the player is grounded.")]
		private float m_SphereCastRadius = 0.09f;

		[SerializeField]
		[Tooltip("Buffer for the distance of the sphere cast used to check if the player is grounded.")]
		private float m_SphereCastDistanceBuffer = -0.05f;

		[SerializeField]
		[Tooltip("The layer mask used for the sphere cast to check if the player is grounded.")]
		private LayerMask m_SphereCastLayerMask = -5;

		[SerializeField]
		[Tooltip("Whether trigger colliders are considered when using a sphere cast to determine if grounded. Use Global refers to the Queries Hit Triggers setting in Physics Project Settings.")]
		private QueryTriggerInteraction m_SphereCastTriggerInteraction = QueryTriggerInteraction.Ignore;

		[Tooltip("Event that is called when gravity lock is changed.")]
		[SerializeField]
		private UnityEvent<GravityOverride> m_OnGravityLockChanged = new UnityEvent<GravityOverride>();

		[Tooltip("Callback for anytime the grounded state changes.")]
		[SerializeField]
		private UnityEvent<bool> m_OnGroundedChanged = new UnityEvent<bool>();

		private bool m_IsGrounded;

		private readonly List<IGravityController> m_GravityControllers = new List<IGravityController>();

		private Transform m_HeadTransform;

		private readonly RaycastHit[] m_GroundedAllocHits = new RaycastHit[1];

		private Vector3 m_CurrentFallVelocity;

		private PhysicsScene m_LocalPhysicsScene;

		private CharacterController m_CharacterController;

		private bool m_AttemptedGetCharacterController;

		private readonly List<IGravityController> m_GravityForcedOnProviders = new List<IGravityController>();

		private readonly List<IGravityController> m_GravityForcedOffProviders = new List<IGravityController>();

		public bool useGravity
		{
			get
			{
				return m_UseGravity;
			}
			set
			{
				m_UseGravity = value;
			}
		}

		public bool useLocalSpaceGravity
		{
			get
