		}
	}
	[AddComponentMenu("XR/Locomotion/Tunneling Vignette Controller", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Comfort.TunnelingVignetteController.html")]
	[MovedFrom("UnityEngine.XR.Interaction.Toolkit")]
	public class TunnelingVignetteController : MonoBehaviour
	{
		private static class ShaderPropertyLookup
		{
			public static readonly int apertureSize = Shader.PropertyToID("_ApertureSize");

			public static readonly int featheringEffect = Shader.PropertyToID("_FeatheringEffect");

			public static readonly int vignetteColor = Shader.PropertyToID("_VignetteColor");

			public static readonly int vignetteColorBlend = Shader.PropertyToID("_VignetteColorBlend");
		}

		private class ProviderRecord
		{
			public ITunnelingVignetteProvider provider { get; }

			public EaseState easeState { get; set; }

			public float dynamicApertureSize { get; set; } = 1f;

			public bool easeInLockEnded { get; set; }

			public float dynamicEaseOutDelayTime { get; set; }

			public ProviderRecord(ITunnelingVignetteProvider provider)
			{
				this.provider = provider;
			}
		}

		private const string k_DefaultShader = "VR/TunnelingVignette";

		[SerializeField]
		private VignetteParameters m_DefaultParameters = new VignetteParameters();

		[SerializeField]
		private VignetteParameters m_CurrentParameters = new VignetteParameters();

		[SerializeField]
		private List<LocomotionVignetteProvider> m_LocomotionVignetteProviders = new List<LocomotionVignetteProvider>();

		private readonly List<ProviderRecord> m_ProviderRecords = new List<ProviderRecord>();

		private MeshRenderer m_MeshRender;

		private MeshFilter m_MeshFilter;

		private Material m_SharedMaterial;

		private MaterialPropertyBlock m_VignettePropertyBlock;

		public VignetteParameters defaultParameters
		{
			get
			{
				return m_DefaultParameters;
			}
			set
			{
				m_DefaultParameters = value;
			}
		}

		public VignetteParameters currentParameters => m_CurrentParameters;

		public List<LocomotionVignetteProvider> locomotionVignetteProviders
		{
			get
			{
				return m_LocomotionVignetteProviders;
			}
			set
			{
				m_LocomotionVignetteProviders = value;
			}
		}

		internal static event Action<ITunnelingVignetteProvider> vignetteProviderQueued;

		public void BeginTunnelingVignette(ITunnelingVignetteProvider provider)
		{
			foreach (ProviderRecord providerRecord in m_ProviderRecords)
			{
				if (providerRecord.provider == provider)
				{
					providerRecord.easeState = EaseState.EasingIn;
					return;
				}
			}
			m_ProviderRecords.Add(new ProviderRecord(provider)
			{
				easeState = EaseState.EasingIn
			});
			TunnelingVignetteController.vignetteProviderQueued?.Invoke(provider);
		}

		public void EndTunnelingVignette(ITunnelingVignetteProvider provider)
		{
			VignetteParameters vignetteParameters = provider.vignetteParameters ?? m_DefaultParameters;
			foreach (ProviderRecord providerRecord in m_ProviderRecords)
			{
				if (providerRecord.provider == provider)
				{
					providerRecord.easeState = ((vignetteParameters.easeInTimeLock && !providerRecord.easeInLockEnded) ? EaseState.EasingInHoldBeforeEasingOut : ((vignetteParameters.easeOutDelayTime > 0f && providerRecord.dynamicEaseOutDelayTime < vignetteParameters.easeOutDelayTime) ? EaseState.EasingOutDelay : EaseState.EasingOut));
					return;
				}
			}
			EaseState easeState = (vignetteParameters.easeInTimeLock ? EaseState.EasingInHoldBeforeEasingOut : ((vignetteParameters.easeOutDelayTime > 0f) ? EaseState.EasingOutDelay : EaseState.EasingOut));
			m_ProviderRecords.Add(new ProviderRecord(provider)
			{
				easeState = easeState
			});
		}

		[Conditional("UNITY_EDITOR")]
		internal void PreviewInEditor(VignetteParameters previewParameters)
		{
			if (!Application.isPlaying && base.gameObject.activeInHierarchy)
			{
				UpdateTunnelingVignette(previewParameters);
			}
		}

		protected virtual void Awake()
		{
			m_CurrentParameters.CopyFrom(VignetteParameters.Defaults.noEffect);
			UpdateTunnelingVignette(VignetteParameters.Defaults.noEffect);
		}

		[Conditional("UNITY_EDITOR")]
		protected virtual void Reset()
		{
			m_DefaultParameters.CopyFrom(VignetteParameters.Defaults.defaultEffect);
			m_CurrentParameters.CopyFrom(VignetteParameters.Defaults.noEffect);
			UpdateTunnelingVignette(m_DefaultParameters);
		}

		protected virtual void Update()
		{
			if (m_LocomotionVignetteProviders.Count > 0)
			{
				foreach (LocomotionVignetteProvider locomotionVignetteProvider in m_LocomotionVignetteProviders)
				{
					LocomotionProvider locomotionProvider = locomotionVignetteProvider.locomotionProvider;
					if (locomotionVignetteProvider.enabled && !(locomotionProvider == null))
					{
						if (locomotionProvider.isLocomotionActive)
						{
							BeginTunnelingVignette(locomotionVignetteProvider);
						}
						else if (locomotionProvider.locomotionState == LocomotionState.Ended)
						{
							EndTunnelingVignette(locomotionVignetteProvider);
						}
					}
				}
			}
			if (m_ProviderRecords.Count == 0)
			{
				return;
			}
			foreach (ProviderRecord providerRecord2 in m_ProviderRecords)
			{
				VignetteParameters vignetteParameters = providerRecord2.provider.vignetteParameters ?? m_DefaultParameters;
				float dynamicApertureSize = providerRecord2.dynamicApertureSize;
				switch (providerRecord2.easeState)
				{
				case EaseState.NotEasing:
					providerRecord2.dynamicApertureSize = 1f;
					providerRecord2.dynamicEaseOutDelayTime = 0f;
					providerRecord2.easeInLockEnded = false;
					continue;
				case EaseState.EasingIn:
				{
					float num3 = Mathf.Max(vignetteParameters.easeInTime, 0f);
					float apertureSize2 = vignetteParameters.apertureSize;
					providerRecord2.easeInLockEnded = false;
					if (num3 > 0f && dynamicApertureSize > apertureSize2)
					{
						float num4 = dynamicApertureSize + (apertureSize2 - 1f) / num3 * Time.unscaledDeltaTime;
						providerRecord2.dynamicApertureSize = ((num4 < apertureSize2) ? apertureSize2 : num4);
					}
					else
					{
						providerRecord2.dynamicApertureSize = apertureSize2;
					}
					continue;
				}
				case EaseState.EasingInHoldBeforeEasingOut:
					if (!providerRecord2.easeInLockEnded)
					{
						float num = Mathf.Max(vignetteParameters.easeInTime, 0f);
						float apertureSize = vignetteParameters.apertureSize;
						if (num > 0f && dynamicApertureSize > apertureSize)
						{
							float num2 = dynamicApertureSize + (apertureSize - 1f) / num * Time.unscaledDeltaTime;
							providerRecord2.dynamicApertureSize = ((num2 < apertureSize) ? apertureSize : num2);
							continue;
						}
						providerRecord2.easeInLockEnded = true;
						if (!(vignetteParameters.easeOutDelayTime > 0f) || !(providerRecord2.dynamicEaseOutDelayTime < vignetteParameters.easeOutDelayTime))
						{
							providerRecord2.easeState = EaseState.EasingOut;
							break;
						}
						providerRecord2.easeState = EaseState.EasingOutDelay;
					}
					else
					{
						if (!(vignetteParameters.easeOutDelayTime > 0f))
						{
							providerRecord2.easeState = EaseState.EasingOutDelay;
							break;
						}
						providerRecord2.easeState = EaseState.EasingOutDelay;
					}
					goto case EaseState.EasingOutDelay;
				case EaseState.EasingOutDelay:
				{
					float dynamicEaseOutDelayTime = providerRecord2.dynamicEaseOutDelayTime;
					float num5 = Mathf.Max(vignetteParameters.easeOutDelayTime, 0f);
					if (num5 > 0f && dynamicEaseOutDelayTime < num5)
					{
						dynamicEaseOutDelayTime += Time.unscaledDeltaTime;
						providerRecord2.dynamicEaseOutDelayTime = ((dynamicEaseOutDelayTime > num5) ? num5 : dynamicEaseOutDelayTime);
					}
					if (!(providerRecord2.dynamicEaseOutDelayTime >= num5))
					{
						continue;
					}
					providerRecord2.easeState = EaseState.EasingOut;
					break;
				}
				case EaseState.EasingOut:
					break;
				default:
					continue;
				}
				float num6 = Mathf.Max(vignetteParameters.easeOutTime, 0f);
				float apertureSize3 = vignetteParameters.apertureSize;
				if (num6 > 0f && dynamicApertureSize < 1f)
				{
					float num7 = dynamicApertureSize + (1f - apertureSize3) / num6 * Time.unscaledDeltaTime;
					providerRecord2.dynamicApertureSize = ((num7 > 1f) ? 1f : num7);
				}
				else
				{
					providerRecord2.dynamicApertureSize = 1f;
				}
				if (providerRecord2.dynamicApertureSize >= 1f)
				{
					providerRecord2.easeState = EaseState.NotEasing;
				}
			}
			float num8 = 1f;
			ProviderRecord providerRecord = null;
			foreach (ProviderRecord providerRecord3 in m_ProviderRecords)
			{
				float dynamicApertureSize2 = providerRecord3.dynamicApertureSize;
				if (dynamicApertureSize2 < num8)
				{
					providerRecord = providerRecord3;
					num8 = dynamicApertureSize2;
				}
			}
			if (providerRecord != null)
			{
				m_CurrentParameters.CopyFrom(providerRecord.provider.vignetteParameters ?? m_DefaultParameters);
			}
			m_CurrentParameters.apertureSize = num8;
			UpdateTunnelingVignette(m_CurrentParameters);
		}

		private void UpdateTunnelingVignette(VignetteParameters parameters)
		{
			if (parameters == null)
			{
				parameters = m_DefaultParameters;
			}
			if (TrySetUpMaterial())
			{
				m_MeshRender.GetPropertyBlock(m_VignettePropertyBlock);
				m_VignettePropertyBlock.SetFloat(ShaderPropertyLookup.apertureSize, parameters.apertureSize);
				m_VignettePropertyBlock.SetFloat(ShaderPropertyLookup.featheringEffect, parameters.featheringEffect);
				m_VignettePropertyBlock.SetColor(ShaderPropertyLookup.vignetteColor, parameters.vignetteColor);
				m_VignettePropertyBlock.SetColor(ShaderPropertyLookup.vignetteColorBlend, parameters.vignetteColorBlend);
				m_MeshRender.SetPropertyBlock(m_VignettePropertyBlock);
			}
			Transform transform = base.transform;
			Vector3 localPosition = transform.localPosition;
			if (!Mathf.Approximately(localPosition.y, parameters.apertureVerticalPosition))
			{
				localPosition.y = parameters.apertureVerticalPosition;
				transform.localPosition = localPosition;
			}
		}

		private bool TrySetUpMaterial()
		{
			if (m_MeshRender == null)
			{
				m_MeshRender = GetComponent<MeshRenderer>();
			}
			if (m_MeshRender == null)
			{
				m_MeshRender = base.gameObject.AddComponent<MeshRenderer>();
			}
			if (m_VignettePropertyBlock == null)
			{
				m_VignettePropertyBlock = new MaterialPropertyBlock();
			}
			if (m_MeshFilter == null)
			{
				m_MeshFilter = GetComponent<MeshFilter>();
			}
			if (m_MeshFilter == null)
			{
				m_MeshFilter = base.gameObject.AddComponent<MeshFilter>();
			}
			if (m_MeshFilter.sharedMesh == null)
			{
				Debug.LogWarning("The default mesh for the TunnelingVignetteController is not set. Make sure to import it from the Tunneling Vignette Sample of XR Interaction Toolkit.", this);
				return false;
			}
			if (m_MeshRender.sharedMaterial == null)
			{
				Shader shader = Shader.Find("VR/TunnelingVignette");
				if (shader == null)
				{
					Debug.LogWarning("The default material for the TunnelingVignetteController is not set, and the default Shader: VR/TunnelingVignette cannot be found. Make sure they are imported from the Tunneling Vignette Sample of XR Interaction Toolkit.", this);
					return false;
				}
				Debug.LogWarning("The default material for the TunnelingVignetteController is not set. Make sure it is imported from the Tunneling Vignette Sample of XR Interaction Toolkit. + Try creating a material using the default Shader: VR/TunnelingVignette", this);
				m_SharedMaterial = new Material(shader)
				{
					name = "DefaultTunnelingVignette"
				};
				m_MeshRender.sharedMaterial = m_SharedMaterial;
			}
			else
			{
				m_SharedMaterial = m_MeshRender.sharedMaterial;
			}
			return true;
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Locomotion.Climbing
{
	[SelectionBase]
	[DisallowMultipleComponent]
	[RequireComponent(typeof(Rigidbody))]
	[AddComponentMenu("XR/Climb Interactable", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Climbing.ClimbInteractable.html")]
	[MovedFrom("UnityEngine.XR.Interaction.Toolkit")]
	public class ClimbInteractable : XRBaseInteractable
	{
		private const float k_DefaultMaxInteractionDistance = 0.1f;

		[SerializeField]
		[Tooltip("The climb provider that performs locomotion while this interactable is selected. If no climb provider is configured, will attempt to find one.")]
		private ClimbProvider m_ClimbProvider;

		[SerializeField]
		[Tooltip("Transform that defines the coordinate space for climb locomotion. Will use this GameObject's Transform by default.")]
		private Transform m_ClimbTransform;

		[SerializeField]
		[Tooltip("Controls whether to apply a distance check when validating hover and select interaction.")]
		private bool m_FilterInteractionByDistance = true;

		[SerializeField]
		[Tooltip("The maximum distance that an interactor can be from this interactable to begin hover or select.")]
		private float m_MaxInteractionDistance = 0.1f;

		[SerializeField]
		[Tooltip("The teleport volume used to assist with movement to a specific destination after ending a climb (optional, may be None). Only used if there is a Climb Teleport Interactor in the scene.")]
		private TeleportationMultiAnchorVolume m_ClimbAssistanceTeleportVolume;

		[SerializeField]
		[Tooltip("Optional override of locomotion settings specified in the climb provider. Only applies as an override if set to Use Value or if the asset reference is set.")]
		private ClimbSettingsDatumProperty m_ClimbSettingsOverride;

		public ClimbProvider climbProvider
		{
			get
			{
				return m_ClimbProvider;
			}
			set
			{
				m_ClimbProvider = value;
			}
		}

		public Transform climbTransform
		{
			get
			{
				if (m_ClimbTransform == null)
				{
					m_ClimbTransform = base.transform;
				}
				return m_ClimbTransform;
			}
			set
			{
				m_ClimbTransform = value;
			}
		}

		public bool filterInteractionByDistance
		{
			get
			{
				return m_FilterInteractionByDistance;
			}
			set
			{
				m_FilterInteractionByDistance = value;
			}
		}

		public float maxInteractionDistance
		{
			get
			{
				return m_MaxInteractionDistance;
			}
			set
			{
				m_MaxInteractionDistance = value;
			}
		}

		public TeleportationMultiAnchorVolume climbAssistanceTeleportVolume
		{
			get
			{
				return m_ClimbAssistanceTeleportVolume;
			}
			set
			{
				m_ClimbAssistanceTeleportVolume = value;
			}
		}

		public ClimbSettingsDatumProperty climbSettingsOverride
		{
			get
			{
				return m_ClimbSettingsOverride;
			}
			set
			{
				m_ClimbSettingsOverride = value;
			}
		}

		protected virtual void OnValidate()
		{
			if (m_ClimbTransform == null)
			{
				m_ClimbTransform = base.transform;
			}
		}

		protected override void Reset()
		{
			base.selectMode = InteractableSelectMode.Multiple;
			m_ClimbTransform = base.transform;
		}

		protected override void Awake()
		{
			base.Awake();
			if (m_ClimbProvider == null)
			{
				ComponentLocatorUtility<ClimbProvider>.TryFindComponent(out m_ClimbProvider, limitTryFindPerFrame: true);
			}
		}

		public override bool IsHoverableBy(IXRHoverInteractor interactor)
		{
			if (base.IsHoverableBy(interactor))
			{
				if (m_FilterInteractionByDistance)
				{
					return GetDistanceSqrToInteractor(interactor) <= m_MaxInteractionDistance * m_MaxInteractionDistance;
				}
				return true;
			}
			return false;
		}

		public override bool IsSelectableBy(IXRSelectInteractor interactor)
		{
			if (base.IsSelectableBy(interactor))
			{
				if (!IsSelected(interactor) && m_FilterInteractionByDistance)
				{
					return GetDistanceSqrToInteractor(interactor) <= m_MaxInteractionDistance * m_MaxInteractionDistance;
				}
				return true;
			}
			return false;
		}

		protected override void OnSelectEntered(SelectEnterEventArgs args)
		{
			base.OnSelectEntered(args);
			if (m_ClimbProvider != null || ComponentLocatorUtility<ClimbProvider>.TryFindComponent(out m_ClimbProvider))
			{
				m_ClimbProvider.StartClimbGrab(this, args.interactorObject);
			}
		}

		protected override void OnSelectExited(SelectExitEventArgs args)
		{
			base.OnSelectExited(args);
			if (m_ClimbProvider != null)
			{
				m_ClimbProvider.FinishClimbGrab(args.interactorObject);
			}
		}
	}
	[AddComponentMenu("XR/Locomotion/Climb Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Locomotion.Climbing.ClimbProvider.html")]
	[MovedFrom("UnityEngine.XR.Interaction.Toolkit")]
	public class ClimbProvider : LocomotionProvider, IGravityController
	{
		[SerializeField]
		[Tooltip("List of providers to disable while climb locomotion is active. If empty, no providers will be disabled by this component while climbing.")]
		private List<LocomotionProvider> m_ProvidersToDisable = new List<LocomotionProvider>();

		[SerializeField]
		[Tooltip("Whether to allow falling when climb locomotion ends. Disable to pause gravity when releasing, keeping the user from falling.")]
		private bool m_EnableGravityOnClimbEnd = true;

		[SerializeField]
		[Tooltip("Climb locomotion settings. Can be overridden by the Climb Interactable used for locomotion.")]
		private ClimbSettingsDatumProperty m_ClimbSettings = new ClimbSettingsDatumProperty(new ClimbSettings());

		private GravityProvider m_GravityProvider;

		private readonly List<IXRSelectInteractor> m_GrabbingInteractors = new List<IXRSelectInteractor>();

		private readonly List<ClimbInteractable> m_GrabbedClimbables = new List<ClimbInteractable>();

		private Vector3 m_InteractorAnchorWorldPosition;

		private Vector3 m_InteractorAnchorClimbSpacePosition;

		private List<LocomotionProvider> m_EnabledProvidersToDisable = new List<LocomotionProvider>();

		public List<LocomotionProvider> providersToDisable
		{
			get
			{
				return m_ProvidersToDisable;
			}
			set
			{
				m_ProvidersToDisable = value;
			}
		}

		public bool enableGravityOnClimbEnd
		{
			get
			{
				return m_EnableGravityOnClimbEnd;
			}
			set
			{
				m_EnableGravityOnClimbEnd = value;
			}
		}

		public ClimbSettingsDatumProperty climbSettings
		{
			get
			{
				return m_ClimbSettings;
			}
			set
			{
				m_ClimbSettings = value;
			}
		}

		public ClimbInteractable climbAnchorInteractable
		{
			get
			{
				if (m_GrabbedClimbables.Count > 0)
				{
					return m_GrabbedClimbables[m_GrabbedClimbables.Count - 1];
				}
				return null;
			}
		}

		public IXRSelectInteractor climbAnchorInteractor
		{
			get
			{
				if (m_GrabbingInteractors.Count > 0)
				{
					return m_GrabbingInteractors[m_GrabbingInteractors.Count - 1];
				}
				return null;
			}
		}

		public XROriginMovement transformation { get; set; } = new XROriginMovement();

		public bool canProcess => base.isActiveAndEnabled;

		public bool gravityPaused { get; protected set; }

		public event Action<ClimbProvider> climbAnchorUpdated;

		protected override void Awake()
		{
			base.Awake();
			if (m_ClimbSettings == null || m_ClimbSettings.Value == null)
			{
				m_ClimbSettings = new ClimbSettingsDatumProperty(new ClimbSettings());
			}
			ComponentLocatorUtility<GravityProvider>.TryFindComponent(out m_GravityProvider);
		}

		protected virtual void Update()
		{
			if (!base.isLocomotionActive)
			{
				return;
			}
			if (m_GrabbingInteractors.Count > 0)
			{
				if (base.locomotionState == LocomotionState.Preparing)
				{
					TryStartLocomotionImmediately();
				}
				int index = m_GrabbingInteractors.Count - 1;
				IXRSelectInteractor iXRSelectInteractor = m_GrabbingInteractors[index];
				ClimbInteractable climbInteractable = m_GrabbedClimbables[index];
				if (iXRSelectInteractor == null || climbInteractable == null)
				{
					FinishLocomotion();
				}
				else
				{
					StepClimbMovement(climbInteractable, iXRSelectInteractor);
				}
			}
			else
			{
				FinishLocomotion();
			}
		}

		public void StartClimbGrab(ClimbInteractable climbInteractable, IXRSelectInteractor interactor)
		{
			if (base.mediator.xrOrigin?.Origin == null)
			{
				return;
			}
			bool num = base.locomotionState == LocomotionState.Moving || base.locomotionState == LocomotionState.Preparing;
			m_GrabbingInteractors.Add(interactor);
			m_GrabbedClimbables.Add(climbInteractable);
			UpdateClimbAnchor(climbInteractable, interactor);
			TryPrepareLocomotion();
			if (!num)
			{
				TryLockGravity(GravityOverride.ForcedOff);
			}
			foreach (LocomotionProvider item in m_ProvidersToDisable)
			{
				if (!(item == null) && item.enabled)
				{
					item.enabled = false;
					m_EnabledProvidersToDisable.Add(item);
				}
			}
		}

		public void FinishClimbGrab(IXRSelectInteractor interactor)
		{
			int num = m_GrabbingInteractors.IndexOf(interactor);
			if (num >= 0)
			{
				if (num > 0 && num == m_GrabbingInteractors.Count - 1)
				{
					int index = num - 1;
					UpdateClimbAnchor(m_GrabbedClimbables[index], m_GrabbingInteractors[index]);
				}
				m_GrabbingInteractors.RemoveAt(num);
				m_GrabbedClimbables.RemoveAt(num);
			}
		}

		private void UpdateClimbAnchor(ClimbInteractable climbInteractable, IXRInteractor interactor)
		{
			Transform climbTransform = climbInteractable.climbTransform;
			m_InteractorAnchorWorldPosition = interactor.transform.position;
			m_InteractorAnchorClimbSpacePosition = climbTransform.InverseTransformPoint(m_InteractorAnchorWorldPosition);
			this.climbAnchorUpdated?.Invoke(this);
		}

		private void StepClimbMovement(ClimbInteractable currentClimbInteractable, IXRSelectInteractor currentInteractor)
		{
			ClimbSettings activeClimbSettings = GetActiveClimbSettings(currentClimbInteractable);
			bool allowFreeXMovement = activeClimbSettings.allowFreeXMovement;
			bool allowFreeYMovement = activeClimbSettings.allowFreeYMovement;
			bool allowFreeZMovement = activeClimbSettings.allowFreeZMovement;
			Vector3 position = currentInteractor.transform.position;
			Vector3 motion;
			if (allowFreeXMovement && allowFreeYMovement && allowFreeZMovement)
			{
				motion = m_InteractorAnchorWorldPosition - position;
			}
			else
			{
				Transform climbTransform = currentClimbInteractable.climbTransform;
				Vector3 vector = climbTransform.InverseTransformPoint(position);
				Vector3 vector2 = m_InteractorAnchorClimbSpacePosition - vector;
				if (!allowFreeXMovement)
				{
					vector2.x = 0f;
				}
				if (!allowFreeYMovement)
				{
					vector2.y = 0f;
				}
				if (!allowFreeZMovement)
				{
					vector2.z = 0f;
				}
				motion = climbTransform.TransformVector(vector2);
			}
			transformation.motion = motion;
			TryQueueTransformation(transformation);
		}

		private void FinishLocomotion()
		{
			TryEndLocomotion();
			m_GrabbingInteractors.Clear();
			m_GrabbedClimbables.Clear();
			RemoveGravityLock();
			gravityPaused = !m_EnableGravityOnClimbEnd;
			foreach (LocomotionProvider item in m_EnabledProvidersToDisable)
			{
				if (!(item == null))
				{
					item.enabled = true;
				}
			}
			m_EnabledProvidersToDisable.Clear();
		}

		private ClimbSettings GetActiveClimbSettings(ClimbInteractable climbInteractable)
		{
			if (climbInteractable.climbSettingsOverride.Value != null)
			{
				return climbInteractable.climbSettingsOverride;
			}
			return m_ClimbSettings;
		}

		public bool TryLockGravity(GravityOverride gravityOverride)
		{
			if (m_GravityProvider != null)
			{
				return m_GravityProvider.TryLockGravity(this, gravityOverride);
			}
			return false;
		}

		public void RemoveGravityLock()
		{
			if (m_GravityProvider != null)
			{
				m_GravityProvider.UnlockGravity(this);
			}
		}

		void IGravityController.OnGroundedChanged(bool isGrounded)
		{
			OnGroundedChanged(isGrounded);
		}

		void IGravityController.OnGravityLockChanged(GravityOverride gravityOverride)
		{
			OnGravityLockChanged(gravityOverride);
		}

		protected virtual void OnGroundedChanged(bool isGrounded)
		{
			gravityPaused = false;
		}

		protected virtual void OnGravityLockChanged(GravityOverride gravityOverride)
		{
			if (gravityOverride == GravityOverride.ForcedOn)
			{
				gravityPaused = false;
			}
		}
	}
