						if (m_HasLineVisual)
						{
							m_LineVisual.enabled = true;
						}
						return true;
					}
					if (m_HasLineVisual && !m_TeleportRay)
					{
						m_LineVisual.enabled = false;
					}
				}
				return false;
			}

			internal void RestoreVisuals()
			{
				if (m_RestoreVisuals && m_HasLineVisual && !fallback)
				{
					m_LineVisual.enabled = true;
				}
				m_RestoreVisuals = false;
			}
		}

