	[Serializable]
	public class XRAngleGazeEvaluator : XRTargetEvaluator
	{
		[Tooltip("The Transform whose forward direction is used to evaluate the target Interactable angle. If none is specified, during OnEnable this property is initialized with the XROrigin Camera.")]
		[SerializeField]
		private Transform m_GazeTransform;

		[Tooltip("The maximum value an angle can be evaluated as before the Interactor receives a normalized score of 0. Think of it as a field-of-view angle.")]
		[SerializeField]
		[Range(0f, 180f)]
		private float m_MaxAngle = 60f;

		public Transform gazeTransform
		{
			get
			{
				return m_GazeTransform;
			}
			set
			{
				m_GazeTransform = value;
			}
		}

		public float maxAngle
		{
			get
			{
				return m_MaxAngle;
			}
			set
			{
				m_MaxAngle = Mathf.Clamp(value, 0f, 180f);
			}
		}

		private static Camera GetXROriginCamera()
		{
			if (!ComponentLocatorUtility<XROrigin>.TryFindComponent(out var component))
			{
				return null;
			}
			return component.Camera;
		}

		private void InitializeGazeTransform()
		{
			Camera xROriginCamera = GetXROriginCamera();
			if (xROriginCamera != null && xROriginCamera.enabled && xROriginCamera.gameObject.activeInHierarchy)
			{
				m_GazeTransform = xROriginCamera.transform;
			}
			else
			{
				Debug.LogWarning("Couldn't find an active XROrigin Camera for XRAngleGazeEvaluator", base.filter);
			}
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			if (m_GazeTransform == null)
			{
				InitializeGazeTransform();
			}
		}

		public override void Reset()
		{
			base.Reset();
			InitializeGazeTransform();
		}

		protected override float CalculateNormalizedScore(IXRInteractor interactor, IXRInteractable target)
		{
			Transform transform = gazeTransform;
			if (transform == null || m_MaxAngle <= 0f)
			{
				return 0f;
			}
			Vector3 vector;
			if (target is XRBaseInteractable xRBaseInteractable)
			{
				vector = xRBaseInteractable.GetDistance(transform.position).point;
			}
			else
			{
				Transform transform2 = target.transform;
				if (transform2 == null)
				{
					return 0f;
				}
				vector = transform2.position;
			}
			float num = Vector3.Angle(vector - transform.position, transform.forward) * 2f / m_MaxAngle;
			return 1f - num;
		}
	}
	[Serializable]
	public class XRDistanceEvaluator : XRTargetEvaluator
	{
		[Tooltip("The maximum distance from the Interactor. Any target from this distance will receive a 0 normalized score.")]
		[SerializeField]
		private float m_MaxDistance = 1f;

		public float maxDistance
		{
			get
			{
				return m_MaxDistance;
			}
			set
			{
				m_MaxDistance = value;
			}
		}

		public override void Reset()
		{
			base.Reset();
			base.weight = new AnimationCurve(new Keyframe(0f, 0f, 0f, 0.5f), new Keyframe(1f, 1f, 2f, 2f));
		}

		protected override float CalculateNormalizedScore(IXRInteractor interactor, IXRInteractable target)
		{
			if (Mathf.Approximately(m_MaxDistance, 0f))
			{
				return 0f;
			}
			using (new XRInteractableUtility.AllowTriggerCollidersScope(newAllowTriggerColliders: true))
			{
				return 1f - Mathf.Clamp01(target.GetDistanceSqrToInteractor(interactor) / (m_MaxDistance * m_MaxDistance));
			}
		}
	}
	[Serializable]
	public class XRLastSelectedEvaluator : XRTargetEvaluator, IXRTargetEvaluatorLinkable
	{
		private readonly Dictionary<IXRInteractable, float> m_InteractableSelectionTimeMap = new Dictionary<IXRInteractable, float>();

		[Tooltip("Any Interactable which was last selected over Max Time seconds ago will receive a normalized score of 0.")]
		[SerializeField]
		private float m_MaxTime = 10f;

		public float maxTime
		{
			get
			{
				return m_MaxTime;
			}
			set
			{
				m_MaxTime = value;
			}
		}

		private void OnSelect(SelectEnterEventArgs args)
		{
			if (base.enabled)
			{
				IXRInteractable interactableObject = args.interactableObject;
				if (interactableObject != null)
				{
					m_InteractableSelectionTimeMap[interactableObject] = Time.time;
				}
			}
		}

		public virtual void OnLink(IXRInteractor interactor)
		{
			if (interactor is IXRSelectInteractor iXRSelectInteractor)
			{
				iXRSelectInteractor.selectEntered.AddListener(OnSelect);
			}
		}

		public virtual void OnUnlink(IXRInteractor interactor)
		{
			if (interactor is IXRSelectInteractor iXRSelectInteractor)
			{
				iXRSelectInteractor.selectEntered.RemoveListener(OnSelect);
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			m_InteractableSelectionTimeMap.Clear();
		}

		protected override float CalculateNormalizedScore(IXRInteractor interactor, IXRInteractable target)
		{
			if (!m_InteractableSelectionTimeMap.TryGetValue(target, out var value) || m_MaxTime <= 0f)
			{
				return 0.5f;
			}
			return (1f - Mathf.Clamp01((Time.time - value) / m_MaxTime)) * 0.5f + 0.5f;
		}
	}
	[Serializable]
	public abstract class XRTargetEvaluator : IDisposable
	{
		[HideInInspector]
		[SerializeField]
		private XRTargetFilter m_Filter;

		[HideInInspector]
		[SerializeField]
		[XRTargetEvaluatorEnabled]
		private bool m_Enabled = true;

		[Tooltip("The weight curve of this evaluator. Use this curve to configure the returned score.\n\nThe x-axis is the normalized score (calculated in CalculateNormalizedScore) and the y-axis is the returned score of this evaluator.")]
		[SerializeField]
		private AnimationCurve m_Weight;

		private bool m_IsAwake;

		private bool m_IsEnabled;

		private bool m_IsRegistered;

		public XRTargetFilter filter => m_Filter;

		public bool enabled
		{
			get
			{
				return m_Enabled;
			}
			set
			{
				if (m_Enabled == value || disposed)
				{
					return;
				}
				if (m_Filter.isProcessing && !value)
				{
					throw new InvalidOperationException("Cannot disable an evaluator " + GetType().Name + " while its filter " + m_Filter.name + " is processing.");
				}
				m_Enabled = value;
				if (m_IsAwake && m_Filter.isActiveAndEnabled)
				{
					if (value)
					{
						EnableInternal();
					}
					else
					{
						DisableInternal();
					}
				}
			}
		}

		public AnimationCurve weight
		{
			get
			{
				return m_Weight;
			}
			set
			{
				m_Weight = value;
			}
		}

		public bool disposed => m_Filter == null;

		internal static bool IsInstanceType(Type evaluatorType)
		{
			if (evaluatorType != null && !evaluatorType.IsInterface && !evaluatorType.IsAbstract && !evaluatorType.IsGenericType)
			{
				return typeof(XRTargetEvaluator).IsAssignableFrom(evaluatorType);
			}
			return false;
		}

		internal static XRTargetEvaluator CreateInstance(Type evaluatorType, XRTargetFilter filter)
		{
			if (!IsInstanceType(evaluatorType) || !(Activator.CreateInstance(evaluatorType) is XRTargetEvaluator xRTargetEvaluator))
			{
				return null;
			}
			xRTargetEvaluator.m_Filter = filter;
			xRTargetEvaluator.m_Weight = AnimationCurve.Linear(0f, 0f, 1f, 1f);
			return xRTargetEvaluator;
		}

		private void RegisterHandlers()
		{
			if (!m_IsRegistered && !disposed)
			{
				m_IsRegistered = true;
				m_Filter.RegisterEvaluatorHandlers(this);
			}
		}

		private void UnregisterHandlers()
		{
			if (m_IsRegistered && !disposed)
			{
				m_IsRegistered = false;
				m_Filter.UnregisterEvaluatorHandlers(this);
			}
		}

		internal void AwakeInternal()
		{
			if (!m_IsAwake && !disposed)
			{
				m_IsAwake = true;
				Awake();
				RegisterHandlers();
			}
		}

		internal void DisposeInternal()
		{
			if (m_IsAwake)
			{
				m_IsAwake = false;
				UnregisterHandlers();
				OnDispose();
				m_Filter = null;
			}
		}

		internal void EnableInternal()
		{
			if (!m_IsEnabled && !disposed)
			{
				m_IsEnabled = true;
				OnEnable();
			}
		}

		internal void DisableInternal()
		{
			if (m_IsEnabled)
			{
				m_IsEnabled = false;
				OnDisable();
			}
		}

		protected virtual void Awake()
		{
		}

		protected virtual void OnDispose()
		{
		}

		protected virtual void OnEnable()
		{
		}

		protected virtual void OnDisable()
		{
		}

		public virtual void Reset()
		{
		}

		public float GetWeightedScore(IXRInteractor interactor, IXRInteractable target)
		{
			return m_Weight.Evaluate(CalculateNormalizedScore(interactor, target));
		}

		protected abstract float CalculateNormalizedScore(IXRInteractor interactor, IXRInteractable target);

		public void Dispose()
		{
			if (m_Filter != null)
			{
				m_Filter.RemoveEvaluator(this);
			}
		}
	}
	public interface IXRTargetFilter
	{
		bool canProcess { get; }

		void Link(IXRInteractor interactor);

		void Unlink(IXRInteractor interactor);

		void Process(IXRInteractor interactor, List<IXRInteractable> targets, List<IXRInteractable> results);
	}
	public abstract class XRBaseTargetFilter : MonoBehaviour, IXRTargetFilter
	{
		public virtual bool canProcess => base.isActiveAndEnabled;

		public virtual void Link(IXRInteractor interactor)
		{
		}

		public virtual void Unlink(IXRInteractor interactor)
		{
		}

		public abstract void Process(IXRInteractor interactor, List<IXRInteractable> targets, List<IXRInteractable> results);
	}
	[AddComponentMenu("XR/XR Target Filter", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Filtering.XRTargetFilter.html")]
	public sealed class XRTargetFilter : XRBaseTargetFilter, IEnumerable<XRTargetEvaluator>, IEnumerable
	{
		private static readonly UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<List<XRTargetEvaluator>> s_EvaluatorListPool = new UnityEngine.XR.Interaction.Toolkit.Utilities.Pooling.LinkedPool<List<XRTargetEvaluator>>(() => new List<XRTargetEvaluator>(), null, delegate(List<XRTargetEvaluator> list)
		{
			list.Clear();
		}, null, collectionCheck: false);

		private static readonly Dictionary<IXRInteractable, float> s_InteractableFinalScoreMap = new Dictionary<IXRInteractable, float>();

		private static readonly Comparison<IXRInteractable> s_InteractableScoreComparison = InteractableScoreDescendingComparison;

		private List<IXRInteractor> m_LinkedInteractors = new List<IXRInteractor>();

		[SerializeReference]
		private List<XRTargetEvaluator> m_Evaluators = new List<XRTargetEvaluator>();

		private bool m_IsAwake;

		internal List<IXRInteractor> linkedInteractors => m_LinkedInteractors;

		internal List<XRTargetEvaluator> evaluators => m_Evaluators;

		public int evaluatorCount => m_Evaluators.Count;

		internal bool isProcessing { get; private set; }

		public override bool canProcess
		{
			get
			{
				if (!isProcessing)
				{
					return base.canProcess;
				}
				return false;
			}
		}

		public event Action<IXRInteractor> interactorLinked;

		public event Action<IXRInteractor> interactorUnlinked;

		private static int InteractableScoreDescendingComparison(IXRInteractable x, IXRInteractable y)
		{
			float num = s_InteractableFinalScoreMap[x];
			float num2 = s_InteractableFinalScoreMap[y];
			if (num < num2)
			{
				return 1;
			}
			if (num > num2)
			{
				return -1;
			}
			return 0;
		}

		private void Awake()
		{
			m_IsAwake = true;
			List<XRTargetEvaluator> v;
			using (s_EvaluatorListPool.Get(out v))
			{
				GetEvaluators(v);
				for (int i = 0; i < v.Count; i++)
				{
					if (!m_IsAwake)
					{
						break;
					}
					v[i].AwakeInternal();
				}
			}
		}

		private void OnEnable()
		{
			List<XRTargetEvaluator> v;
			using (s_EvaluatorListPool.Get(out v))
			{
				GetEvaluators(v);
				for (int i = 0; i < v.Count; i++)
				{
					if (!base.isActiveAndEnabled)
					{
						break;
					}
					XRTargetEvaluator xRTargetEvaluator = v[i];
					if (xRTargetEvaluator.enabled)
					{
						xRTargetEvaluator.EnableInternal();
					}
				}
			}
		}

		private void OnDisable()
		{
			List<XRTargetEvaluator> v;
			using (s_EvaluatorListPool.Get(out v))
			{
				GetEnabledEvaluators(v);
				for (int i = 0; i < v.Count; i++)
				{
					if (base.isActiveAndEnabled)
					{
						break;
					}
					v[i].DisableInternal();
				}
			}
		}

		private void OnDestroy()
		{
			m_IsAwake = false;
			List<XRTargetEvaluator> v;
			using (s_EvaluatorListPool.Get(out v))
			{
				GetEvaluators(v);
				foreach (XRTargetEvaluator item in v)
				{
					item.DisposeInternal();
				}
			}
		}

		private void Reset()
		{
			AddEvaluator<XRDistanceEvaluator>().Reset();
		}

		internal void RegisterEvaluatorHandlers(XRTargetEvaluator evaluator)
		{
			if (!(evaluator is IXRTargetEvaluatorLinkable iXRTargetEvaluatorLinkable))
			{
				return;
			}
			interactorLinked += iXRTargetEvaluatorLinkable.OnLink;
			interactorUnlinked += iXRTargetEvaluatorLinkable.OnUnlink;
			foreach (IXRInteractor linkedInteractor in m_LinkedInteractors)
			{
				iXRTargetEvaluatorLinkable.OnLink(linkedInteractor);
			}
		}

		internal void UnregisterEvaluatorHandlers(XRTargetEvaluator evaluator)
		{
			if (!(evaluator is IXRTargetEvaluatorLinkable iXRTargetEvaluatorLinkable))
			{
				return;
			}
			interactorLinked -= iXRTargetEvaluatorLinkable.OnLink;
			interactorUnlinked -= iXRTargetEvaluatorLinkable.OnUnlink;
			foreach (IXRInteractor linkedInteractor in m_LinkedInteractors)
			{
				iXRTargetEvaluatorLinkable.OnUnlink(linkedInteractor);
			}
		}

		public void GetLinkedInteractors(List<IXRInteractor> results)
		{
			if (results == null)
			{
				throw new ArgumentNullException("results");
			}
			results.Clear();
			results.AddRange(m_LinkedInteractors);
		}

		public void GetEvaluators(List<XRTargetEvaluator> results)
		{
			if (results == null)
			{
				throw new ArgumentNullException("results");
			}
			results.Clear();
			results.AddRange(m_Evaluators);
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return ((IEnumerable)m_Evaluators).GetEnumerator();
		}

		public IEnumerator<XRTargetEvaluator> GetEnumerator()
		{
			return m_Evaluators.GetEnumerator();
		}

		public XRTargetEvaluator GetEvaluatorAt(int index)
		{
			return m_Evaluators[index];
		}

		public XRTargetEvaluator GetEvaluator(Type type)
		{
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			foreach (XRTargetEvaluator evaluator in m_Evaluators)
			{
				if (type.IsInstanceOfType(evaluator))
				{
					return evaluator;
				}
			}
			return null;
		}

		public T GetEvaluator<T>()
		{
			return (T)(object)GetEvaluator(typeof(T));
		}

		public void GetEnabledEvaluators(List<XRTargetEvaluator> results)
		{
			if (results == null)
			{
				throw new ArgumentNullException("results");
			}
			results.Clear();
			foreach (XRTargetEvaluator evaluator in m_Evaluators)
			{
				if (evaluator.enabled)
				{
					results.Add(evaluator);
				}
			}
		}

		public XRTargetEvaluator AddEvaluator(Type evaluatorType)
		{
			if (evaluatorType == null)
			{
				throw new ArgumentNullException("evaluatorType");
			}
			XRTargetEvaluator xRTargetEvaluator = XRTargetEvaluator.CreateInstance(evaluatorType, this);
			if (xRTargetEvaluator == null)
			{
				return null;
			}
			m_Evaluators.Add(xRTargetEvaluator);
			if (m_IsAwake)
			{
				xRTargetEvaluator.AwakeInternal();
				if (base.isActiveAndEnabled && xRTargetEvaluator.enabled)
				{
					xRTargetEvaluator.EnableInternal();
				}
			}
			return xRTargetEvaluator;
		}

		public T AddEvaluator<T>() where T : XRTargetEvaluator
		{
			return AddEvaluator(typeof(T)) as T;
		}

		public void RemoveEvaluatorAt(int index)
		{
			if (isProcessing)
			{
				throw new InvalidOperationException("Cannot remove evaluators while a filter " + base.name + " is processing.");
			}
			XRTargetEvaluator xRTargetEvaluator = m_Evaluators[index];
			if (m_IsAwake && xRTargetEvaluator != null)
			{
				if (base.isActiveAndEnabled && xRTargetEvaluator.enabled)
				{
					xRTargetEvaluator.DisableInternal();
				}
				xRTargetEvaluator.DisposeInternal();
			}
			m_Evaluators.RemoveAt(index);
		}

		public void RemoveEvaluator(XRTargetEvaluator evaluator)
		{
			if (isProcessing)
			{
				throw new InvalidOperationException("Cannot remove evaluators while a filter " + base.name + " is processing.");
			}
			int num = m_Evaluators.IndexOf(evaluator);
			if (num >= 0)
			{
				RemoveEvaluatorAt(num);
			}
		}

		public void MoveEvaluatorTo(XRTargetEvaluator evaluator, int newIndex)
		{
			int num = m_Evaluators.IndexOf(evaluator);
			if (num >= 0 && num != newIndex)
			{
				m_Evaluators.RemoveAt(num);
				m_Evaluators.Insert(newIndex, evaluator);
			}
		}

		public override void Link(IXRInteractor interactor)
		{
			if (interactor == null)
			{
				throw new ArgumentNullException("interactor");
			}
			if (!m_LinkedInteractors.Contains(interactor))
			{
				m_LinkedInteractors.Add(interactor);
				this.interactorLinked?.Invoke(interactor);
			}
		}

		public override void Unlink(IXRInteractor interactor)
		{
			if (interactor == null)
			{
				throw new ArgumentNullException("interactor");
			}
			if (isProcessing)
			{
				throw new InvalidOperationException($"Cannot unlink an interactor {interactor} while the filter {base.name} is processing.");
			}
			if (m_LinkedInteractors.Remove(interactor))
			{
				this.interactorUnlinked?.Invoke(interactor);
			}
		}

		public override void Process(IXRInteractor interactor, List<IXRInteractable> targets, List<IXRInteractable> results)
		{
			if (isProcessing)
			{
				throw new InvalidOperationException("Process for filter " + base.name + " is already running, cannot start a new one.");
			}
			isProcessing = true;
			try
			{
				results.Clear();
				List<XRTargetEvaluator> v;
				using (s_EvaluatorListPool.Get(out v))
				{
					GetEnabledEvaluators(v);
					foreach (IXRInteractable target in targets)
					{
						float num = 1f;
						foreach (XRTargetEvaluator item in v)
						{
							float weightedScore = item.GetWeightedScore(interactor, target);
							num *= weightedScore;
							if (num <= 0f)
							{
								break;
							}
						}
						if (num >= 0f)
						{
							results.Add(target);
							s_InteractableFinalScoreMap[target] = num;
						}
					}
				}
				results.Sort(s_InteractableScoreComparison);
			}
			finally
			{
				isProcessing = false;
				s_InteractableFinalScoreMap.Clear();
			}
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Attachment
{
	[MovedFrom("UnityEngine.XR.Interaction.Toolkit.Interaction")]
	public class AttachPointVelocityTracker : IAttachPointVelocityTracker, IAttachPointVelocityProvider
	{
		private const int k_BufferSize = 20;

		private const float k_MinimumDeltaTime = 1E-05f;

		private readonly CircularBuffer<(Vector3 position, float time)> m_PositionTimeBuffer = new CircularBuffer<(Vector3, float)>(20);

		private readonly CircularBuffer<(Quaternion rotation, float time)> m_RotationTimeBuffer = new CircularBuffer<(Quaternion, float)>(20);

		private Vector3 m_AttachPointVelocity;

		private Vector3 m_AttachPointAngularVelocity;

		public void UpdateAttachPointVelocityData(Transform attachTransform)
		{
			UpdateAttachPointVelocityData(attachTransform, useXROriginTransform: false);
		}

		public void UpdateAttachPointVelocityData(Transform attachTransform, Transform xrOriginTransform)
		{
			UpdateAttachPointVelocityData(attachTransform, useXROriginTransform: true, xrOriginTransform);
		}

		private void UpdateAttachPointVelocityData(Transform attachTransform, bool useXROriginTransform, Transform xrOriginTransform = null)
		{
			float unscaledTime = Time.unscaledTime;
			bool num = useXROriginTransform && xrOriginTransform != null;
			Pose worldPose = attachTransform.GetWorldPose();
			Vector3 item = (num ? xrOriginTransform.InverseTransformPoint(worldPose.position) : worldPose.position);
			Quaternion item2 = (num ? (Quaternion.Inverse(xrOriginTransform.rotation) * worldPose.rotation) : worldPose.rotation);
			m_PositionTimeBuffer.Add((item, unscaledTime));
			m_RotationTimeBuffer.Add((item2, unscaledTime));
			m_AttachPointVelocity = ((m_PositionTimeBuffer.count > 1) ? CalculateVelocityWithWeightedLinearRegression() : Vector3.zero);
			m_AttachPointAngularVelocity = ((m_RotationTimeBuffer.count > 1) ? CalculateAngularVelocityWithWeightedRegression() : Vector3.zero);
		}

		private Vector3 CalculateVelocityWithWeightedLinearRegression()
		{
			int count = m_PositionTimeBuffer.count;
			if (count < 2)
			{
				return Vector3.zero;
			}
			Vector3 zero = Vector3.zero;
			float num = 0f;
			Vector3 zero2 = Vector3.zero;
			float num2 = 0f;
			float num3 = 0f;
			float item = m_PositionTimeBuffer[0].time;
			float num4 = m_PositionTimeBuffer[count - 1].time - item;
			if (num4 < 1E-05f)
			{
				if (!Mathf.Approximately(num4, 0f))
				{
					return (m_PositionTimeBuffer[count - 1].position - m_PositionTimeBuffer[0].position) / num4;
				}
				return Vector3.zero;
			}
			for (int i = 0; i < count; i++)
			{
				float num5 = m_PositionTimeBuffer[i].time - item;
				Vector3 item2 = m_PositionTimeBuffer[i].position;
				float num6 = 1f + num5 / num4;
				zero += item2 * num6;
				num += num5 * num6;
				zero2 += item2 * (num5 * num6);
				num2 += num5 * num5 * num6;
				num3 += num6;
			}
			float num7 = num3 * num2 - num * num;
			if (Mathf.Approximately(num7, 0f))
			{
				return Vector3.zero;
			}
			return (num3 * zero2 - zero * num) / num7;
		}

		private Vector3 CalculateAngularVelocityWithWeightedRegression()
		{
			int count = m_RotationTimeBuffer.count;
			if (count < 2)
			{
				return Vector3.zero;
			}
			Vector3 zero = Vector3.zero;
			float num = 0f;
			Vector3 zero2 = Vector3.zero;
			float num2 = 0f;
			float num3 = 0f;
			float item = m_RotationTimeBuffer[0].time;
			float num4 = m_RotationTimeBuffer[count - 1].time - item;
			if (num4 < 1E-05f)
			{
				return Vector3.zero;
			}
			Quaternion item2 = m_RotationTimeBuffer[0].rotation;
			for (int i = 1; i < count; i++)
			{
				float num5 = m_RotationTimeBuffer[i].time - item;
				(m_RotationTimeBuffer[i].rotation * Quaternion.Inverse(item2)).ToAngleAxis(out var angle, out var axis);
				if (angle > 180f)
				{
					angle -= 360f;
				}
				Vector3 vector = axis * (angle * (MathF.PI / 180f));
				float num6 = 1f + num5 / num4;
				zero += vector * num6;
				num += num5 * num6;
				zero2 += vector * (num5 * num6);
				num2 += num5 * num5 * num6;
				num3 += num6;
			}
			float num7 = num3 * num2 - num * num;
			if (Mathf.Approximately(num7, 0f))
			{
				return Vector3.zero;
			}
			return (num3 * zero2 - zero * num) / num7;
		}

