		private Vector2 FilterManipulationInput(in Vector2 input)
		{
			if (m_CombineManipulationAxes || m_ManipulationXAxisMode == ManipulationXAxisMode.None || m_ManipulationYAxisMode == ManipulationYAxisMode.None)
