namespace UnityEngine.XR.Interaction.Toolkit.Inputs
{
	public enum Cardinal
	{
		North,
		South,
		East,
		West
	}
	public static class CardinalUtility
	{
		public static Cardinal GetNearestCardinal(Vector2 value)
		{
			float num = Mathf.Atan2(value.y, value.x) * 57.29578f;
			float num2 = Mathf.Abs(num);
			if (num2 < 45f)
			{
				return Cardinal.East;
			}
			if (num2 > 135f)
			{
				return Cardinal.West;
			}
			if (!(num >= 0f))
			{
				return Cardinal.South;
			}
			return Cardinal.North;
		}
	}
	[AddComponentMenu("Input/Input Action Manager")]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Inputs.InputActionManager.html")]
	public class InputActionManager : MonoBehaviour
	{
		[SerializeField]
		[Tooltip("Input action assets to affect when inputs are enabled or disabled.")]
		private List<InputActionAsset> m_ActionAssets;

		public List<InputActionAsset> actionAssets
		{
			get
			{
				return m_ActionAssets;
			}
			set
			{
				m_ActionAssets = value ?? throw new ArgumentNullException("value");
			}
		}

		protected void OnEnable()
		{
			EnableInput();
		}

		protected void OnDisable()
		{
			DisableInput();
		}

		public void EnableInput()
		{
			if (m_ActionAssets == null)
			{
				return;
			}
			foreach (InputActionAsset actionAsset in m_ActionAssets)
			{
				if (actionAsset != null)
				{
					actionAsset.Enable();
				}
			}
		}

		public void DisableInput()
		{
			if (m_ActionAssets == null)
			{
				return;
			}
			foreach (InputActionAsset actionAsset in m_ActionAssets)
			{
				if (actionAsset != null)
				{
					actionAsset.Disable();
				}
			}
		}
	}
	public static class InputActionPropertyExtensions
	{
		public static void EnableDirectAction(this InputActionProperty property)
		{
			if (!(property.reference != null))
			{
				property.action?.Enable();
			}
		}

		public static void DisableDirectAction(this InputActionProperty property)
		{
			if (!(property.reference != null))
			{
				property.action?.Disable();
			}
		}
	}
	internal static class InputActionUtility
	{
		public static InputAction CreateValueAction(Type valueType, string name = null)
		{
			return new InputAction(name, InputActionType.Value, null, null, null, GetExpectedControlType(valueType));
		}

		public static InputAction CreateButtonAction(string name = null, bool wantsInitialStateCheck = false)
		{
			return new InputAction(name, InputActionType.Button)
			{
				wantsInitialStateCheck = wantsInitialStateCheck
			};
		}

		public static InputAction CreatePassThroughAction(Type valueType = null, string name = null, bool wantsInitialStateCheck = false)
		{
			return new InputAction(name, InputActionType.PassThrough, null, null, null, GetExpectedControlType(valueType))
			{
				wantsInitialStateCheck = wantsInitialStateCheck
			};
		}

		private static string GetExpectedControlType(Type valueType)
		{
			if ((object)valueType != null)
			{
				if (valueType == typeof(float))
				{
					return "Axis";
				}
				if (valueType == typeof(int) || valueType == typeof(InputTrackingState))
				{
					return "Integer";
				}
				if (valueType == typeof(Quaternion))
				{
					return "Quaternion";
				}
				if (valueType == typeof(Vector2))
				{
					return "Vector2";
				}
				if (valueType == typeof(Vector3))
				{
					return "Vector3";
				}
			}
			return null;
		}
	}
