		protected bool TryReadBoolValue(out bool value)
		{
			if (RefreshInputDeviceIfNeeded() && m_InputDevice.TryGetFeatureValue(new InputFeatureUsage<bool>(m_Usage.name), out value))
			{
				return true;
			}
			value = false;
			return false;
