		protected bool TryReadVector2Value(out Vector2 value)
		{
			if (RefreshInputDeviceIfNeeded() && m_InputDevice.TryGetFeatureValue(new InputFeatureUsage<Vector2>(m_Usage.name), out value))
			{
				return true;
			}
