		protected bool RefreshInputDeviceIfNeeded()
		{
			if (!m_InputDevice.isValid)
			{
				return XRInputTrackingAggregator.TryGetDeviceWithExactCharacteristics(m_Characteristics, out m_InputDevice);
			}
