	public abstract class XRInputValueReader
	{
		public enum InputSourceMode
		{
			Unused,
			InputAction,
			InputActionReference,
			ObjectReference,
			ManualValue
		}

		[SerializeField]
		private protected InputSourceMode m_InputSourceMode = InputSourceMode.InputActionReference;

		[SerializeField]
		private protected InputAction m_InputAction;

		[SerializeField]
		private InputActionReference m_InputActionReference;

		private readonly UnityObjectReferenceCache<InputActionReference> m_InputActionReferenceCache = new UnityObjectReferenceCache<InputActionReference>();

		public InputSourceMode inputSourceMode
		{
			get
			{
				return m_InputSourceMode;
			}
			set
			{
				m_InputSourceMode = value;
			}
		}

		public InputAction inputAction
		{
			get
			{
				return m_InputAction;
			}
			set
			{
				m_InputAction = value;
			}
		}

		public InputActionReference inputActionReference
		{
			get
			{
				return m_InputActionReference;
			}
			set
			{
				m_InputActionReference = value;
			}
		}

		protected XRInputValueReader()
		{
		}

		protected XRInputValueReader(InputAction inputAction, InputSourceMode inputSourceMode)
		{
			m_InputAction = inputAction;
			m_InputSourceMode = inputSourceMode;
		}

		public void EnableDirectActionIfModeUsed()
		{
			if (m_InputSourceMode == InputSourceMode.InputAction)
			{
				m_InputAction.Enable();
			}
		}

		public void DisableDirectActionIfModeUsed()
		{
			if (m_InputSourceMode == InputSourceMode.InputAction)
			{
				m_InputAction.Disable();
			}
		}

		private protected bool TryGetInputActionReference(out InputActionReference reference)
		{
			return m_InputActionReferenceCache.TryGet(m_InputActionReference, out reference);
		}
	}
	[Serializable]
	public class XRInputValueReader<TValue> : XRInputValueReader, IXRInputValueReader<TValue>, IXRInputValueReader where TValue : struct
	{
		private readonly struct BypassScope : IDisposable
		{
			private readonly XRInputValueReader<TValue> m_Reader;

			public BypassScope(XRInputValueReader<TValue> reader)
			{
				m_Reader = reader;
				m_Reader.m_CallingBypass = true;
			}

			public void Dispose()
			{
				m_Reader.m_CallingBypass = false;
			}
		}

		[SerializeField]
		[RequireInterface(typeof(IXRInputValueReader))]
		private Object m_ObjectReferenceObject;

		[SerializeField]
		private TValue m_ManualValue;

		private bool m_CallingBypass;

		private readonly UnityObjectReferenceCache<IXRInputValueReader<TValue>, Object> m_ObjectReference = new UnityObjectReferenceCache<IXRInputValueReader<TValue>, Object>();

		public TValue manualValue
		{
			get
			{
				return m_ManualValue;
			}
			set
			{
				m_ManualValue = value;
			}
		}

		public IXRInputValueReader<TValue> bypass { get; set; }

		public XRInputValueReader()
		{
		}

		public XRInputValueReader(string name = null, InputSourceMode inputSourceMode = InputSourceMode.InputActionReference)
			: base(InputActionUtility.CreateValueAction(typeof(TValue), name), inputSourceMode)
		{
		}

		public IXRInputValueReader<TValue> GetObjectReference()
		{
			return m_ObjectReference.Get(m_ObjectReferenceObject);
		}

		public void SetObjectReference(IXRInputValueReader<TValue> value)
		{
			m_ObjectReference.Set(ref m_ObjectReferenceObject, value);
		}

		public TValue ReadValue()
		{
			if (bypass != null && !m_CallingBypass)
			{
				using (new BypassScope(this))
				{
					return bypass.ReadValue();
				}
			}
			switch (m_InputSourceMode)
			{
			default:
				return default(TValue);
			case InputSourceMode.InputAction:
				return ReadValue(m_InputAction);
			case InputSourceMode.InputActionReference:
			{
				if (!TryGetInputActionReference(out var reference))
				{
					return default(TValue);
				}
				return ReadValue(reference.action);
			}
			case InputSourceMode.ObjectReference:
				return GetObjectReference()?.ReadValue() ?? default(TValue);
			case InputSourceMode.ManualValue:
				return m_ManualValue;
			}
		}

		public bool TryReadValue(out TValue value)
		{
			if (bypass != null && !m_CallingBypass)
			{
				using (new BypassScope(this))
				{
					return bypass.TryReadValue(out value);
				}
			}
			switch (base.inputSourceMode)
			{
			default:
				value = default(TValue);
				return false;
			case InputSourceMode.InputAction:
				return TryReadValue(m_InputAction, out value);
			case InputSourceMode.InputActionReference:
			{
				if (TryGetInputActionReference(out var reference))
				{
					return TryReadValue(reference.action, out value);
				}
				value = default(TValue);
				return false;
			}
			case InputSourceMode.ObjectReference:
			{
				IXRInputValueReader<TValue> objectReference = GetObjectReference();
				if (objectReference != null)
				{
					return objectReference.TryReadValue(out value);
				}
				value = default(TValue);
				return false;
			}
			case InputSourceMode.ManualValue:
				value = m_ManualValue;
				return true;
			}
		}

		private static TValue ReadValue(InputAction action)
		{
			return action?.ReadValue<TValue>() ?? default(TValue);
		}

		private static bool TryReadValue(InputAction action, out TValue value)
		{
			if (action == null)
			{
				value = default(TValue);
				return false;
			}
			value = action.ReadValue<TValue>();
			return action.IsInProgress();
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Inputs.Interactions
{
	[Preserve]
	public class SectorInteraction : IInputInteraction<Vector2>, IInputInteraction
	{
		[Flags]
		public enum Directions
		{
			None = 0,
			North = 1,
			South = 2,
			East = 4,
			West = 8
		}

		public enum SweepBehavior
		{
			Locked,
			[InspectorName("Allow Reentry")]
			AllowReentry,
			[InspectorName("Disallow Reentry")]
			DisallowReentry,
			[InspectorName("History Independent")]
			HistoryIndependent
		}

		private enum State
		{
			Centered,
			StartedValidDirection,
			StartedInvalidDirection
		}

		public Directions directions;

		public SweepBehavior sweepBehavior;

		public float pressPoint = -1f;

		private State m_State;

		private bool m_WasValidDirection;

		internal float pressPointOrDefault
		{
			get
			{
				if (!(pressPoint >= 0f))
				{
					return defaultPressPoint;
				}
				return pressPoint;
			}
		}

		public static float defaultPressPoint { get; set; }

		public void Process(ref InputInteractionContext context)
		{
			if (!context.ControlIsActuated(pressPointOrDefault))
			{
				State state = m_State;
				if (state != State.Centered && (uint)(state - 1) <= 1u)
				{
					m_State = State.Centered;
					context.Canceled();
				}
				return;
			}
			bool flag = IsValidDirection(ref context);
			if (m_State == State.Centered)
			{
				m_State = (flag ? State.StartedValidDirection : State.StartedInvalidDirection);
				if (flag)
				{
					context.PerformedAndStayPerformed();
				}
				m_WasValidDirection = flag;
				return;
			}
			switch (sweepBehavior)
			{
			case SweepBehavior.AllowReentry:
				if (m_WasValidDirection && !flag && m_State == State.StartedValidDirection)
				{
					context.Canceled();
				}
				else if (!m_WasValidDirection && flag && m_State == State.StartedValidDirection)
				{
					context.PerformedAndStayPerformed();
				}
				break;
			case SweepBehavior.DisallowReentry:
				if (m_WasValidDirection && !flag && m_State == State.StartedValidDirection)
				{
					context.Canceled();
				}
				break;
			case SweepBehavior.HistoryIndependent:
				if (m_WasValidDirection && !flag)
				{
					context.Canceled();
				}
				else if (!m_WasValidDirection && flag)
				{
					context.PerformedAndStayPerformed();
				}
				break;
			}
			m_WasValidDirection = flag;
		}

		private bool IsValidDirection(ref InputInteractionContext context)
		{
			return (GetNearestDirection(CardinalUtility.GetNearestCardinal(context.ReadValue<Vector2>())) & directions) != 0;
		}

		private static Directions GetNearestDirection(Cardinal value)
		{
			return value switch
			{
				Cardinal.North => Directions.North, 
				Cardinal.South => Directions.South, 
				Cardinal.East => Directions.East, 
				Cardinal.West => Directions.West, 
				_ => Directions.None, 
			};
		}

		public void Reset()
		{
		}

		[Preserve]
		static SectorInteraction()
		{
			defaultPressPoint = 0.5f;
			UnityEngine.InputSystem.InputSystem.RegisterInteraction<SectorInteraction>();
		}

		[RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
		[Preserve]
		private static void Initialize()
		{
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.Inputs.Haptics
{
	public class HapticControlActionManager
	{
		private readonly HapticImpulseCommandChannelGroup m_DeviceChannelGroup;

		private readonly OpenXRHapticImpulseChannel m_OpenXRChannel;

		private readonly HapticImpulseSingleChannelGroup m_OpenXRChannelGroup;

		public HapticControlActionManager()
		{
			m_DeviceChannelGroup = new HapticImpulseCommandChannelGroup();
			m_OpenXRChannel = new OpenXRHapticImpulseChannel();
			m_OpenXRChannelGroup = new HapticImpulseSingleChannelGroup(m_OpenXRChannel);
		}

		public IXRHapticImpulseChannelGroup GetChannelGroup(InputAction action)
		{
			if (action == null)
			{
				return null;
			}
			InputControl activeControl = action.activeControl;
			if (activeControl == null)
			{
				ReadOnlyArray<InputControl> controls = action.controls;
				if (controls.Count > 0 && controls[0] is HapticControl hapticControl)
				{
					m_OpenXRChannel.hapticAction = action;
					m_OpenXRChannel.device = hapticControl.device;
					return m_OpenXRChannelGroup;
				}
				return null;
			}
			m_DeviceChannelGroup.Initialize(activeControl.device);
			return m_DeviceChannelGroup;
		}
	}
	public class HapticImpulseCommandChannel : IXRHapticImpulseChannel
	{
		public int motorChannel { get; set; }

		public UnityEngine.InputSystem.InputDevice device { get; set; }

		public bool SendHapticImpulse(float amplitude, float duration, float frequency)
		{
			if (device == null)
			{
				return false;
			}
			SendHapticImpulseCommand command = SendHapticImpulseCommand.Create(motorChannel, amplitude, duration);
			return device.ExecuteCommand(ref command) >= 0;
		}
	}
	public class HapticImpulseCommandChannelGroup : IXRHapticImpulseChannelGroup
	{
		private readonly List<IXRHapticImpulseChannel> m_Channels = new List<IXRHapticImpulseChannel>();

		private UnityEngine.InputSystem.InputDevice m_Device;

		public int channelCount => m_Channels.Count;

		public IXRHapticImpulseChannel GetChannel(int channel = 0)
		{
			if (channel < 0)
			{
				Debug.LogError("Haptic channel can't be negative.");
				return null;
			}
			if (channel >= m_Channels.Count)
			{
				return null;
			}
			return m_Channels[channel];
		}

		public void Initialize(UnityEngine.InputSystem.InputDevice device)
		{
			if (m_Device == device)
			{
				return;
			}
			m_Device = device;
			m_Channels.Clear();
			if (device != null)
			{
				GetHapticCapabilitiesCommand command = GetHapticCapabilitiesCommand.Create();
				long num = device.ExecuteCommand(ref command);
				int num2;
				if (num < 0)
				{
					Debug.LogWarning($"Failed to get haptic capabilities of {device}, error code {num}. Continuing assuming a single haptic channel.");
					num2 = 1;
				}
				else
				{
					num2 = (int)command.numChannels;
				}
				for (int i = 0; i < num2; i++)
				{
					m_Channels.Add(new HapticImpulseCommandChannel
					{
						motorChannel = i,
						device = device
					});
				}
			}
		}
	}
	[AddComponentMenu("XR/Haptics/Haptic Impulse Player", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Inputs.Haptics.HapticImpulsePlayer.html")]
	public class HapticImpulsePlayer : MonoBehaviour
	{
		[SerializeField]
		[Tooltip("Specifies the output haptic control or controller that haptic impulses will be sent to.")]
		private XRInputHapticImpulseProvider m_HapticOutput = new XRInputHapticImpulseProvider("Haptic");

		[SerializeField]
		[Range(0f, 1f)]
		[Tooltip("Amplitude multiplier which can be used to dampen the haptic impulses sent by this component.")]
		private float m_AmplitudeMultiplier = 1f;

		public XRInputHapticImpulseProvider hapticOutput
		{
			get
			{
				return m_HapticOutput;
			}
			set
			{
				XRInputReaderUtility.SetInputProperty(ref m_HapticOutput, value, this);
			}
		}

		public float amplitudeMultiplier
		{
			get
			{
				return m_AmplitudeMultiplier;
			}
			set
			{
				m_AmplitudeMultiplier = value;
			}
		}

		protected void Awake()
		{
			XRInputHapticImpulseProvider xRInputHapticImpulseProvider = m_HapticOutput;
			if (xRInputHapticImpulseProvider != null && xRInputHapticImpulseProvider.inputSourceMode == XRInputHapticImpulseProvider.InputSourceMode.InputActionReference && m_HapticOutput.inputActionReference == null)
			{
				IXRHapticImpulseProvider componentInParent = base.gameObject.GetComponentInParent<IXRHapticImpulseProvider>(includeInactive: true);
				if (componentInParent as Component != null)
				{
					m_HapticOutput.SetObjectReference(componentInParent);
					m_HapticOutput.inputSourceMode = XRInputHapticImpulseProvider.InputSourceMode.ObjectReference;
				}
			}
		}

		protected void OnEnable()
		{
			m_HapticOutput.EnableDirectActionIfModeUsed();
		}

		protected void OnDisable()
		{
			m_HapticOutput.DisableDirectActionIfModeUsed();
		}

		public bool SendHapticImpulse(float amplitude, float duration)
		{
			return SendHapticImpulse(amplitude, duration, 0f);
		}

		public bool SendHapticImpulse(float amplitude, float duration, float frequency)
		{
			if (!base.isActiveAndEnabled)
			{
				return false;
			}
			return m_HapticOutput.GetChannelGroup()?.GetChannel()?.SendHapticImpulse(amplitude * m_AmplitudeMultiplier, duration, frequency) == true;
		}

		internal static HapticImpulsePlayer GetOrCreateInHierarchy(GameObject gameObject)
		{
			HapticImpulsePlayer hapticImpulsePlayer = gameObject.GetComponentInParent<HapticImpulsePlayer>(includeInactive: true);
			if (hapticImpulsePlayer == null)
			{
				Component component = gameObject.GetComponentInParent<IXRHapticImpulseProvider>(includeInactive: true) as Component;
				hapticImpulsePlayer = ((component != null) ? component.gameObject.AddComponent<HapticImpulsePlayer>() : gameObject.AddComponent<HapticImpulsePlayer>());
			}
			return hapticImpulsePlayer;
		}
	}
	public class HapticImpulseSingleChannelGroup : IXRHapticImpulseChannelGroup
	{
