	public class XRInputDeviceHapticImpulseChannel : IXRHapticImpulseChannel
	{
		public int motorChannel { get; set; }

		public InputDevice device { get; set; }

		public bool SendHapticImpulse(float amplitude, float duration, float frequency)
		{
			return device.SendHapticImpulse((uint)motorChannel, amplitude, duration);
		}
	}
	public class XRInputDeviceHapticImpulseChannelGroup : IXRHapticImpulseChannelGroup
	{
		private InputDevice m_Device;

		private readonly List<IXRHapticImpulseChannel> m_Channels = new List<IXRHapticImpulseChannel>();

		public int channelCount => m_Channels.Count;

		public IXRHapticImpulseChannel GetChannel(int channel = 0)
		{
			if (channel < 0)
			{
				Debug.LogError("Haptic channel can't be negative.");
				return null;
			}
			if (channel >= m_Channels.Count)
			{
				return null;
			}
			return m_Channels[channel];
		}

		public void Initialize(InputDevice device)
		{
			if (m_Device == device)
			{
				return;
			}
			m_Device = device;
			m_Channels.Clear();
			if (!device.isValid)
			{
				return;
			}
			if (!device.TryGetHapticCapabilities(out var capabilities))
			{
				Debug.LogWarning($"Failed to get haptic capabilities of {device}");
				return;
			}
			if (!capabilities.supportsImpulse)
			{
				Debug.LogWarning($"{device} does not support haptic impulse.");
				return;
			}
			int numChannels = (int)capabilities.numChannels;
			for (int i = 0; i < numChannels; i++)
			{
				m_Channels.Add(new XRInputDeviceHapticImpulseChannel
				{
					motorChannel = i,
					device = device
				});
			}
		}
	}
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.Inputs.Haptics.XRInputDeviceHapticImpulseProvider.html")]
	[CreateAssetMenu(fileName = "XRInputDeviceHapticImpulseProvider", menuName = "XR/Input Device Haptic Impulse Provider")]
	public class XRInputDeviceHapticImpulseProvider : ScriptableObject, IXRHapticImpulseProvider
	{
		[SerializeField]
		private InputDeviceCharacteristics m_Characteristics;

		private XRInputDeviceHapticImpulseChannelGroup m_ChannelGroup;

		private InputDevice m_InputDevice;

		public IXRHapticImpulseChannelGroup GetChannelGroup()
		{
			RefreshInputDeviceIfNeeded();
			if (m_ChannelGroup == null)
			{
				m_ChannelGroup = new XRInputDeviceHapticImpulseChannelGroup();
			}
			m_ChannelGroup.Initialize(m_InputDevice);
			return m_ChannelGroup;
		}

		private void RefreshInputDeviceIfNeeded()
		{
			if (!m_InputDevice.isValid)
			{
				XRInputTrackingAggregator.TryGetDeviceWithExactCharacteristics(m_Characteristics, out m_InputDevice);
			}
		}
	}
	[Serializable]
	public class XRInputHapticImpulseProvider : IXRHapticImpulseProvider
	{
		public enum InputSourceMode
		{
			Unused,
			InputAction,
			InputActionReference,
			ObjectReference
		}

		[SerializeField]
		private InputSourceMode m_InputSourceMode = InputSourceMode.InputActionReference;

		[SerializeField]
		private InputAction m_InputAction;

		[SerializeField]
		private InputActionReference m_InputActionReference;

		[SerializeField]
		[RequireInterface(typeof(IXRHapticImpulseProvider))]
		private Object m_ObjectReferenceObject;

		private readonly UnityObjectReferenceCache<IXRHapticImpulseProvider, Object> m_ObjectReference = new UnityObjectReferenceCache<IXRHapticImpulseProvider, Object>();

		private HapticControlActionManager m_HapticControlActionManager;

		public InputSourceMode inputSourceMode
		{
			get
			{
				return m_InputSourceMode;
			}
			set
			{
				m_InputSourceMode = value;
			}
		}

		public InputAction inputAction
		{
			get
			{
				return m_InputAction;
			}
			set
			{
				m_InputAction = value;
			}
		}

		public InputActionReference inputActionReference
		{
			get
			{
				return m_InputActionReference;
			}
			set
			{
				m_InputActionReference = value;
			}
		}

		public XRInputHapticImpulseProvider()
		{
		}

		public XRInputHapticImpulseProvider(string name = null, bool wantsInitialStateCheck = false, InputSourceMode inputSourceMode = InputSourceMode.InputActionReference)
		{
			m_InputAction = InputActionUtility.CreatePassThroughAction(null, name, wantsInitialStateCheck);
			m_InputSourceMode = inputSourceMode;
		}

		public void EnableDirectActionIfModeUsed()
		{
			if (m_InputSourceMode == InputSourceMode.InputAction)
			{
				m_InputAction.Enable();
			}
		}

		public void DisableDirectActionIfModeUsed()
		{
			if (m_InputSourceMode == InputSourceMode.InputAction)
			{
				m_InputAction.Disable();
			}
		}

		public IXRHapticImpulseProvider GetObjectReference()
		{
			return m_ObjectReference.Get(m_ObjectReferenceObject);
		}

		public void SetObjectReference(IXRHapticImpulseProvider value)
		{
			m_ObjectReference.Set(ref m_ObjectReferenceObject, value);
		}

		public IXRHapticImpulseChannelGroup GetChannelGroup()
		{
			switch (m_InputSourceMode)
			{
			default:
				return null;
			case InputSourceMode.InputAction:
				if (m_HapticControlActionManager == null)
				{
					m_HapticControlActionManager = new HapticControlActionManager();
				}
				return m_HapticControlActionManager.GetChannelGroup(m_InputAction);
			case InputSourceMode.InputActionReference:
				if (m_InputActionReference != null)
				{
					if (m_HapticControlActionManager == null)
					{
						m_HapticControlActionManager = new HapticControlActionManager();
					}
					return m_HapticControlActionManager.GetChannelGroup(m_InputActionReference.action);
				}
				return null;
			case InputSourceMode.ObjectReference:
				return GetObjectReference()?.GetChannelGroup();
			}
		}
	}
