	[Obsolete("The Affordance System namespace and all associated classes have been deprecated. The existing affordance system will be moved, replaced and updated with a new interaction feedback system in a future version of XRI.")]
	public abstract class BaseAffordanceStateProvider : MonoBehaviour
	{
		[SerializeField]
		[Range(0f, 5f)]
		[Tooltip("Duration of transition in seconds. 0 means no smoothing.")]
		private float m_TransitionDuration = 0.125f;

		private readonly BindableVariable<AffordanceStateData> m_AffordanceStateData = new BindableVariable<AffordanceStateData>();

		private AffordanceStateData m_AffordanceStateDataBeforeSet;

		private AffordanceStateData m_PreviousAffordanceStateData;

		private readonly HashSetList<IAsyncAffordanceStateReceiver> m_AsyncAffordanceReceivers = new HashSetList<IAsyncAffordanceStateReceiver>();

		private readonly HashSetList<ISynchronousAffordanceStateReceiver> m_SynchronousAffordanceReceivers = new HashSetList<ISynchronousAffordanceStateReceiver>();

		private readonly List<JobHandle> m_ScheduledJobs = new List<JobHandle>();

		private readonly BindingsGroup m_BindingsGroup = new BindingsGroup();

		private float m_TimeSinceLastStateUpdate;

		private bool m_IsFirstFrame = true;

		private bool m_CompletingTweens;

		private float m_InterpolationSpeed = 8f;

		private float m_MaxTransitionDuration = 5f;

		public float transitionDuration
		{
			get
			{
				return m_TransitionDuration;
			}
			set
			{
				m_TransitionDuration = value;
				RefreshTransitionDuration();
			}
		}

		public bool isCurrentlyTransitioning
		{
			get
			{
				if (m_CompletingTweens)
				{
					return m_ScheduledJobs.Count > 0;
				}
				return true;
			}
		}

		public IReadOnlyBindableVariable<AffordanceStateData> currentAffordanceStateData => m_AffordanceStateData;

		protected virtual void OnValidate()
		{
			RefreshTransitionDuration();
		}

		protected virtual void OnEnable()
		{
			RefreshTransitionDuration();
			BindToProviders();
		}

		protected virtual void OnDisable()
		{
			ClearBindings();
		}

		protected virtual void Update()
		{
			if (m_IsFirstFrame)
			{
				OnAffordanceStateUpdated(m_AffordanceStateData.Value);
				DoTween(1f);
				m_IsFirstFrame = false;
			}
			else
			{
				DoTween((m_InterpolationSpeed > 0f) ? (Time.deltaTime * m_InterpolationSpeed) : 1f);
			}
		}

		protected virtual void BindToProviders()
		{
			ClearBindings();
			m_IsFirstFrame = true;
			AddBinding(m_AffordanceStateData.SubscribeAndUpdate(OnAffordanceStateUpdated));
		}

		protected virtual void ClearBindings()
		{
			m_BindingsGroup.Clear();
		}

		protected void AddBinding(IEventBinding binding)
		{
			m_BindingsGroup.AddBinding(binding);
		}

		public void UpdateAffordanceState(AffordanceStateData newAffordanceStateData)
		{
			m_AffordanceStateDataBeforeSet = m_AffordanceStateData.Value;
			m_AffordanceStateData.Value = newAffordanceStateData;
		}

		private void OnAffordanceStateUpdated(AffordanceStateData newAffordanceStateData)
		{
			m_PreviousAffordanceStateData = m_AffordanceStateDataBeforeSet;
			for (int i = 0; i < m_AsyncAffordanceReceivers.Count; i++)
			{
				m_AsyncAffordanceReceivers[i].OnAffordanceStateUpdated(m_PreviousAffordanceStateData, newAffordanceStateData);
			}
			for (int j = 0; j < m_SynchronousAffordanceReceivers.Count; j++)
			{
				m_SynchronousAffordanceReceivers[j].OnAffordanceStateUpdated(m_PreviousAffordanceStateData, newAffordanceStateData);
			}
			m_TimeSinceLastStateUpdate = 0f;
			m_CompletingTweens = false;
		}

		public bool RegisterAffordanceReceiver(IAffordanceStateReceiver receiver)
		{
			if (receiver is IAsyncAffordanceStateReceiver receiver2)
			{
				return RegisterAffordanceReceiver(receiver2);
			}
			if (receiver is ISynchronousAffordanceStateReceiver receiver3)
			{
				return RegisterAffordanceReceiver(receiver3);
			}
			if (receiver != null)
			{
				Debug.LogError("Unhandled type of IAffordanceStateReceiver: " + receiver.GetType().Name, this);
			}
			return false;
		}

		private bool RegisterAffordanceReceiver(IAsyncAffordanceStateReceiver receiver)
		{
			return m_AsyncAffordanceReceivers.Add(receiver);
		}

		private bool RegisterAffordanceReceiver(ISynchronousAffordanceStateReceiver receiver)
		{
			return m_SynchronousAffordanceReceivers.Add(receiver);
		}

		public bool UnregisterAffordanceReceiver(IAffordanceStateReceiver receiver)
		{
			if (receiver is IAsyncAffordanceStateReceiver receiver2)
			{
				return UnregisterAffordanceReceiver(receiver2);
			}
			if (receiver is ISynchronousAffordanceStateReceiver receiver3)
			{
				return UnregisterAffordanceReceiver(receiver3);
			}
			if (receiver != null)
			{
				Debug.LogError("Unhandled type of IAffordanceStateReceiver: " + receiver.GetType().Name, this);
			}
			return false;
		}

		private bool UnregisterAffordanceReceiver(IAsyncAffordanceStateReceiver receiver)
		{
			CompleteJobs();
			return m_AsyncAffordanceReceivers.Remove(receiver);
		}

		private bool UnregisterAffordanceReceiver(ISynchronousAffordanceStateReceiver receiver)
		{
			return m_SynchronousAffordanceReceivers.Remove(receiver);
		}

		private bool CompleteJobs()
		{
			for (int i = 0; i < m_ScheduledJobs.Count; i++)
			{
				m_ScheduledJobs[i].Complete();
			}
			bool result = m_ScheduledJobs.Count > 0;
			m_ScheduledJobs.Clear();
			return result;
		}

		private void DoTween(float tweenTarget)
		{
			if (CompleteJobs())
			{
				for (int i = 0; i < m_AsyncAffordanceReceivers.Count; i++)
				{
					m_AsyncAffordanceReceivers[i].UpdateStateFromCompletedJob();
				}
			}
			float num = tweenTarget;
			if (m_TimeSinceLastStateUpdate > m_MaxTransitionDuration || num > 0.99f)
			{
				if (m_CompletingTweens)
				{
					return;
				}
				num = 1f;
				m_CompletingTweens = true;
			}
			for (int j = 0; j < m_AsyncAffordanceReceivers.Count; j++)
			{
				m_ScheduledJobs.Add(m_AsyncAffordanceReceivers[j].HandleTween(num));
			}
			for (int k = 0; k < m_SynchronousAffordanceReceivers.Count; k++)
			{
				m_SynchronousAffordanceReceivers[k].HandleTween(num);
			}
			m_TimeSinceLastStateUpdate += Time.deltaTime;
		}

		private void RefreshTransitionDuration()
		{
			m_InterpolationSpeed = ((m_TransitionDuration > 0f) ? (1f / m_TransitionDuration) : 0f);
			m_MaxTransitionDuration = m_TransitionDuration * 4f;
		}
	}
	[AddComponentMenu("Affordance System/XR Interactable Affordance State Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.AffordanceSystem.State.XRInteractableAffordanceStateProvider.html")]
	[DisallowMultipleComponent]
	[Obsolete("The Affordance System namespace and all associated classes have been deprecated. The existing affordance system will be moved, replaced and updated with a new interaction feedback system in a future version of XRI.")]
	public class XRInteractableAffordanceStateProvider : BaseAffordanceStateProvider
	{
		public enum SelectClickAnimationMode
		{
			None,
			SelectEntered,
			SelectExited
		}

		public enum ActivateClickAnimationMode
		{
			None,
			Activated,
			Deactivated
		}

		[SerializeField]
		[RequireInterface(typeof(IXRInteractable))]
		[Tooltip("The interactable component that drives the affordance states. If null, Unity will try and find an interactable component attached.")]
		private Object m_InteractableSource;

		[Header("Event Constraints")]
		[SerializeField]
		[Tooltip("When hover events are registered and this is true, the state will fallback to idle or disabled.")]
		private bool m_IgnoreHoverEvents;

		[SerializeField]
		[Tooltip("When this is true, the state will fallback to hover if the later is not ignored. When this is false, this provider will check if the Interactable Source has priority for selection when hovered, and update its state accordingly.")]
		private bool m_IgnoreHoverPriorityEvents = true;

		[SerializeField]
		[Tooltip("When focus events are registered and this is true, the state will fallback to idle or disabled.")]
		private bool m_IgnoreFocusEvents = true;

		[SerializeField]
		[Tooltip("When select events are registered and this is true, the state will fallback to idle or disabled. Note this will not affect click animations which can be disabled separately.")]
		private bool m_IgnoreSelectEvents;

		[SerializeField]
		[Tooltip("When activate events are registered and this is true, the state will fallback to idle or disabled.Note this will not affect click animations which can be disabled separately.")]
		private bool m_IgnoreActivateEvents;

		[Header("Click Animation Config")]
		[SerializeField]
		[Tooltip("Condition to trigger click animation for Selected interaction events.")]
		private SelectClickAnimationMode m_SelectClickAnimationMode = SelectClickAnimationMode.SelectEntered;

		[SerializeField]
		[Tooltip("Condition to trigger click animation for activated interaction events.")]
		private ActivateClickAnimationMode m_ActivateClickAnimationMode;

		[SerializeField]
		[Range(0f, 1f)]
		[Tooltip("Duration of click animations for selected and activated events.")]
		private float m_ClickAnimationDuration = 0.25f;

		[SerializeField]
		[Tooltip("Animation curve reference for click animation events. Select the More menu (?) to choose between a direct reference and a reusable scriptable object animation curve datum.")]
		private AnimationCurveDatumProperty m_ClickAnimationCurve = new AnimationCurveDatumProperty(AnimationCurve.EaseInOut(0f, 0f, 1f, 1f));

		private IXRInteractable m_Interactable;

		private IXRHoverInteractable m_HoverInteractable;

		private IXRSelectInteractable m_SelectInteractable;

		private IXRFocusInteractable m_FocusInteractable;

		private IXRActivateInteractable m_ActivateInteractable;

		private IXRInteractionStrengthInteractable m_InteractionStrengthInteractable;

		private Coroutine m_SelectedClickAnimation;

		private Coroutine m_ActivatedClickAnimation;

		private Coroutine m_HoveredPriorityRoutine;

		private bool m_IsBoundToInteractionEvents;

		private bool m_IsActivated;

		private bool m_IsRegistered;

		private bool m_IsHoveredPriority;

		private bool m_HasHoverInteractable;

		private bool m_HasSelectInteractable;

		private bool m_HasInteractionStrengthInteractable;

		private int m_HoveringPriorityInteractorCount;

		public Object interactableSource
		{
			get
			{
				return m_InteractableSource;
			}
			set
			{
				m_InteractableSource = value;
				if (Application.isPlaying && base.isActiveAndEnabled)
				{
					SetBoundInteractionReceiver(value as IXRInteractable);
				}
			}
		}

		public bool ignoreHoverEvents
		{
			get
			{
				return m_IgnoreHoverEvents;
			}
			set
			{
				m_IgnoreHoverEvents = value;
			}
		}

		public bool ignoreHoverPriorityEvents
		{
			get
			{
				return m_IgnoreHoverPriorityEvents;
			}
			set
			{
				if (Application.isPlaying && base.isActiveAndEnabled && !m_IgnoreHoverPriorityEvents && value)
				{
					StopHoveredPriorityRoutine();
					RefreshState();
				}
				m_IgnoreHoverPriorityEvents = value;
			}
		}

		public bool ignoreFocusEvents
		{
			get
			{
				return m_IgnoreFocusEvents;
			}
			set
			{
				m_IgnoreFocusEvents = value;
			}
		}

		public bool ignoreSelectEvents
		{
			get
			{
				return m_IgnoreSelectEvents;
			}
			set
			{
				m_IgnoreSelectEvents = value;
			}
		}

		public bool ignoreActivateEvents
		{
			get
			{
				return m_IgnoreActivateEvents;
			}
			set
			{
				m_IgnoreActivateEvents = value;
			}
		}

		public SelectClickAnimationMode selectClickAnimationMode
		{
			get
			{
				return m_SelectClickAnimationMode;
			}
			set
			{
				m_SelectClickAnimationMode = value;
			}
		}

		public ActivateClickAnimationMode activateClickAnimationMode
		{
			get
			{
				return m_ActivateClickAnimationMode;
			}
			set
			{
				m_ActivateClickAnimationMode = value;
			}
		}

		public float clickAnimationDuration
		{
			get
			{
				return m_ClickAnimationDuration;
			}
			set
			{
				m_ClickAnimationDuration = value;
			}
		}

		public AnimationCurveDatumProperty clickAnimationCurve
		{
			get
			{
				return m_ClickAnimationCurve;
			}
			set
			{
				m_ClickAnimationCurve = value;
			}
		}

		protected virtual bool isHovered
		{
			get
			{
				if (m_HasHoverInteractable)
				{
					return m_HoverInteractable.isHovered;
				}
				return false;
			}
		}

		protected virtual bool isSelected
		{
			get
			{
				if (m_HasSelectInteractable)
				{
					return m_SelectInteractable.isSelected;
				}
				return false;
			}
		}

		protected virtual bool isFocused
		{
			get
			{
				if (m_FocusInteractable != null)
				{
					return m_FocusInteractable.isFocused;
				}
				return false;
			}
		}

		protected virtual bool isActivated => m_IsActivated;

		protected virtual bool isRegistered => m_IsRegistered;

		protected void Awake()
		{
			IXRInteractable boundInteractionReceiver = ((m_InteractableSource != null && m_InteractableSource is IXRInteractable iXRInteractable) ? iXRInteractable : GetComponentInParent<IXRInteractable>());
			if (!SetBoundInteractionReceiver(boundInteractionReceiver))
			{
				XRLoggingUtils.LogWarning($"Could not find required interactable component on {base.gameObject}" + " for which to provide affordance states.", this);
				base.enabled = false;
			}
		}

		protected override void OnValidate()
		{
			base.OnValidate();
			if (Application.isPlaying && base.isActiveAndEnabled && m_IgnoreHoverPriorityEvents)
			{
				StopHoveredPriorityRoutine();
				RefreshState();
			}
		}

		public bool SetBoundInteractionReceiver(IXRInteractable receiver)
		{
			ClearBindings();
			int num;
			if (receiver is Object obj)
			{
				num = ((obj != null) ? 1 : 0);
				if (num != 0)
				{
					m_Interactable = receiver;
					if (m_Interactable is IXRHoverInteractable hoverInteractable)
					{
						m_HoverInteractable = hoverInteractable;
					}
					if (m_Interactable is IXRSelectInteractable selectInteractable)
					{
						m_SelectInteractable = selectInteractable;
					}
					if (m_Interactable is IXRFocusInteractable focusInteractable)
					{
						m_FocusInteractable = focusInteractable;
					}
					if (m_Interactable is IXRActivateInteractable activateInteractable)
					{
						m_ActivateInteractable = activateInteractable;
					}
					if (m_Interactable is IXRInteractionStrengthInteractable interactionStrengthInteractable)
					{
						m_InteractionStrengthInteractable = interactionStrengthInteractable;
					}
					goto IL_00c4;
				}
			}
			else
			{
				num = 0;
			}
			m_Interactable = null;
			m_HoverInteractable = null;
			m_SelectInteractable = null;
			m_FocusInteractable = null;
			m_ActivateInteractable = null;
			m_InteractionStrengthInteractable = null;
			goto IL_00c4;
			IL_00c4:
			m_HasHoverInteractable = m_HoverInteractable != null;
			m_HasSelectInteractable = m_SelectInteractable != null;
			m_HasInteractionStrengthInteractable = m_InteractionStrengthInteractable != null;
			BindToProviders();
			return (byte)num != 0;
		}

		protected virtual void OnRegistered(InteractableRegisteredEventArgs args)
		{
			m_IsRegistered = true;
			RefreshState();
		}

		protected virtual void OnUnregistered(InteractableUnregisteredEventArgs args)
		{
			m_IsRegistered = false;
			RefreshState();
		}

		protected virtual void OnFirstHoverEntered(HoverEnterEventArgs args)
		{
			RefreshState();
		}

		protected virtual void OnLastHoverExited(HoverExitEventArgs args)
		{
			RefreshState();
		}

		protected virtual void OnHoverEntered(HoverEnterEventArgs args)
		{
			if (!m_IgnoreHoverPriorityEvents && args.interactorObject is IXRTargetPriorityInteractor iXRTargetPriorityInteractor)
			{
				m_HoveringPriorityInteractorCount++;
				if (iXRTargetPriorityInteractor.targetPriorityMode != TargetPriorityMode.None)
				{
					m_HoveredPriorityRoutine = m_HoveredPriorityRoutine ?? StartCoroutine(HoveredPriorityRoutine());
				}
			}
		}

		protected virtual void OnHoverExited(HoverExitEventArgs args)
		{
			if (!m_IgnoreHoverPriorityEvents && args.interactorObject is IXRTargetPriorityInteractor)
			{
				m_HoveringPriorityInteractorCount--;
				if (m_HoveringPriorityInteractorCount <= 0)
				{
					StopHoveredPriorityRoutine();
					RefreshState();
				}
			}
		}

		private void StopHoveredPriorityRoutine()
		{
			m_HoveringPriorityInteractorCount = 0;
			m_IsHoveredPriority = false;
			if (m_HoveredPriorityRoutine != null)
			{
				StopCoroutine(m_HoveredPriorityRoutine);
				m_HoveredPriorityRoutine = null;
			}
		}

		protected virtual void OnFirstSelectEntered(SelectEnterEventArgs args)
		{
			if (m_IgnoreSelectEvents || m_SelectClickAnimationMode != SelectClickAnimationMode.SelectEntered || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				SelectedClickBehavior();
			}
		}

		protected virtual void OnLastSelectExited(SelectExitEventArgs args)
		{
			if (m_IgnoreSelectEvents || m_SelectClickAnimationMode != SelectClickAnimationMode.SelectExited || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				if (m_SelectedClickAnimation == null)
				{
					RefreshState();
				}
			}
			else
			{
				SelectedClickBehavior();
			}
		}

		protected virtual void OnFirstFocusEntered(FocusEnterEventArgs args)
		{
			RefreshState();
		}

		protected virtual void OnLastFocusExited(FocusExitEventArgs args)
		{
			RefreshState();
		}

		protected virtual void OnActivatedEvent(ActivateEventArgs args)
		{
			m_IsActivated = true;
			if (m_IgnoreActivateEvents || m_ActivateClickAnimationMode != ActivateClickAnimationMode.Activated || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				ActivatedClickBehavior();
			}
		}

		protected virtual void OnDeactivatedEvent(DeactivateEventArgs args)
		{
			m_IsActivated = false;
			if (m_IgnoreActivateEvents || m_ActivateClickAnimationMode != ActivateClickAnimationMode.Deactivated || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				if (m_ActivatedClickAnimation == null)
				{
					RefreshState();
				}
			}
			else
			{
				ActivatedClickBehavior();
			}
		}

		protected virtual void OnLargestInteractionStrengthChanged(float value)
		{
			if (m_SelectedClickAnimation == null && m_ActivatedClickAnimation == null)
			{
				RefreshState();
			}
		}

		protected virtual void SelectedClickBehavior()
		{
			StopAllClickAnimations();
			m_SelectedClickAnimation = StartCoroutine(ClickAnimation(4, m_ClickAnimationDuration, delegate
			{
				m_SelectedClickAnimation = null;
			}));
		}

		protected virtual void ActivatedClickBehavior()
		{
			StopAllClickAnimations();
			m_ActivatedClickAnimation = StartCoroutine(ClickAnimation(5, m_ClickAnimationDuration, delegate
			{
				m_ActivatedClickAnimation = null;
			}));
		}

		private void StopActivatedCoroutine()
		{
			if (m_ActivatedClickAnimation != null)
			{
				StopCoroutine(m_ActivatedClickAnimation);
				m_ActivatedClickAnimation = null;
			}
		}

		private void StopSelectedCoroutine()
		{
			if (m_SelectedClickAnimation != null)
			{
				StopCoroutine(m_SelectedClickAnimation);
				m_SelectedClickAnimation = null;
			}
		}

		private void StopAllClickAnimations()
		{
			StopActivatedCoroutine();
			StopSelectedCoroutine();
		}

		protected virtual IEnumerator ClickAnimation(byte targetStateIndex, float duration, Action onComplete = null)
		{
			for (float elapsedTime = 0f; elapsedTime < duration; elapsedTime += Time.deltaTime)
			{
				float time = Mathf.Clamp01(elapsedTime / duration);
				float transitionAmount = m_ClickAnimationCurve.Value.Evaluate(time);
				AffordanceStateData newAffordanceStateData = new AffordanceStateData(targetStateIndex, transitionAmount);
				UpdateAffordanceState(newAffordanceStateData);
				yield return null;
			}
			yield return null;
			RefreshState();
			onComplete?.Invoke();
		}

		protected virtual AffordanceStateData GenerateNewAffordanceState()
		{
			if (!m_IsBoundToInteractionEvents)
			{
				return base.currentAffordanceStateData.Value;
			}
			if (isActivated && !m_IgnoreActivateEvents)
			{
				return AffordanceStateShortcuts.activatedState;
			}
			if (!isActivated && isSelected && !m_IgnoreSelectEvents)
			{
				float transitionAmount = (m_HasInteractionStrengthInteractable ? m_InteractionStrengthInteractable.largestInteractionStrength.Value : 1f);
				return new AffordanceStateData(4, transitionAmount);
			}
			if (!isActivated && !isSelected && isHovered && !m_IgnoreHoverEvents)
			{
				int stateIndex = (m_IsHoveredPriority ? 3 : 2);
				float transitionAmount2 = (m_HasInteractionStrengthInteractable ? m_InteractionStrengthInteractable.largestInteractionStrength.Value : 0f);
				return new AffordanceStateData((byte)stateIndex, transitionAmount2);
			}
			if (!isActivated && !isSelected && !isHovered && isFocused && !m_IgnoreFocusEvents)
			{
				return AffordanceStateShortcuts.focusedState;
			}
			if (!isRegistered)
			{
				return AffordanceStateShortcuts.disabledState;
			}
			return AffordanceStateShortcuts.idleState;
		}

		private IEnumerator HoveredPriorityRoutine()
		{
			do
			{
				if (m_HoverInteractable is XRBaseInteractable xRBaseInteractable && xRBaseInteractable.interactionManager != null && xRBaseInteractable.interactionManager.IsHighestPriorityTarget(xRBaseInteractable) != m_IsHoveredPriority)
				{
					m_IsHoveredPriority = !m_IsHoveredPriority;
					RefreshState();
				}
				yield return null;
			}
			while (m_HoveringPriorityInteractorCount > 0);
			m_HoveredPriorityRoutine = null;
		}

		protected override void BindToProviders()
		{
			base.BindToProviders();
			m_IsBoundToInteractionEvents = m_Interactable is Object obj && obj != null;
			if (m_IsBoundToInteractionEvents)
			{
				m_Interactable.registered += OnRegistered;
				m_Interactable.unregistered += OnUnregistered;
				if (m_HoverInteractable != null)
				{
					m_HoverInteractable.firstHoverEntered.AddListener(OnFirstHoverEntered);
					m_HoverInteractable.lastHoverExited.AddListener(OnLastHoverExited);
					m_HoverInteractable.hoverEntered.AddListener(OnHoverEntered);
					m_HoverInteractable.hoverExited.AddListener(OnHoverExited);
				}
				if (m_SelectInteractable != null)
				{
					m_SelectInteractable.firstSelectEntered.AddListener(OnFirstSelectEntered);
					m_SelectInteractable.lastSelectExited.AddListener(OnLastSelectExited);
				}
				if (m_FocusInteractable != null)
				{
					m_FocusInteractable.firstFocusEntered.AddListener(OnFirstFocusEntered);
					m_FocusInteractable.lastFocusExited.AddListener(OnLastFocusExited);
				}
				if (m_ActivateInteractable != null)
				{
					m_ActivateInteractable.activated.AddListener(OnActivatedEvent);
					m_ActivateInteractable.deactivated.AddListener(OnDeactivatedEvent);
				}
				if (m_InteractionStrengthInteractable != null)
				{
					AddBinding(m_InteractionStrengthInteractable.largestInteractionStrength.Subscribe(OnLargestInteractionStrengthChanged));
				}
				m_IsActivated = false;
				if (m_Interactable is XRBaseInteractable xRBaseInteractable)
				{
					m_IsRegistered = xRBaseInteractable.interactionManager != null && xRBaseInteractable.interactionManager.IsRegistered(m_Interactable);
				}
				else if (m_Interactable is Behaviour behaviour)
				{
					m_IsRegistered = behaviour.isActiveAndEnabled;
				}
				else
				{
					m_IsRegistered = true;
				}
			}
			RefreshState();
		}

		public void RefreshState()
		{
			AffordanceStateData newAffordanceStateData = GenerateNewAffordanceState();
			if (newAffordanceStateData.stateIndex != 4)
			{
				StopSelectedCoroutine();
			}
			if (newAffordanceStateData.stateIndex != 5)
			{
				StopActivatedCoroutine();
			}
			UpdateAffordanceState(newAffordanceStateData);
		}

		protected override void ClearBindings()
		{
			base.ClearBindings();
			if (m_IsBoundToInteractionEvents)
			{
				m_Interactable.registered -= OnRegistered;
				m_Interactable.unregistered -= OnUnregistered;
				if (m_HoverInteractable != null)
				{
					m_HoverInteractable.firstHoverEntered.RemoveListener(OnFirstHoverEntered);
					m_HoverInteractable.lastHoverExited.RemoveListener(OnLastHoverExited);
					m_HoverInteractable.hoverEntered.RemoveListener(OnHoverEntered);
					m_HoverInteractable.hoverExited.RemoveListener(OnHoverExited);
				}
				if (m_SelectInteractable != null)
				{
					m_SelectInteractable.firstSelectEntered.RemoveListener(OnFirstSelectEntered);
					m_SelectInteractable.lastSelectExited.RemoveListener(OnLastSelectExited);
				}
				if (m_FocusInteractable != null)
				{
					m_FocusInteractable.firstFocusEntered.RemoveListener(OnFirstFocusEntered);
					m_FocusInteractable.lastFocusExited.RemoveListener(OnLastFocusExited);
				}
				if (m_ActivateInteractable != null)
				{
					m_ActivateInteractable.activated.RemoveListener(OnActivatedEvent);
					m_ActivateInteractable.deactivated.RemoveListener(OnDeactivatedEvent);
				}
			}
			m_IsBoundToInteractionEvents = false;
		}
	}
	[AddComponentMenu("Affordance System/XR Interactor Affordance State Provider", 11)]
	[HelpURL("https://docs.unity3d.com/Packages/com.unity.xr.interaction.toolkit@3.2/api/UnityEngine.XR.Interaction.Toolkit.AffordanceSystem.State.XRInteractorAffordanceStateProvider.html")]
	[DisallowMultipleComponent]
	[Obsolete("The Affordance System namespace and all associated classes have been deprecated. The existing affordance system will be moved, replaced and updated with a new interaction feedback system in a future version of XRI.")]
	public class XRInteractorAffordanceStateProvider : BaseAffordanceStateProvider
	{
		public enum SelectClickAnimationMode
		{
			None,
			SelectEntered,
			SelectExited
		}

		public enum ActivateClickAnimationMode
		{
			None,
			Activated,
			Deactivated
		}

		[SerializeField]
		[RequireInterface(typeof(IXRInteractor))]
		[Tooltip("The interactor component that drives the affordance states. If null, Unity will try and find an interactor component attached.")]
		private Object m_InteractorSource;

		[Header("Event Constraints")]
		[SerializeField]
		[Tooltip("When hover events are registered and this is true, the state will fallback to idle or disabled.")]
		private bool m_IgnoreHoverEvents;

		[SerializeField]
		[Tooltip("When select events are registered and this is true, the state will fallback to idle or disabled. \nNote: Click animations must be disabled separately.")]
		private bool m_IgnoreSelectEvents;

		[SerializeField]
		[Tooltip("When activate events are registered and this is true, the state will fallback to idle or disabled.\nNote: Click animations must be disabled separately.")]
		private bool m_IgnoreActivateEvents = true;

		[SerializeField]
		[Tooltip("With the XR Ray Interactor it is possible to trigger select events from the ray interactor overlapping with a canvas.")]
		private bool m_IgnoreUGUIHover;

		[SerializeField]
		[Tooltip("With the XR Ray Interactor it is possible to trigger select events from the ray interactor overlapping with a canvas and triggering the select input.")]
		private bool m_IgnoreUGUISelect;

		[SerializeField]
		[Tooltip("This option will prevent Hover, Select, and Activate events from being triggered when they come from the XR Interaction Manager. UGUI hover and select events will still come through.")]
		private bool m_IgnoreXRInteractionEvents;

		[Header("Click Animation Config")]
		[SerializeField]
		[Tooltip("Condition to trigger click animation for Selected interaction events.")]
		private SelectClickAnimationMode m_SelectClickAnimationMode = SelectClickAnimationMode.SelectEntered;

		[SerializeField]
		[Tooltip("Condition to trigger click animation for activated interaction events.")]
		private ActivateClickAnimationMode m_ActivateClickAnimationMode = ActivateClickAnimationMode.Activated;

		[SerializeField]
		[Range(0f, 1f)]
		[Tooltip("Duration of click animations for selected and activated events.")]
		private float m_ClickAnimationDuration = 0.25f;

		[SerializeField]
		[Tooltip("Animation curve reference for click animation events. Select the More menu (?) to choose between a direct reference and a reusable asset.")]
		private AnimationCurveDatumProperty m_ClickAnimationCurve = new AnimationCurveDatumProperty(AnimationCurve.EaseInOut(0f, 0f, 1f, 1f));

		private IXRInteractor m_Interactor;

		private IXRHoverInteractor m_HoverInteractor;

		private IXRSelectInteractor m_SelectInteractor;

		private IXRInteractionStrengthInteractor m_InteractionStrengthInteractor;

		private XRRayInteractor m_RayInteractor;

		private ICurveInteractionDataProvider m_CurveInteractionDataProvider;

		private bool m_IsBoundToInteractionEvents;

		private bool m_HasRayInteractor;

		private bool m_HasCurveInteractionDataProvider;

		private bool m_HasHoverInteractor;

		private bool m_HasSelectInteractor;

		private bool m_HasInteractionStrengthInteractor;

		private bool m_IsIXRInteractor;

		private Coroutine m_SelectedClickAnimation;

		private Coroutine m_ActivatedClickAnimation;

		private bool m_IsActivated;

		private bool m_IsRegistered;

		private readonly HashSet<IXRActivateInteractable> m_BoundActivateInteractable = new HashSet<IXRActivateInteractable>();

		private bool m_UIHovering;

		private bool m_UISelecting;

		private Coroutine m_UGUIUpdateCoroutine;

		public Object interactorSource
		{
			get
			{
				return m_InteractorSource;
			}
			set
			{
				m_InteractorSource = value;
				if (Application.isPlaying && base.isActiveAndEnabled)
				{
					SetBoundInteractionReceiver(value as IXRInteractor);
				}
			}
		}

		public bool ignoreHoverEvents
		{
			get
			{
				return m_IgnoreHoverEvents;
			}
			set
			{
				m_IgnoreHoverEvents = value;
			}
		}

		public bool ignoreSelectEvents
		{
			get
			{
				return m_IgnoreSelectEvents;
			}
			set
			{
				m_IgnoreSelectEvents = value;
			}
		}

		public bool ignoreActivateEvents
		{
			get
			{
				return m_IgnoreActivateEvents;
			}
			set
			{
				m_IgnoreActivateEvents = value;
			}
		}

		public bool ignoreUGUIHover
		{
			get
			{
				return m_IgnoreUGUIHover;
			}
			set
			{
				m_IgnoreUGUIHover = value;
			}
		}

		public bool ignoreUGUISelect
		{
			get
			{
				return m_IgnoreUGUISelect;
			}
			set
			{
				m_IgnoreUGUISelect = value;
			}
		}

		public bool ignoreXRInteractionEvents
		{
			get
			{
				return m_IgnoreXRInteractionEvents;
			}
			set
			{
				m_IgnoreXRInteractionEvents = value;
			}
		}

		protected virtual bool hasXRHover
		{
			get
			{
				if (!m_IgnoreXRInteractionEvents && m_HasHoverInteractor)
				{
					return m_HoverInteractor.hasHover;
				}
				return false;
			}
		}

		protected virtual bool hasUIHover
		{
			get
			{
				if (!m_IgnoreUGUIHover)
				{
					return m_UIHovering;
				}
				return false;
			}
		}

		protected virtual bool hasXRSelection
		{
			get
			{
				if (!m_IgnoreXRInteractionEvents && m_HasSelectInteractor)
				{
					return m_SelectInteractor.hasSelection;
				}
				return false;
			}
		}

		protected virtual bool hasUISelection
		{
			get
			{
				if (!m_IgnoreUGUISelect)
				{
					return m_UISelecting;
				}
				return false;
			}
		}

		protected virtual bool isActivated
		{
			get
			{
				if (!m_IgnoreXRInteractionEvents)
				{
					return m_IsActivated;
				}
				return false;
			}
		}

		protected virtual bool isRegistered => m_IsRegistered;

		protected virtual bool isBlockedByGroup
		{
			get
			{
				if (m_IsIXRInteractor)
				{
					return !m_Interactor.IsBlockedByInteractionWithinGroup();
				}
				return false;
			}
		}

		public SelectClickAnimationMode selectClickAnimationMode
		{
			get
			{
				return m_SelectClickAnimationMode;
			}
			set
			{
				m_SelectClickAnimationMode = value;
			}
		}

		public ActivateClickAnimationMode activateClickAnimationMode
		{
			get
			{
				return m_ActivateClickAnimationMode;
			}
			set
			{
				m_ActivateClickAnimationMode = value;
			}
		}

		public float clickAnimationDuration
		{
			get
			{
				return m_ClickAnimationDuration;
			}
			set
			{
				m_ClickAnimationDuration = value;
			}
		}

		public AnimationCurveDatumProperty clickAnimationCurve
		{
			get
			{
				return m_ClickAnimationCurve;
			}
			set
			{
				m_ClickAnimationCurve = value;
			}
		}

		protected void Awake()
		{
			IXRInteractor boundInteractionReceiver = ((m_InteractorSource != null && m_InteractorSource is IXRInteractor iXRInteractor) ? iXRInteractor : GetComponentInParent<IXRInteractor>());
			if (!SetBoundInteractionReceiver(boundInteractionReceiver))
			{
				XRLoggingUtils.LogWarning($"Could not find required interactor component on {base.gameObject}" + " for which to provide affordance states.", this);
				base.enabled = false;
			}
		}

		public bool SetBoundInteractionReceiver(IXRInteractor interactor)
		{
			ClearBindings();
			int num;
			if (interactor is Object obj)
			{
				num = ((obj != null) ? 1 : 0);
				if (num != 0)
				{
					m_Interactor = interactor;
					if (m_Interactor is IXRHoverInteractor hoverInteractor)
					{
						m_HoverInteractor = hoverInteractor;
					}
					if (m_Interactor is IXRSelectInteractor selectInteractor)
					{
						m_SelectInteractor = selectInteractor;
					}
					if (m_Interactor is IXRInteractionStrengthInteractor interactionStrengthInteractor)
					{
						m_InteractionStrengthInteractor = interactionStrengthInteractor;
					}
					if (m_Interactor is XRRayInteractor rayInteractor)
					{
						m_RayInteractor = rayInteractor;
					}
					if (m_Interactor is ICurveInteractionDataProvider curveInteractionDataProvider)
					{
						m_CurveInteractionDataProvider = curveInteractionDataProvider;
					}
					goto IL_00c4;
				}
			}
			else
			{
				num = 0;
			}
			m_Interactor = null;
			m_HoverInteractor = null;
			m_SelectInteractor = null;
			m_InteractionStrengthInteractor = null;
			m_RayInteractor = null;
			m_CurveInteractionDataProvider = null;
			goto IL_00c4;
			IL_00c4:
			m_IsIXRInteractor = m_Interactor != null;
			m_HasHoverInteractor = m_HoverInteractor != null;
			m_HasSelectInteractor = m_SelectInteractor != null;
			m_HasInteractionStrengthInteractor = m_InteractionStrengthInteractor != null;
			m_HasRayInteractor = m_RayInteractor != null;
			m_HasCurveInteractionDataProvider = m_CurveInteractionDataProvider != null;
			BindToProviders();
			return (byte)num != 0;
		}

		protected override void BindToProviders()
		{
			base.BindToProviders();
			m_IsBoundToInteractionEvents = m_Interactor is Object obj && obj != null;
			if (m_IsBoundToInteractionEvents)
			{
				m_Interactor.registered += OnRegistered;
				m_Interactor.unregistered += OnUnregistered;
				if (m_HasHoverInteractor)
				{
					m_HoverInteractor.hoverEntered.AddListener(OnHoverEntered);
					m_HoverInteractor.hoverExited.AddListener(OnHoverExited);
				}
				if (m_HasSelectInteractor)
				{
					m_SelectInteractor.selectEntered.AddListener(OnSelectEntered);
					m_SelectInteractor.selectExited.AddListener(OnSelectExited);
				}
				if (m_HasInteractionStrengthInteractor)
				{
					AddBinding(m_InteractionStrengthInteractor.largestInteractionStrength.Subscribe(OnLargestInteractionStrengthChanged));
				}
				m_IsActivated = false;
				if (m_Interactor is XRBaseInteractor xRBaseInteractor)
				{
					m_IsRegistered = xRBaseInteractor.interactionManager != null && xRBaseInteractor.interactionManager.IsRegistered(m_Interactor);
				}
				else if (m_Interactor is Behaviour behaviour)
				{
					m_IsRegistered = behaviour.isActiveAndEnabled;
				}
				else
				{
					m_IsRegistered = true;
				}
				if (m_UGUIUpdateCoroutine != null)
				{
					StopCoroutine(m_UGUIUpdateCoroutine);
				}
				m_UGUIUpdateCoroutine = StartCoroutine(UIUpdateCheckCoroutine());
			}
			RefreshState();
		}

		public void RefreshState()
		{
			UpdateAffordanceState(GenerateNewAffordanceState());
		}

		protected override void ClearBindings()
		{
			base.ClearBindings();
			if (m_IsBoundToInteractionEvents)
			{
				m_Interactor.registered -= OnRegistered;
				m_Interactor.unregistered -= OnUnregistered;
				if (m_HasHoverInteractor)
				{
					m_HoverInteractor.hoverEntered.RemoveListener(OnHoverEntered);
					m_HoverInteractor.hoverExited.RemoveListener(OnHoverExited);
				}
				if (m_HasSelectInteractor)
				{
					m_SelectInteractor.selectEntered.RemoveListener(OnSelectEntered);
					m_SelectInteractor.selectExited.RemoveListener(OnSelectExited);
				}
			}
			foreach (IXRActivateInteractable item in m_BoundActivateInteractable)
			{
				if (item != null)
				{
					item.activated.RemoveListener(OnActivated);
					item.deactivated.RemoveListener(OnDeactivated);
				}
			}
			m_BoundActivateInteractable.Clear();
			m_IsBoundToInteractionEvents = false;
			if (m_UGUIUpdateCoroutine != null)
			{
				StopCoroutine(m_UGUIUpdateCoroutine);
				m_UGUIUpdateCoroutine = null;
			}
		}

		protected virtual AffordanceStateData GenerateNewAffordanceState()
		{
			if (!m_IsBoundToInteractionEvents)
			{
				return base.currentAffordanceStateData.Value;
			}
			if (isActivated && !m_IgnoreActivateEvents)
			{
				return AffordanceStateShortcuts.activatedState;
			}
			if ((hasXRSelection || hasUISelection) && !m_IgnoreSelectEvents)
			{
				float transitionAmount = (m_HasInteractionStrengthInteractor ? m_InteractionStrengthInteractor.largestInteractionStrength.Value : 1f);
				return new AffordanceStateData(4, transitionAmount);
			}
			if ((hasXRHover || hasUIHover) && !m_IgnoreHoverEvents)
			{
				float transitionAmount2 = (m_HasInteractionStrengthInteractor ? m_InteractionStrengthInteractor.largestInteractionStrength.Value : 0f);
				return new AffordanceStateData(2, transitionAmount2);
			}
			if (!isRegistered || isBlockedByGroup)
			{
				return AffordanceStateShortcuts.disabledState;
			}
			return AffordanceStateShortcuts.idleState;
		}

		protected virtual void OnRegistered(InteractorRegisteredEventArgs args)
		{
			m_IsRegistered = true;
			RefreshState();
		}

		protected virtual void OnUnregistered(InteractorUnregisteredEventArgs args)
		{
			m_IsRegistered = false;
			RefreshState();
		}

		protected virtual void OnHoverEntered(HoverEnterEventArgs args)
		{
			if (!m_IgnoreActivateEvents && args.interactableObject is IXRActivateInteractable iXRActivateInteractable && !m_BoundActivateInteractable.Contains(iXRActivateInteractable))
			{
				m_BoundActivateInteractable.Add(iXRActivateInteractable);
				iXRActivateInteractable.activated.RemoveListener(OnActivated);
				iXRActivateInteractable.deactivated.RemoveListener(OnDeactivated);
				iXRActivateInteractable.activated.AddListener(OnActivated);
				iXRActivateInteractable.deactivated.AddListener(OnDeactivated);
			}
			RefreshState();
		}

		protected virtual void OnHoverExited(HoverExitEventArgs args)
		{
			if (args.interactableObject is IXRActivateInteractable iXRActivateInteractable && m_BoundActivateInteractable.Contains(iXRActivateInteractable))
			{
				m_BoundActivateInteractable.Remove(iXRActivateInteractable);
				iXRActivateInteractable.activated.RemoveListener(OnActivated);
				iXRActivateInteractable.deactivated.RemoveListener(OnDeactivated);
			}
			RefreshState();
		}

		protected virtual void OnSelectEntered(SelectEnterEventArgs args)
		{
			if (!m_IgnoreActivateEvents && args.interactableObject is IXRActivateInteractable iXRActivateInteractable && !m_BoundActivateInteractable.Contains(iXRActivateInteractable))
			{
				m_BoundActivateInteractable.Add(iXRActivateInteractable);
				iXRActivateInteractable.activated.RemoveListener(OnActivated);
				iXRActivateInteractable.deactivated.RemoveListener(OnDeactivated);
				iXRActivateInteractable.activated.AddListener(OnActivated);
				iXRActivateInteractable.deactivated.AddListener(OnDeactivated);
			}
			if (m_IgnoreSelectEvents || m_IgnoreXRInteractionEvents || m_SelectClickAnimationMode != SelectClickAnimationMode.SelectEntered || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				SelectedClickBehavior();
			}
		}

		protected virtual void OnSelectExited(SelectExitEventArgs args)
		{
			if (!hasXRHover && args.interactableObject is IXRActivateInteractable iXRActivateInteractable && m_BoundActivateInteractable.Contains(iXRActivateInteractable))
			{
				m_BoundActivateInteractable.Remove(iXRActivateInteractable);
				iXRActivateInteractable.activated.RemoveListener(OnActivated);
				iXRActivateInteractable.deactivated.RemoveListener(OnDeactivated);
			}
			if (m_IgnoreSelectEvents || m_IgnoreXRInteractionEvents || m_SelectClickAnimationMode != SelectClickAnimationMode.SelectExited || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				SelectedClickBehavior();
			}
		}

		protected virtual void OnLargestInteractionStrengthChanged(float value)
		{
			if (m_SelectedClickAnimation == null && m_ActivatedClickAnimation == null)
			{
				RefreshState();
			}
		}

		private void OnActivated(ActivateEventArgs args)
		{
			m_IsActivated = true;
			if (m_IgnoreActivateEvents || m_IgnoreXRInteractionEvents || m_ActivateClickAnimationMode != ActivateClickAnimationMode.Activated || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				ActivatedClickBehavior();
			}
		}

		private void OnDeactivated(DeactivateEventArgs args)
		{
			m_IsActivated = false;
			if (m_IgnoreActivateEvents || m_IgnoreXRInteractionEvents || m_ActivateClickAnimationMode != ActivateClickAnimationMode.Deactivated || m_ClickAnimationDuration < Mathf.Epsilon)
			{
				RefreshState();
			}
			else
			{
				ActivatedClickBehavior();
			}
		}

		protected virtual void SelectedClickBehavior()
		{
			if (m_SelectedClickAnimation != null)
			{
				StopCoroutine(m_SelectedClickAnimation);
			}
			m_SelectedClickAnimation = StartCoroutine(ClickAnimation(4, m_ClickAnimationDuration, delegate
			{
				m_SelectedClickAnimation = null;
			}));
		}

		protected virtual void ActivatedClickBehavior()
		{
			if (m_ActivatedClickAnimation != null)
			{
				StopCoroutine(m_ActivatedClickAnimation);
			}
			m_ActivatedClickAnimation = StartCoroutine(ClickAnimation(5, m_ClickAnimationDuration, delegate
			{
				m_ActivatedClickAnimation = null;
			}));
		}

		protected virtual IEnumerator ClickAnimation(byte targetStateIndex, float duration, Action onComplete = null)
		{
			for (float elapsedTime = 0f; elapsedTime < duration; elapsedTime += Time.deltaTime)
			{
				float time = Mathf.Clamp01(elapsedTime / duration);
				float transitionAmount = m_ClickAnimationCurve.Value.Evaluate(time);
				AffordanceStateData newAffordanceStateData = new AffordanceStateData(targetStateIndex, transitionAmount);
				UpdateAffordanceState(newAffordanceStateData);
				yield return null;
			}
			yield return null;
			RefreshState();
			onComplete?.Invoke();
		}

		private IEnumerator UIUpdateCheckCoroutine()
		{
			while (true)
			{
				yield return null;
				if (!m_HasCurveInteractionDataProvider && !m_HasRayInteractor)
				{
					continue;
				}
				bool flag = false;
				bool flag2 = false;
				if ((!m_IgnoreHoverEvents || !m_IgnoreSelectEvents) && (m_HasCurveInteractionDataProvider ? (m_CurveInteractionDataProvider.TryGetCurveEndPoint(out var _) == EndPointType.UI) : (m_RayInteractor.TryGetCurrentUIRaycastResult(out var _, out var raycastEndpointIndex) && raycastEndpointIndex != 0)))
				{
					if (!m_IgnoreSelectEvents && !m_IgnoreUGUISelect)
					{
						flag2 = (m_HasCurveInteractionDataProvider ? m_CurveInteractionDataProvider.hasValidSelect : (m_RayInteractor.TryGetUIModel(out var model) && model.select));
					}
					if (!m_IgnoreHoverEvents && !m_IgnoreUGUIHover)
					{
						flag = true;
					}
				}
				bool num = flag != m_UIHovering || flag2 != m_UISelecting;
				m_UIHovering = flag;
				m_UISelecting = flag2;
				if (num)
				{
					RefreshState();
				}
			}
		}
	}
}
namespace UnityEngine.XR.Interaction.Toolkit.AffordanceSystem.Rendering
